class Solution {

    firstElementKTime(arr, n, k) {
        let freq_count = {};
        let result = -1;

        for (let i = 0; i < arr.length; i++) {
            let num = arr[i];
            if (!(num in freq_count)) {
                freq_count[num] = 1;
            } else {
                freq_count[num] += 1;
            }

            if (freq_count[num] === k) {
                result = num;
                break;
            }
        }

        return result;
    }
}

