    }
    return oddArr;
}

function createEvenArray(n) {
    let evenArr = [];
    for (let i = 0; i < n / 2; i++) {
        evenArr.push((i + 1) * 2);
    }
    return evenArr;
}

function reverseArray(arr) {
    let reversed = [];
    for (let i = arr.length - 1; i >= 0; i--) {
        reversed.push(arr[i]);
    }
    return reversed;
