class MergeFind {
	constructor(n) {
		this.parent = Array.from({ length: n }, (_, i) => i);
		this.size = Array(n).fill(1);
		this.num_sets = n;
		this.lista = Array.from({ length: n }, (_, i) => [i]);
	}

	find(a) {
		let to_update = [];
		while (a !== this.parent[a]) {
			to_update.push(a);
			a = this.parent[a];
		}
		for (let b of to_update) {
			this.parent[b] = a;
		}
		return this.parent[a];
	}

	merge(a, b) {
		a = this.find(a);
		b = this.find(b);
		if (a === b) return;
		if (this.size[a] < this.size[b]) {
			[a, b] = [b, a];
		}
		this.num_sets--;
		this.parent[b] = a;
		this.size[a] += this.size[b];
		this.lista[a] = this.lista[a].concat(this.lista[b]);
	}

	set_size(a) {
		return this.size[this.find(a)];
	}

	length() {
		return this.num_sets;
	}
}

