function prime_factors(n) {
	let factors = {};
	for (let i = 2; i <= Math.ceil(Math.sqrt(n)); i++) {
		while (n % i === 0) {
			if (factors[i]) {
				factors[i] += 1;
			} else {
				factors[i] = 1;
			}
			n = Math.floor(n / i);
		}
	}
	if (n > 2) {
		factors[n] = 1;
	}
	return factors;
}

function all_factors(n) {
	return new Set(Array.from({ length: Math.floor(Math.sqrt(n)) }, (_, i) => i + 1)
				 .flatMap(i => n % i === 0 ? [i, n / i] : []));
}

function fibonacci_modP(n, MOD) {
	if (n < 2) return 1;
	return (cached_fn(fibonacci_modP, Math.floor((n + 1) / 2), MOD) * 
			cached_fn(fibonacci_modP, Math.floor(n / 2), MOD) + 
			cached_fn(fibonacci_modP, Math.floor((n - 1) / 2), MOD) * 
			cached_fn(fibonacci_modP, Math.floor((n - 2) / 2), MOD)) % MOD;
}

function factorial_modP_Wilson(n, p) {
	if (p <= n) return 0;
	let res = p - 1;
	for (let i = n + 1; i < p; i++) {
		res = res * cached_fn(InverseEuler, i, p) % p;
	}
	return res;
}

function binary(n, digits=20) {
	let b = n.toString(2);
	return '0'.repeat(digits - b.length) + b;
}

function is_prime(n) {
	if (n < 4) return true;
	if (n % 2 === 0) return false;
	if (n % 3 === 0) return false;
	let i = 5;
	let w = 2;
	while (i * i <= n) {
		if (n % i === 0) return false;
		i += w;
		w = 6 - w;
	}
	return true;
}

function generate_primes(n) {
	let prime = Array(n + 1).fill(true);
	for (let p = 2; p * p <= n; p++) {
		if (prime[p]) {
			for (let i = p * 2; i <= n; i += p) {
				prime[i] = false;
			}
		}
	}
	return prime;
}

function warm_up_fac(MOD) {
	if (fac_warm_up) return;
	factorial_modP = [1, ...Array(fac_warm_up_size - 1).fill(1)];
	for (let i = 2; i < fac_warm_up_size; i++) {
		factorial_modP[i] = factorial_modP[i - 1] * i % MOD;
	}
	fac_warm_up = true;
}

function InverseEuler(n, MOD) {
	return Math.pow(n, MOD - 2) % MOD;
}

function nCr(n, r, MOD) {
	if (!fac_warm_up) {
		warm_up_fac(MOD);
	}
	return factorial_modP[n] * (Math.pow(factorial_modP[r], MOD - 2, MOD) * 
		Math.pow(factorial_modP[n - r], MOD - 2, MOD) % MOD) % MOD;
}

