function cached_fn(fn, ...args) {
	if (args in memory) {
		return memory[args];
	} else {
		let result = fn(...args);
		memory[args] = result;
		return result;
	}
}

function ncr(n, r) {
	return Math.factorial(n) / (Math.factorial(n - r) * Math.factorial(r));
}

function binary_search(i, li) {
	let fn = x => li[x] - Math.floor(x / i);
	let x = -1;
	let b = li.length;
	while (b >= 1) {
		while (b + x < li.length && fn(b + x) > 0) {
			x += b;
		}
		b = Math.floor(b / 2);
	}
	return x;
}

