function sumSeq(sumSol) {
    let numL = [];
    let tmpData = sumSol.split(''); // split the input into characters

    for (let i = 0; i < tmpData.length; i++) {
        if (tmpData[i] !== '+') {
            numL.push(parseInt(tmpData[i])); // convert to int
        }
    }

    numL.sort((a, b) => a - b); // sort numbers

    let res = '';
    for (let j = 0; j < numL.length; j++) {
        res += numL[j].toString() + '+';
    }

    return res.slice(0, -1); // remove the last '+'
