function solve_task(n) {
    if (n <= 1) {
        return 0;
    }
    let res = n;
    let he = 1;
    let n_sum = 2;
    let result = 0;

    while (res >= 2) {
        let new_sum = n_sum + 2 * (he + 1) + he;
        if (new_sum > res) {
            res -= n_sum;
            he = 1;
            n_sum = 2;
            result += 1;
        } else {
            he += 1;
            n_sum = new_sum;
        }
    }
    return result;
}

