function sol(n, arr) {
    arr.sort((a, b) => a - b);
    if (n === 2) {
        return arr;
    }
    let x = Infinity;
    let y = -1;
    for (let i = 1; i < n; i++) {
        if (arr[i] === arr[i - 1]) {
            return arr.slice(i).concat(arr.slice(0, i));
        } else if ((arr[i] - arr[i - 1]) < x) {
            x = arr[i] - arr[i - 1];
            y = i;
        }
    }
    return arr.slice(y).concat(arr.slice(0, y));
}

