function areOccurrencesEqual(s) {
    let charCnt = new Array(26).fill(0);

    for (let i = 0; i < s.length; i++) {
        let c = s.charCodeAt(i) - 'a'.charCodeAt(0);
        if (c >= 0 && c < 26) {
            charCnt[c]++;
        }
    }

    // This is going to hold the count we're checking for equality
    let sameCnt = 0;

    for (let j = 0; j < charCnt.length; j++) {
        let cnt = charCnt[j];

        if (cnt === 0) {
            continue;
        } else {
            if (sameCnt === 0) {
                sameCnt = cnt;
                continue;
            } else if (sameCnt === cnt) {
                continue;
            }
        }
        return false;
    }
    return true;
}

