class Solution {

	longestStrChain(words) {
		const that = this;
		function compare(s1, s2) {
			if (Math.abs(s1.length - s2.length) !== 1) {
				return false;
			}
			if (s2.length > s1.length) {
				let tmp = s1; 
				s1 = s2; 
				s2 = tmp; 
			}
			let broke = false;
			s1 = s1.split(''); 
			s2 = s2.split(''); 
			while (s1.length && s2.length) {
				let a = s1.pop(); 
				let b = s2.pop(); 
				if (a !== b) {
					if (broke || s1.pop() !== b) {
						return false; 
					}
					broke = true; 
				}
			}
			return true; 
		}

		let G = {}, 
			i = Infinity, 
			j = -Infinity;

		for (let w of words) {
			i = Math.min(i, w.length);
			j = Math.max(j, w.length);
			if (!G[w.length]) {
				G[w.length] = []; 
			}
			G[w.length].push([w, 1]); 
		}

		let res = 1; 
		let m = i + 1; 

		while (m <= j) {
			if (G[m]) {
				for (let [a, w1] of G[m].entries()) {
					if (G[m - 1]) {
						for (let [b, w2] of G[m - 1].entries()) {
							if (compare(w1[0], w2[0])) {
								G[m][a] = [w1[0], 1 + w2[1]];
								res = Math.max(1 + w2[1], res);
							}
						}
					}
				}
			}
			m += 1; 
		}
		return res; 
	}
}

