function gcdl(A) {
    if (A.length === 0) {
        return -1;
    }
    if (A.length === 1) {
        return 0;
    }
    let g = gcd(A[0], A[1]);
    for (let i=2; i < A.length; i++) {
        g = gcd(A[i], g);
    }
    return g;
}

function gcd(a, b) {
    if (b === 0) {
        return a;
    }
    return gcd(b, a % b);
}

