    }
    return count;
}

class Solution {

    deleteKey(root, key) {
        let lastNode = [root, idx(key[0])];
        let node = root;
        for (let i = 0; i < key.length; i++) {
            let c = key[i];
            let ci = idx(c);
            if (childCount(node) > 1) {
                lastNode = [node, ci];
            }
            node = node.children[ci];
            if (node === null) {
                return;
            }
        }
        node.isEndOfWord = false;

        let li = lastNode[1];
        lastNode[0].children[li] = null;
        return;
    }
}

