function find(parent, i) {
    let t = parent[i];
    if (t < 0) {
        return i;
    }
    t = find(parent, t);
    parent[i] = t;
    return t;
}

function unite(parent, i, j) {
    i = find(parent, i);
    j = find(parent, j);
    if (i === j) {
        return;
    }
    parent[j] += parent[i];
    parent[i] = j;
}

