class Solution {

    max_xor(arr, n) {
        let l = 0;
        try {
            l = Math.floor(Math.log2(Math.max(...arr)));
        } catch (e) {
            l = 1;
        }

        let mask = 0, res = 0;

        for (let i = l; i >= 0; i--) {
            mask |= (1 << i);
            let S = new Set(arr.map(num => mask & num));

            let temp = res | (1 << i);
            for (let num of S) {
                if (S.has(num ^ temp)) {
                    res = temp;
                    break;    
                }
            }
        }

        return res;
    }
}

