class StronglyConnectedComponent {
    constructor(n = 0) {
        this.n = n;
        this.g = Array.from({ length: n }, () => []);
        this.rev_g = Array.from({ length: n }, () => []);
    }

    size() {
        return this.n;
    }

    add(from, to) {
        if (from < 0 || from >= this.n) throw new Error('Invalid from');
        if (to < 0 || to >= this.n) throw new Error('Invalid to');
        this.g[from].push(to);
        this.rev_g[to].push(from);
    }

    scc() {
        let order = [];
        let used = Array(this.n).fill(0);

        const dfs_order = (v) => {
            used[v] = 1;
            for (let u of this.g[v]) {
                if (!used[u]) dfs_order(u);
            }
            order.push(v);
        };

        for (let i = 0; i < this.n; i++) {
            if (!used[i]) dfs_order(i);
        }

        order.reverse();
        let current_num = 0;
        let scc_num = Array(this.n).fill(-1);

        const dfs_fill = (v) => {
            scc_num[v] = current_num;
            for (let u of this.rev_g[v]) {
                if (scc_num[u] === -1) dfs_fill(u);
            }
        };

        for (let i of order) {
            if (scc_num[i] === -1) {
                dfs_fill(i);
                current_num++;
            }
        }

        return scc_num;
    }
}

const input = fs.readFileSync(0, 'utf8').split('\n');
