let a = input[n + 1].split(' ').map(Number);

let nvers = 0;
let id = Array.from({ length: n }, () => Array(m).fill(-1));
let col = [];

for (let i = 0; i < n; i++) {
    for (let j = 0; j < m; j++) {
        if (grid[i][j] === '#') {
            id[i][j] = nvers++;
            col.push(j);
        }
