let scc = new StronglyConnectedComponent(nvers);
let last = Array(m).fill(-1);

for (let i = 0; i < n; i++) {
    for (let j = 0; j < m; j++) {
        if (id[i][j] !== -1 && last[j] !== -1) {
            scc.add(last[j], id[i][j]);
        }
        if (i && id[i][j] !== -1 && id[i - 1][j] !== -1) {
            scc.add(id[i][j], id[i - 1][j]);
        }
    }

    for (let j = 0; j < m; j++) {
        if (id[i][j] !== -1) {
            last[j] = id[i][j];
        }
    }

    for (let j = 0; j < m; j++) {
        if (id[i][j] === -1) continue;
        if (j && last[j - 1] !== -1) {
            scc.add(last[j - 1], id[i][j]);
        }
        if (j !== m - 1 && last[j + 1] !== -1) {
            scc.add(last[j + 1], id[i][j]);
        }
    }
}

let scc_num = scc.scc();
let new_vers = Math.max(...scc_num) + 1;
let g = Array.from({ length: new_vers }, () => []);
let in_deg = Array(new_vers).fill(0);

for (let v = 0; v < nvers; v++) {
    for (let u of scc.g[v]) {
        if (scc_num[v] !== scc_num[u]) {
            g[scc_num[v]].push(scc_num[u]);
            in_deg[scc_num[u]]++;
        }
    }
}

let need = Array(new_vers).fill(false);
for (let j = 0; j < m; j++) {
