let removed = Array(new_vers).fill(false);
let que = [];

for (let i = 0; i < new_vers; i++) {
    if (in_deg[i] === 0) que.push(i);
}

let initial_in_deg = [...in_deg];

while (que.length) {
    let v = que.shift();
    for (let u of g[v]) {
        if (removed[v] || need[v]) removed[u] = true;
        if (--in_deg[u] === 0) que.push(u);
    }
}

in_deg = initial_in_deg;
let scc_components = Array.from({ length: new_vers }, () => []);

for (let i = 0; i < nvers; i++) {
    scc_components[scc_num[i]].push(i);
}

let alive = [];

for (let i = 0; i < new_vers; i++) {
    if (need[i] && !removed[i]) {
        let cur = m;
        for (let id of scc_components[i]) {
            cur = Math.min(cur, col[id]);
