        }
        let pos = alive.indexOf(cur);
        if (pos !== -1) {
            from[i] = Math.min(from[i], pos);
            to[i] = Math.max(to[i], pos);
        }
    }
}

let used = Array(new_vers).fill(false);

for (let i = 0; i < new_vers; i++) {
    if (used[i]) continue;

    (function dfs(v) {
