function nxtSmallest(string, n) {
    let stack = [];
    let top = -1;
    let res = [];

    for (let i = n - 1; i >= 0; i--) {
        let curr = string[i];
        while (top >= 0 && string[stack[top]] >= curr) {
            stack.pop();
            top--;
        }
        if (top == -1) {
            res.push(-1);
        } else {
            res.push(stack[top]);
        }
        stack.push(i);
        top++;
    }

    res.reverse();

    for (let i = 0; i < n; i++) {
        if (res[i] != -1) {
            return [i + 1, res[i] + 1];
        }
    }
    return null;
}

