function getPermutations(array) {
    let result = [];
    const permute = (arr, memo = []) => {
        if (arr.length === 0) {
            result.push(memo);
            return;
        }
        for (let i = 0; i < arr.length; i++) {
            let curr = arr[i];
            let remaining = arr.filter((_, index) => index !== i);
            permute(remaining, memo.concat([curr]));
