function findIntersection(head1, head2) {
    let temp = null;
    let head3 = null;

    while (head1 && head2) {
        if (head1.data < head2.data) {
            head1 = head1.next;
        } else if (head1.data > head2.data) {
            head2 = head2.next;
        } else {
            let newNode = new Node(head1.data);
            if (temp === null) {
                temp = newNode;
                head3 = temp;
            } else {
                temp.next = newNode;
                temp = newNode;
            }
            head1 = head1.next;
            head2 = head2.next;
        }
    }

    return head3;
}

