function areSentencesSimilar(words1, words2, pairs) {
    if (words1.length != words2.length) {
        return false;
    }

    let n = words1.length;
    let map = {}; // Using object as hashmap like in Java
    for (let i = 0; i < pairs.length; i++) {
        let a = pairs[i][0];
        let b = pairs[i][1];

        if (!(a in map)) {
            map[a] = new Set(); // Set for unique values
        }
        map[a].add(b);

        if (!(b in map)) {
            map[b] = new Set();
        }
        map[b].add(a);
    }

    for (let j = 0; j < n; j++) {
        if (words1[j] === words2[j]) {
            continue;
        }
        if (!(words1[j] in map) || !map[words1[j]].has(words2[j])) {
            return false;
        }
    }

    return true;
}

