class Bimatching {
    constructor(n, m) {
        this.n = n;
        this.m = m;
        this.vis = new Array(n).fill(false);
        this.adj = new Array(n).fill(0).map(() => []);
        this.match = new Array(m).fill(-1);
    }

    dfs(at) {
        this.vis[at] = true;
        for (let to of this.adj[at]) {
            let o = this.match[to];
            if (o === -1 || (!this.vis[o] && this.dfs(o))) {
                this.match[to] = at;
                return true;
            }
        }
        return false;
    }

    run() {
        for (let v of this.adj) {
            v.sort(() => Math.random() - 0.5);
        }
        let ans = 0;
        let used = new Array(this.n).fill(false);

        for(let i = 0; i < this.n; ++i) {
            for (let to of this.adj[i]) {
                if (this.match[to] === -1) {
                    this.match[to] = i;
                    used[i] = true;
                    ans++;
                    break;
                }
            }
        }

        for(let i = 0; i < this.n; ++i) {
            if (!used[i]) {
                this.vis.fill(false);
                ans += this.dfs(i) ? 1 : 0;
            }
        }
        return ans;
    }
}

