class Solution {
    AllParenthesis(n) {
        let l = [];
        let lt = n;
        let rt = n;
        this.gen(lt, rt, n, 0, '', l);
        return l;
    }

    gen(lt, rt, n, i, s, l) {
        if (i === 2 * n - 1) {
            l.push(s + ')');
            return;
        } else if (lt === rt) {
            this.gen(lt - 1, rt, n, i + 1, s + '(', l);
        } else if (lt === 0) {
            this.gen(lt, rt - 1, n, i + 1, s + ')', l);
        } else if (lt < rt) {
            this.gen(lt, rt - 1, n, i + 1, s + ')', l);
            this.gen(lt - 1, rt, n, i + 1, s + '(', l);
        }
    }
}

