const fs = require('fs');
const BUFSIZE = 8192;

class FastIO {
    constructor(file) {
        this._fd = file.fd;
        this.buffer = Buffer.alloc(0);
        this.writable = file.writable;
        this.newlines = 0;
    }

    read() {
        while (true) {
            const stat = fs.fstatSync(this._fd);
            const b = fs.readSync(this._fd, Buffer.alloc(Math.max(stat.size, BUFSIZE)), 0, Math.max(stat.size, BUFSIZE));
            if (b === 0) break;
            this.buffer = Buffer.concat([this.buffer, b]);
            this.newlines = this.buffer.toString().split('\n').length - 1;
        }
        return this.buffer;
    }

    readline() {
        while (this.newlines === 0) {
            const stat = fs.fstatSync(this._fd);
            const b = fs.readSync(this._fd, Buffer.alloc(Math.max(stat.size, BUFSIZE)), 0, Math.max(stat.size, BUFSIZE));
            this.buffer = Buffer.concat([this.buffer, b]);
            this.newlines = this.buffer.toString().split('\n').length - 1;
        }
        const line = this.buffer.toString().split('\n')[0];
        this.buffer = Buffer.from(this.buffer.toString().split('\n').slice(1).join('\n'));
        this.newlines--;
        return line;
    }

    flush() {
        if (this.writable) fs.writeSync(this._fd, this.buffer);
        this.buffer = Buffer.alloc(0);
    }
}

class IOWrapper {
    constructor(file) {
        this.buffer = new FastIO(file);
        this.flush = this.buffer.flush.bind(this.buffer);
        this.writable = this.buffer.writable;
        this.write = (s) => this.buffer.write(Buffer.from(s));
        this.read = () => this.buffer.read().toString();
        this.readline = () => this.buffer.readline().toString();
    }
}

