function bootstrap(func) {
    const stack = [];

    function wrapped_function(...args) {
        if (stack.length) {
            return func(...args);
        } else {
            let call = func(...args);
            while (true) {
                if (call && typeof call.next === 'function') {
                    stack.push(call);
                    call = call.next();
                } else {
                    stack.pop();
                    if (!stack.length) {
                        break;
                    }
                    call = stack[stack.length - 1].send(call);
                }
            }
            return call;
        }
    }
    return wrapped_function;
}

