function shave(stack, nex, prv) {
    let res = prv - nex;
    while (res > 0) {
        if (res >= stack[stack.length - 1][1]) {
            const tmp = stack.pop();
            res -= tmp[1];
        } else {
            stack[stack.length - 1][1] -= res;
            res = 0;
        }
    }
}

function normalize(stack) {
    if (stack[stack.length - 1][0] === stack[stack.length - 2][0]) {
        stack[stack.length - 2][1] += stack[stack.length - 1][1];
        stack.pop();
    }
}

function add(stack) {
    if (stack[stack.length - 1][1] === 1) {
        stack[stack.length - 1][0] += 1;
    } else {
        stack[stack.length - 1][1] -= 1;
        stack.push([stack[stack.length - 1][0] + 1, 1]);
    }
}

function kuriagari(stack) {
    const tmp = stack.pop();
    add(stack);
    normalize(stack);
    stack.push([1, tmp[1]]);
}

function check(a, upto) {
    let stack = [[0, 0]];
    for (let i = 0; i < n; i++) {
        if (a[i + 1] > a[i]) {
            stack.push([1, a[i + 1] - a[i]]);
            normalize(stack);
        } else {
            shave(stack, a[i + 1], a[i]);
            if (stack[stack.length - 1][0] === upto && stack[stack.length - 1][1] === a[i + 1]) {
                return false;
            } else if (stack[stack.length - 1][0] === upto) {
                kuriagari(stack);
            } else {
                add(stack);
                normalize(stack);
            }
        }
    }
    return true;
}

function binsearch(a) {
    let low = 0;
    let high = 1000000001;
    while (high - low > 1) {
        let mid = Math.floor((high + low) / 2);
        if (check(a, mid)) {
            high = mid;
        } else {
            low = mid;
        }
    }
    return high;
}

