class Solution {
    deleteTreeNodes(nodes, parent, value) {
        let subsum = Array(nodes).fill(-3.14);
        let leaves = new Set([...Array(nodes).keys()].filter(i => !parent.includes(i)));
        let dic = {};

        for (let i = 0; i < parent.length; i++) {
            if (dic[parent[i]]) {
                dic[parent[i]].push(i);
            } else {
                dic[parent[i]] = [i];
            }
        }

        for (let i of leaves) {
            subsum[i] = value[i];
        }

        for (let i = 0; i < nodes; i++) {
            if (subsum[i] !== -3.14) {
                continue;
            } else {
                subsum[i] = this.getsum(subsum, dic, value, i);
            }
        }

        console.log(subsum);

        let visited = Array(nodes).fill(false);
        let count = nodes;

        for (let i = 0; i < nodes; i++) {
            if (subsum[i] === 0 && !visited[i]) {
                let q = [i];
                while (q.length !== 0) {
                    let curr = q.shift();
                    visited[curr] = true;
                    count--;
                    if (dic[curr]) {
                        q.push(...dic[curr]);
                    }
                }
            }
        }
        return count;
    }

    getsum(subsum, dic, value, i) {
        if (subsum[i] !== -3.14) {
            return subsum[i];
        }
        let s = value[i];
        for (let j of (dic[i] || [])) {
            subsum[j] = this.getsum(subsum, dic, value, j);
            s += subsum[j];
        }
        return s;
    }
}

