function nextPalin(N) {
    let a = [];
    let ans = '';
    let f = 0;
    let lenN = N.length;

    for (let i = Math.floor(lenN / 2) - 1; i >= 0; i--) {
        a.push(parseInt(N[i]));
        if (N[i] > N[i - 1]) {
            f = 1;
            break;
        }
    }

    if (f === 0) {
        return -1;
    }

    let i = Math.floor(lenN / 2) - 1;
    i = i < 0 ? 0 : i;
    a.sort();

    for (let j = 0; j < a.length; j++) {
        ans += a[j].toString();
    }

    ans = N[i] + ans;

    for (let j = 1; j < ans.length; j++) {
        if (parseInt(ans[0]) < parseInt(ans[j])) {
            ans = ans[j] + ans.slice(1, j) + ans[0] + ans.slice(j + 1);
            break;
        }
    }

    ans = N.slice(0, i) + ans;

    if (lenN % 2 === 0) {
        ans += ans.split('').reverse().join('');
    } else {
        ans += N[Math.floor(lenN / 2)] + ans.split('').reverse().join('');
    }

    return ans;
}

