class Solution {
    minEdgeReversals(n, edges) {
        let G = Array.from({ length: n }, () => []);
        for (const [u, v] of edges) {
            G[u].push([v, 1]);
            G[v].push([u, 0]);
        }

        let cnt = new Array(n).fill(0);
        let sm = new Array(n).fill(0);
        let par = new Array(n).fill(-1);
        let st = [0];

        while (st.length > 0) {
            let cur = st.pop();
            if (cur >= 0) {
                st.push(~cur);
                for (const [nxt, w] of G[cur]) {
                    if (par[cur] === nxt) continue;
                    par[nxt] = cur;
                    st.push(nxt);
                }
            } else {
                cur = ~cur;
                for (const [nxt, w] of G[cur]) {
                    if (par[cur] === nxt) continue;
                    sm[cur] += sm[nxt] + 1;
                    cnt[cur] += 1 - w + cnt[nxt];
                }
            }
        }

        par.fill(-1);
        st = [0];
        let S = cnt[0];
        let ans = new Array(n).fill(-1);
        let cnt2 = new Array(n).fill(0);
        let cnt3 = new Array(n).fill(0);

        while (st.length > 0) {
            let cur = st.pop();
            ans[cur] = S - cnt2[cur] + cnt3[cur];

            for (const [nxt, w] of G[cur]) {
                if (par[cur] === nxt) continue;
                par[nxt] = cur;
                cnt2[nxt] = cnt2[cur] + 1 - w;
                cnt3[nxt] = cnt3[cur] + w;
                st.push(nxt);
            }
        }

        return ans;
    }
}

