class Solution {

    decodedString(s) {
        let a = []
        let n = s.length
        let i = 0

        while (i < n) {
            if (this.isAlpha(s[i])) {
                a.push(s[i])
                i += 1
            } else if (this.isNumeric(s[i])) {
                let x = ''
                while (this.isNumeric(s[i])) {
                    x += s[i]
                    i += 1
                }
                a.push(x)
            } else {
                if (s[i] === '[') {
                    a.push(s[i])
                } else {
                    let x = ''
                    while (a[a.length - 1] !== '[') {
                        x += a.pop()
                    }
                    a.pop()
                    let repeatCount = parseInt(a.pop())
                    a.push(this.repeatString(x, repeatCount))
                }
                i += 1
            }
        }

        let resultString = ''
        for (let j = 0; j < a.length; j++) {
            resultString += a[j]
        }
        return this.reverseString(resultString)
    }

    isAlpha(char) {
        return /^[a-zA-Z]$/.test(char)
    }

    isNumeric(char) {
        return /^[0-9]$/.test(char)
    }

    repeatString(str, count) {
        let result = ''
        for (let k = 0; k < count; k++) {
            result += str
        }
        return result
    }

    reverseString(str) {
        let reversed = ''
        for (let l = str.length - 1; l >= 0; l--) {
            reversed += str[l]
        }
        return reversed
    }
}

