class Solution {
    minCost(s, cost) {
        let arr = s.split('');
        let totalCost = 0;
        let i = 0;

        while (i < arr.length - 1) {
            let start = 0;
            let end = 0;

            if (arr[i] === arr[i + 1]) {
                start = i;
                while (i < arr.length - 1 && arr[i] === arr[i + 1]) {
                    end = i + 1;
                    i++;
                }
                totalCost += this.calculateCost(cost, start, end);
            } else {
                i++;
            }
        }

        return totalCost;
    }

    calculateCost(cost, start, end) {
        let sumCost = 0;
        let maxCost = 0;

        for (let j = start; j <= end; j++) {
            sumCost += cost[j];
            if (cost[j] > maxCost) {
                maxCost = cost[j];
            }
        }

        return sumCost - maxCost;
    }
}

