const fs = require('fs');

class ListNode {
    constructor(val = 0, next = null) {
        this.val = val;
        this.next = next;
    }
}

class Solution {
    swapNodes(head, k) {
        let headPtr = new ListNode(0, head);
        let headRem = k;

        let firstPtr = null;
        let secondPtr = null;

        let node = headPtr;
        while (node.next) {
            headRem -= 1;
            if (headRem === 0) {
                firstPtr = node;
                secondPtr = headPtr;
            }
            if (headRem < 0) {
                secondPtr = secondPtr.next;
            }
            node = node.next;
        }

        if (firstPtr !== secondPtr) {
            if (firstPtr.next === secondPtr) {
                let tmp = secondPtr.next;
                secondPtr.next = tmp.next;
                tmp.next = firstPtr.next;
                firstPtr.next = tmp;
            } else if (secondPtr.next === firstPtr) {
                let tmp2 = firstPtr.next;
                firstPtr.next = tmp2.next;
                tmp2.next = secondPtr.next;
                secondPtr.next = tmp2;
            } else {
                let tmp3 = firstPtr.next.next;
                let tmp4 = secondPtr.next.next;
                firstPtr.next.next = tmp4;
                secondPtr.next.next = tmp3;
                let tmp5 = firstPtr.next;
                firstPtr.next = secondPtr.next;
                secondPtr.next = tmp5;
            }
        }
        return headPtr.next;
    }
}

function run(){
    const input = fs.readFileSync(0, 'utf8').split('\n');
    // Assuming first line is k and second line is the linked list
    const k = parseInt(input[0]);
    const values = input[1].split(' ').map(Number);

    let head = null;
    let tail = null;

    for (let val of values) {
        let newNode = new ListNode(val);
        if (!head) {
            head = newNode;
            tail = newNode;
        } else {
            tail.next = newNode;
            tail = tail.next;
        }
    }

    const solution = new Solution();
    const result = solution.swapNodes(head, k);

    // Output the result linked list
    let output = [];
    while (result) {
        output.push(result.val);
        result = result.next;
    }
    console.log(output.join(' '));
}

run();

