const Maxn = 1e4, Maxs = 1024, inf = 1e9;

let Edge = [], Head = new Array(Maxn + 5).fill(0), tot = 1, cur = new Array(Maxn + 5).fill(0);
let vis = new Array(Maxn + 5).fill(0), dis = new Array(Maxn + 5).fill(0), ans = new Array(1024).fill(0);
let w = new Array(1024).fill(0), bit = new Array(1024).fill(0), lg = new Array(1024).fill(0);
let hzh = Array.from({length: Maxn + 5}, () => ({}));
let n, m, k, q, lim;

function read() {
