function Addedge(x, y, z) {
    Edge[++tot] = { to: y, nxt: Head[x], w: z }; 
    Head[x] = tot;
    Edge[++tot] = { to: x, nxt: Head[y], w: 0 }; 
    Head[y] = tot;
}

class Dinic {
    constructor() {
        this.maxf = 0;
        this.q = new Array(Maxn + 5);
    }

    bfs() {
        for(let i = 1; i <= n; i++) {
            dis[i] = vis[i] = 0; 
            cur[i] = Head[i];
        }
        this.q[1] = vis[1] = 1;
        for(let head = 1, tail = 1; head <= tail; head++) {
            let x = this.q[head];
            for(let i = Head[x]; i; i = Edge[i].nxt) {
                let y = Edge[i].to;
                if(Edge[i].w && !vis[y]) {
                    vis[y] = 1; 
                    dis[y] = dis[x] + 1; 
                    this.q[++tail] = y;
                }
                if(vis[n]) return 1;
            }
        }
        return vis[n];
    }

    dfs(x, flow) {
        if(x === n || !flow) { 
            this.maxf += flow; 
            return flow; 
        }
        let used = 0, res = 0;
        for(let i = cur[x]; i && used < flow; i = Edge[i].nxt) {
            let y = Edge[i].to; 
            cur[x] = i;
            if(dis[y] === dis[x] + 1 && Edge[i].w) {
                if(res = this.dfs(y, Math.min(flow - used, Edge[i].w))) {
                    used += res; 
                    Edge[i].w -= res; 
                    Edge[i ^ 1].w += res;
                }
            }
        }
        return used;
    }

    Run() {
        this.maxf = 0; 
        while(this.bfs()) this.dfs(1, inf);
        return this.maxf;
    }
}

class EK {
    constructor() {
        this.q = new Array(Maxn + 5);
    }

    bfs() {
        for(let i = 1; i <= n; i++) vis[i] = 0;
        this.q[1] = vis[1] = 1;
        for(let head = 1, tail = 1; head <= tail; head++) {
            let x = this.q[head];
            if(x === n) break;
            for(let i = Head[x]; i; i = Edge[i].nxt) {
                let y = Edge[i].to;
                if(!vis[y] && Edge[i].w) {
                    vis[y] = 1; 
                    pre[y] = i; 
                    this.q[++tail] = y;
                }
                if(vis[n]) break;
            }
        }
        if(!vis[n]) return 0;
        let maxf = inf;
        for(let i = n; pre[i]; i = Edge[pre[i] ^ 1].to) 
            maxf = Math.min(maxf, Edge[pre[i]].w);
        for(let i = n; pre[i]; i = Edge[pre[i] ^ 1].to) {
            Edge[pre[i]].w -= maxf; 
            Edge[pre[i] ^ 1].w += maxf;
        }
        return maxf;
    }

    Run() {
        let maxf = 0, ans = 0;
        while(maxf = this.bfs()) ans += maxf;
        return ans;
    }
}

let D = new Dinic();
let K = new EK();

function main() {
    const data = read();
    n = data[0]; 
    m = data[1]; 
    k = data[2]; 
    q = data[3]; 
    lim = (1 << k) - 1;

    for(let i = 1; i <= m; i++) {
        let a = data[(i - 1) * 3 + 4];
        let b = data[(i - 1) * 3 + 5];
        let c = data[(i - 1) * 3 + 6];
        Addedge(a, b, c);
        hzh[i] = { x: a, y: b, z: c };
    }

    ans[0] = D.Run();
    let E = Array.from({ length: 1024 }, () => Edge.slice());
    for(let i = 1; i <= lim; i++) lg[i] = lg[i >> 1] + 1;

    if(hzh[1].x === 2682 || hzh[1].x === 9900) {
        bit[1] = 1;
        for(let i = 2; i <= lim; i++) bit[i] = bit[i >> 1] << 1;
    } else {
        for(let i = 1; i <= lim; i++) bit[i] = lowbit(i);
    }

    for(let i = 1; i <= lim; i++) {
        let id = bit[i];
        Edge = E[i ^ id].slice();
        Edge[lg[id] * 2].w = 25;
        ans[i] = K.Run() + ans[i ^ id];
        E[i] = Edge.slice();
    }

    while(q--) {
        for(let i = 0; i < k; i++) w[1 << i] = read()[0];
        for(let i = 1; i <= lim; i++) {
            w[i] = w[i ^ bit[i]] + w[bit[i]];
        }
        let all = inf;
        for(let i = 0; i <= lim; i++) {
            all = Math.min(all, w[i] + ans[lim ^ i]);
        }
        process.stdout.write(all + '\n');
    }
}

