function didWeWin(plays) {
    if (anyTurnoverOrEmpty(plays)) {
        return false;
    }
    if (notAllPlays(plays)) {
        return true;
    }
    let totalYards = calculateTotalYards(plays);
    return totalYards > 10;
}

function anyTurnoverOrEmpty(plays) {
    for (let i = 0; i < plays.length; i++) {
        let play = plays[i];
        if (play && (play[1] == 'turnover' || play.length === 0)) {
            return true;
        }
    }
    return false;
}

function notAllPlays(plays) {
    for (let i = 0; i < plays.length; i++) {
        if (!plays[i]) {
            return true;
        }
    }
    return false;
}

function calculateTotalYards(plays) {
    let total = 0;
    for (let i = 0; i < plays.length; i++) {
        let play = plays[i];
        if (play) {
            let yards = play[0];
            let action = play[1];
            if (action == 'sack') {
                total -= yards;
            } else {
                total += yards;
            }
        }
    }
    return total;
}

