const fs = require('fs');

function choose(n, k, factorial, ifactorial) {
    return factorial[n] * ifactorial[n - k] * ifactorial[k] % 998244353;
}

function computeFactorials(n) {
    let factorial = [1];
    for (let i = 1; i <= n; i++) {
        factorial.push(factorial[factorial.length - 1] * i % 998244353);
    }
    return factorial;
}

function computeInverseFactorials(n, factorial) {
    let ifactorial = new Array(n + 1).fill(1);
    let curr = modPow(factorial[n], 998244353 - 2, 998244353);
    for (let i = n; i > 0; i--) {
        ifactorial[i] = curr;
        curr = curr * i % 998244353;
    }
    return ifactorial;
}

function modPow(a, b, mod) {
    let result = 1;
    while (b > 0) {
        if (b % 2 === 1) {
            result = result * a % mod;
        }
        a = a * a % mod;
        b = Math.floor(b / 2);
    }
    return result;
}

function prog() {
    const input = fs.readFileSync(0, 'utf8');
    let data = input.split(' ').map(Number);
    let n = data[0], k = data[1];

    let factorial = computeFactorials(n);
    let ifactorial = computeInverseFactorials(n, factorial);

    let tot_stable = 0;
    for (let smallest = 1; smallest <= Math.floor(n / k); smallest++) {
        tot_stable += choose(Math.floor(n / smallest) - 1, k - 1, factorial, ifactorial);
    }

    console.log(tot_stable % 998244353);
}

