function minFlips(a, b, c) {
    let res = 0;
    let x = a.toString(2).padStart(32, '0');
    let y = b.toString(2).padStart(32, '0');
    let z = c.toString(2).padStart(32, '0');

    for(let i = 0; i < 32; i++) {
        let zBit = z[i] === '1';
        let xBit = x[i] === '1';
        let yBit = y[i] === '1';

        if(zBit) {
            if(!xBit && !yBit) {
                res += 1;
            }
        } else {
            res += Number(xBit) + Number(yBit);
        }
    }

    return res;
