function movesToChessboard($board) {
    $n = count($board);
    if ($n == 0) return -1;

    $rowZeroCount = 0; 
    $colZeroCount = 0;
    for ($i=0; $i<$n; $i++) {
        if ($board[0][$i] == 0) {
            $rowZeroCount++;
        }
        if ($board[$i][0] == 0) {
            $colZeroCount++;
        }
    }

    if (abs($rowZeroCount - ($n - $rowZeroCount)) > 1 || abs($colZeroCount - ($n - $colZeroCount)) > 1)
        return -1;

    for ($i=1; $i<$n; $i++) {
        $isInverseRow = false; 
        $isInverseCol = false;

        for ($j=0; $j<$n; $j++) {
            if ($j == 0) {
                if ($board[$i][$j] != $board[0][$j]) {
                    $isInverseRow = true;
                }
                if ($board[$j][$i] != $board[$j][0]) {
                    $isInverseCol = true;
                }
            } else {
                if ($isInverseRow == ($board[$i][$j] == $board[0][$j])) {
                    return -1;
                }
                if ($isInverseCol == ($board[$j][$i] == $board[$j][0])) {
                    return -1;
                }
            }
        }
    }

    $rowSwaps = 0; 

    if ($n % 2 == 1) {
        $oneFirst = $rowZeroCount < ($n - $rowZeroCount);
        for ($i=0; $i<$n; $i++) {
            if ($oneFirst && $board[0][$i] == $i % 2 || !$oneFirst && $board[0][$i] != $i % 2) {
                $rowSwaps++;
            }
        }

    } else {
        for ($i=0; $i<$n; $i++) {
            if ($board[0][$i] != $i % 2) {
                $rowSwaps++;
            }
        }

        $rowSwaps = min($rowSwaps, $n - $rowSwaps);
    }

    $rowSwaps /= 2;

    $colSwaps = 0; 

    if ($n % 2 == 1) {
        $oneFirst = $colZeroCount < ($n - $colZeroCount);
        for ($i=0; $i<$n; $i++) {
            if ($oneFirst && $board[$i][0] == $i % 2 || !$oneFirst && $board[$i][0] != $i % 2) {
                $colSwaps++;
            }
        }
    } else {
        for ($i=0; $i<$n; $i++) {
            if ($board[$i][0] != $i % 2) {
                $colSwaps++;
            }
        }

        $colSwaps = min($colSwaps, $n - $colSwaps);
    }

    $colSwaps /= 2;

    return $rowSwaps + $colSwaps;
}

