func main() {
	reader := bufio.NewReader(os.Stdin)

	fmt.Print("Enter your initial input: ")
	x, _ := reader.ReadString('\n')
	x = strings.TrimSpace(x)
	p := strings.Split(x, " ")

	fmt.Print("Enter a number for how many pairs will follow: ")
	var a int
	_, _ = fmt.Fscan(reader, &a)

	array := make([]string, 0)

	for i := 0; i < a; i++ {
		fmt.Print("Enter your next input pair: ")
		y, _ := reader.ReadString('\n')
		y = strings.TrimSpace(y)
		z := strings.Split(y, " ")
		m := z[0]
		n := z[1]

		t := findIndex(p, m)
		if t != -1 {
			p[t] = n
		}

		array = append(array, p[0])
		array = append(array, p[1])
	}

	fmt.Println(x)
	printArray(array, a)
}

func findIndex(p []string, m string) int {
	for i := 0; i < len(p); i++ {
		if p[i] == m {
			return i
		}
	}
	return -1
}

func printArray(array []string, a int) {
	for i := 0; i < a*2; i += 2 {
		fmt.Println(array[i] + " " + array[i+1])
	}
}

