			*a = false
		}
		*x = *x / 2
		c += 1
	}
	return c
}

func calculateSum(c int) int {
	s := 0
	for c > 0 {
		c = c - 1
		s = s + powerOfTwo(c)
	}
	return s
}

func powerOfTwo(exp int) int {
	return 1 << exp
}

