}

func countCards(cards []int) map[int]int {
	countMap := make(map[int]int)
	for _, card := range cards {
		countMap[card]++ 
	}
	return countMap
}

func calculateMaxDis(countMap map[int]int) int {
	maxDis := 0
	for card, qtd := range countMap {
		if qtd > 1 {
			multiplier := minimum(qtd, 3)
			tmpDis := card * multiplier
			if tmpDis > maxDis {
				maxDis = tmpDis
			}
		}
	}
	return maxDis
}

func minimum(a, b int) int {
	if a < b {
		return a
	}
	return b
}

func sumCards(cards []int) int {
	total := 0
	for _, card := range cards {
		total += card
	}
	return total
}

