		fmt.Println(result)
	} else {
		sp1 := doSp1(n, z)
		sp11 := make(map[int]struct{})
		for _, val := range sp1 {
			sp11[val] = struct{}{}
		}

		sp2 := doSp2(m, z)
		sp22 := make(map[int]struct{})
		for _, val := range sp2 {
			sp22[val] = struct{}{}
		}

		res := intersect(sp11, sp22)
		fmt.Println(len(res))
	}
}

func doSp1(n int, z int) []int {
	tmp := []int{}
	for k := n; k <= z; k += n {
		tmp = append(tmp, k)
	}
	return tmp
}

func doSp2(m int, z int) []int {
	tmp2 := []int{}
	for d := m; d <= z; d += m {
		tmp2 = append(tmp2, d)
	}
	return tmp2
}

func intersect(a, b map[int]struct{}) []int {
	result := []int{}
	for key := range a {
		if _, ok := b[key]; ok {
			result = append(result, key)
		}
	}
	return result
}

