func doWorks(counter []int, N int) int {
	res1 := num(counter, 75)
	res2 := num(counter, 25) * (num(counter, 3) - 1)
	res3 := num(counter, 15) * (num(counter, 5) - 1)
	res4 := num(counter, 5) * (num(counter, 5) - 1) * (num(counter, 3) - 2) / 2
	total := res1 + res2 + res3 + res4
	return total
}

func num(counter []int, n int) int {
	count := 0
	for m := 2; m < len(counter); m++ {
		if counter[m] >= n - 1 {
			count++
		}
	}
	return count
}

