			c := s[j+2]
			if isLessThanThreeDistinct(a, b, c) {
				if j == 0 {
					l[j] = 1 // edge case for first element
				} else {
					l[j] = l[j-1] + 1
				}
			} else {
				if j == 0 {
					l[j] = 0 // edge case for first element
				} else {
					l[j] = l[j-1]
				}
			}
		}

		for k := 0; k < q; k++ {
			var left, right int
			fmt.Fscan(reader, &left, &right)
			left -= 1
			right -= 1

			if right-left+1 < 3 {
