func isLessThanThreeDistinct(a, b, c byte) bool {
	set := make(map[byte]bool)
	set[a] = true
	set[b] = true
	set[c] = true
	return len(set) < 3
}

func getLeftValue(l []int, left int) int {
	if left == 0 {
		return 0
	}
	return l[left-1]
}

