func main() {
	reader := bufio.NewReader(os.Stdin)
	var n int
	fmt.Fscan(reader, &n)
	a := make([]int, n)

	for i := 0; i < n; i++ {
		fmt.Fscan(reader, &a[i])
	}

	result := lexicographicallyLargest(a, n)
	for _, v := range result {
		fmt.Print(v, " ")
	}
}

func lexicographicallyLargest(a []int, n int) []int {
	prev := 0
	if a[0] % 2 == 0 {
		prev = 1
	}
	k := []int{a[0]}
	res := make([]int, 0)

	for i := 1; i < n; i++ {
		tmp := a[i]
		if tmp % 2 == 0 && prev == 1 {
			k = append(k, tmp)
		} else if tmp % 2 == 0 && prev == 0 {
			res = append(res, sortedAndReversed(k...)...)
			k = []int{tmp}
			prev = 1
		} else if tmp % 2 != 0 && prev == 0 {
			k = append(k, tmp)
		} else {
			res = append(res, sortedAndReversed(k...)...)
			k = []int{tmp}
			prev = 0
		}
	}
	res = append(res, sortedAndReversed(k...)...)
	return res
}

func sortedAndReversed(arr ...int) []int {
	s := make([]int, len(arr))
	copy(s, arr)
	sort.Ints(s)
	for i, j := 0, len(s)-1; i < j; i, j = i+1, j-1 {
		s[i], s[j] = s[j], s[i]
	}
	return s
}

