func makeSets(input string) [][]rune {
	data := strings.Split(input, " ")
	sets := make([][]rune, len(data))
	for i := 0; i < len(data); i++ {
		sets[i] = createSet(data[i])
	}
	return sets
}

func createSet(item string) []rune {
	tmpSet := make(map[rune]struct{})
	for _, char := range item {
		tmpSet[char] = struct{}{}
	}
	setSlice := make([]rune, 0, len(tmpSet))
	for key := range tmpSet {
		setSlice = append(setSlice, key)
	}
	return setSlice
}

func doCalculations(sets [][]rune) int {
	ans := 0
	for i := 0; i < 101; i++ {
		if len(sets) == 1 {
			break
		}
		tmp := sets[0]
		for j := 1; j < len(sets); j++ {
			tmp = intersect(tmp, sets[j])
		}
		if len(tmp) >= 1 {
			break
		}
		sets = mergeSets(sets)
		ans += 1
	}
	return ans
}

func intersect(a []rune, b []rune) []rune {
	tmpMap := make(map[rune]struct{})
	for _, val := range a {
		tmpMap[val] = struct{}{}
	}
	intersection := []rune{}
	for _, val := range b {
		if _, exists := tmpMap[val]; exists {
			intersection = append(intersection, val)
		}
	}
	return intersection
}

func mergeSets(sets [][]rune) [][]rune {
	newSets := make([][]rune, len(sets)-1)
	for j := 0; j < len(sets)-1; j++ {
		newSet := union(sets[j], sets[j + 1])
		newSets[j] = newSet
	}
	return newSets
}

func union(a []rune, b []rune) []rune {
	tmpMap := make(map[rune]struct{})
	for _, val := range a {
		tmpMap[val] = struct{}{}
	}
	for _, val := range b {
		tmpMap[val] = struct{}{}
	}
	unionSet := []rune{}
	for key := range tmpMap {
		unionSet = append(unionSet, key)
	}
	return unionSet
}

