	"os"
	"sort"
)

func bipartiteMatch(graph map[[2]int]map[[2]int]bool) (map[[2]int][2]int, []interface{}, []interface{}) {
	matching := make(map[[2]int][2]int)
	for u := range graph {
		for v := range graph[u] {
			if _, ok := matching[v]; !ok {
				matching[v] = u
				break
			}
		}
	}

	for {
		preds := make(map[[2]int][][2]int)
		unmatched := []([2]int){}
		pred := make(map[[2]int][][2]int)

		for u := range graph {
			pred[u] = unmatched
		}

		for v := range matching {
			delete(pred, matching[v])
		}

		layer := make([][2]int, 0)
		for k := range pred {
			layer = append(layer, k)
		}

		for len(layer) > 0 && len(unmatched) == 0 {
			newLayer := make(map[[2]int][][2]int)
			for _, u := range layer {
				for v := range graph[u] {
					if _, ok := preds[v]; !ok {
						newLayer[v] = append(newLayer[v], u)
					}
				}
			}
			layer = []([2]int){}
			for v := range newLayer {
				preds[v] = newLayer[v]
				if u, ok := matching[v]; ok {
					layer = append(layer, u)
					pred[u] = append(pred[u], v)
				} else {
					unmatched = append(unmatched, v)
				}
			}
		}

		if len(unmatched) == 0 {
			unlayered := make(map[[2]int]interface{})
			for u := range graph {
				for v := range graph[u] {
					if _, ok := preds[v]; !ok {
						unlayered[v] = nil
					}
				}
			}
			return matching, []interface{}{}, []interface{}{}
		}

		var recurse func(v [2]int) int
		recurse = func(v [2]int) int {
			if lst, ok := preds[v]; ok {
				L := lst
				delete(preds, v)
				for _, u := range L {
					if pu, ok := pred[u]; ok {
						delete(pred, u)
						if pu == unmatched || recurse(pu) == 1 {
							matching[v] = u
							return 1
						}
					}
				}
			}
			return 0
		}

		for _, v := range unmatched {
			recurse(v)
		}
	}
}

func main() {
	reader := bufio.NewReader(os.Stdin)
	var N, M, K int
	fmt.Fscan(reader, &N, &M, &K)

	bikers := make([][2]int, N)
	bikes := make([][2]int, M)

	for i := 0; i < N; i++ {
		fmt.Fscan(reader, &bikers[i][0], &bikers[i][1])
	}
	for i := 0; i < M; i++ {
		fmt.Fscan(reader, &bikes[i][0], &bikes[i][1])
	}

	edges := []struct{ dist int; biker, bike [2]int }{}
	for _, biker := range bikers {
		for _, bike := range bikes {
			dist := (biker[0]-bike[0])*(biker[0]-bike[0]) + (biker[1]-bike[1])*(biker[1]-bike[1])
			edges = append(edges, struct{ dist int; biker, bike [2]int }{dist, biker, bike})
		}
	}
	sort.Slice(edges, func(i, j int) bool { return edges[i].dist > edges[j].dist })

	bikerHits := make(map[[2]int]int)
	bikeHits := make(map[[2]int]int)

	for _, biker := range bikers {
		bikerHits[biker] = 0
	}
	for _, bike := range bikes {
		bikeHits[bike] = 0
	}

	neighbors := make(map[[2]int]map[[2]int]bool)
	for _, biker := range bikers {
		neighbors[biker] = make(map[[2]int]bool)
		for _, bike := range bikes {
			neighbors[biker][bike] = true
		}
	}

	G := make(map[[2]int]map[[2]int]bool)
	for biker := range bikers {
		G[biker] = neighbors[biker]
	}

	matching, _, _ := bipartiteMatch(G)
	matchingPairs := make(map[[2]int][2]int)
	for bike, biker := range matching {
		matchingPairs[bike] = biker
	}

	for _, edge := range edges {
		bikerHits[edge.biker]++
		bikeHits[edge.bike]++
		delete(neighbors[edge.biker], edge.bike)

		if _, ok := matchingPairs[edge.bike]; ok {
			G = make(map[[2]int]map[[2]int]bool)
			for biker := range bikers {
				G[biker] = neighbors[biker]
			}
			matching, _, _ = bipartiteMatch(G)
			matchingPairs = make(map[[2]int][2]int)
			for bike, biker := range matching {
				matchingPairs[bike] = biker
			}
			if len(matching) < K {
				fmt.Println(edge.dist)
				break
			}
		}
		if bikerHits[edge.biker] == M {
			delete(bikers, edge.biker)
		}
	}
}

