const N = 1000000

var f [N]bool

func main() {
	reader := bufio.NewReader(os.Stdin)
	var n int
	fmt.Fscan(reader, &n)

	g := make([][]int, n)

	for i := 1; i < n; i++ {
		var p int
		fmt.Fscan(reader, &p)
		p -= 1
		g[p] = append(g[p], i)
		g[i] = append(g[i], p)
	}

	sz := make([]int, n)

	var dfs func(u, fa int)
	dfs = func(u, fa int) {
		sz[u] = 1
		for _, v := range g[u] {
			if v == fa {
				continue
			}
			dfs(v, u)
			sz[u] += sz[v]
		}
	}

	var getCen func(u, fa int) int
	getCen = func(u, fa int) int {
		for _, v := range g[u] {
			if v == fa || sz[v]*2 <= n {
				continue
			}
			return getCen(v, u)
		}
		return u
	}

	dfs(0, -1)
	root := getCen(0, -1)
	dfs(root, -1)

	cnt := make([]int, n)
	for _, v := range g[root] {
		cnt[sz[v]] += 1
	}

	f[0] = true
	for i := 1; i < n; i++ {
		if cnt[i] > 0 {
			k := 1
			for k <= cnt[i] {
				f[i*k] = f[i*k] || (k*i < N && f[k*i])
				cnt[i] -= k
				k <<= 1
			}
			if cnt[i] > 0 {
				f[i*cnt[i]] = true
			}
		}
	}

	res := 0
	for i := 0; i < n; i++ {
		if f[i] {
			if res < i*(n-i-1) {
				res = i * (n - i - 1)
			}
		}
	}

	totalSz := int64(0)
	for _, szVal := range sz {
		totalSz += int64(szVal)
	}

	res += totalSz
	fmt.Println(res)
}

