func cross(a complex128, b complex128) float64 {
	return real(a) * imag(b) - imag(a) * real(b)
}

func cross_point(p1 complex128, p2 complex128, p3 complex128, p4 complex128) complex128 {
	base := p4 - p3
	hypo1 := p1 - p3
	hypo2 := p2 - p3
	d1 := abs(cross(base, hypo1)) / abs(base)
	d2 := abs(cross(base, hypo2)) / abs(base)
	section := p2 - p1
	crossP := p1 + d1 / (d1 + d2) * section 
	return crossP
}

func abs(x float64) float64 {
	if x < 0 {
		return -x
	}
	return x
}

