}

func makeDivisorList(k int) []int {
	divisor_lst := make([]int, k)
	for i := 1; i <= k; i++ {
		divisor_lst[i-1] = i - 1
	}
	divisor_lst[0] = 1
	return divisor_lst
}

func fillDivisorList(k int, divisor_lst []int) {
	for i := 2; i < k; i++ {
		for j := 2 * i; j <= k; j += i {
			divisor_lst[j-1] -= divisor_lst[i-1]
		}
	}
}

func calculateAnswer(n int, k int, divisor_lst []int) int {
	ans := 0
	for num := 1; num <= k; num++ {
		tmp := pow(k/num, n, MOD)
		ans += tmp * divisor_lst[num-1]
		ans %= MOD
	}
	return ans
}

func pow(base, exp, mod int) int {
	result := 1
	base = base % mod
	for exp > 0 {
		if exp%2 == 1 {
			result = (result * base) % mod
		}
		exp = exp >> 1
		base = (base * base) % mod
	}
	return result
}

