func ternarySearch(arr []int, N int, K int) int {
	l := 0
	h := N - 1

	for l <= h {
		mid := (l + h) / 2 // calculate mid
		if arr[mid] == K {
			return 1
		} else if arr[mid] > K {
			h = mid - 1 // adjust high
		} else {
			l = mid + 1 // adjust low
		}
	}

	return -1 // not found
}

