			if s == b {
				continue
			}
			bb := splitAndGetLengths(b)
			cc := splitAndGetLengths(s)
			if sum(cc) > cc[0]+cc[len(cc)-1] || bb[0] <= cc[0] || bb[len(bb)-1] <= cc[len(cc)-1] {
				fmt.Println("NO")
				return
			}
			state += 1
		} else if state == 3 {
			if s != b {
				fmt.Println("NO")
				return
			}
			state += 1
		} else if state == 4 {
			if s == b {
				continue
			} else if s == a {
				state += 1
			} else {
				fmt.Println("NO")
				return
			}
		} else if state == 5 {
			if s != a {
				fmt.Println("NO")
				return
			}
		} else {
			fmt.Println("NO")
			return
		}
	}

	if state < 4 {
		fmt.Println("NO")
	} else {
		fmt.Println("YES")
	}
}

func countStars(s string) int {
	count := 0
	for _, c := range s {
		if c == '*' {
			count++
		}
	}
	return count
}

func splitAndGetLengths(s string) []int {
	parts := strings.Split(s, "*")
	lengths := make([]int, len(parts))
	for i, part := range parts {
		lengths[i] = len(part)
	}
	return lengths
}

func sum(arr []int) int {
	total := 0
	for _, v := range arr {
		total += v
	}
	return total
}

