const TERM_CHAR = '\x00'

func buildTrie(words []string) map[rune]map[rune]interface{} {
	trie := make(map[rune]map[rune]interface{})
	for _, word := range words {
		current := trie
		for _, c := range word {
			if _, ok := current[c]; !ok {
				current[c] = make(map[rune]interface{})
			}
			current = current[c].(map[rune]interface{})
		}
		current[TERM_CHAR] = true
	}
	return trie
}

type StreamChecker struct {
	trie           map[rune]map[rune]interface{}
	trieCurrents   []map[rune]interface{}
}

func NewStreamChecker(words []string) *StreamChecker {
	trie := buildTrie(words)
	return &StreamChecker{trie: trie, trieCurrents: []map[rune]interface{}{}}
}

func (sc *StreamChecker) Query(letter rune) bool {
	found := false
	nextTries := []map[rune]interface{}{}

	for _, current := range append(sc.trieCurrents, sc.trie) {
		if next, ok := current[letter]; ok {
			nextTries = append(nextTries, next.(map[rune]interface{}))
			if _, exists := next.(map[rune]interface{})[TERM_CHAR]; exists {
				found = true
			}
		}
	}
	sc.trieCurrents = nextTries
	return found
}

func main() {
	reader := bufio.NewReader(os.Stdin)
	var n int
	fmt.Fscan(reader, &n)
	words := make([]string, n)
	for i := 0; i < n; i++ {
		fmt.Fscan(reader, &words[i])
	}
	sc := NewStreamChecker(words)

	var queryCount int
	fmt.Fscan(reader, &queryCount)
	for i := 0; i < queryCount; i++ {
		var letter string
		fmt.Fscan(reader, &letter)
		if len(letter) > 0 {
			result := sc.Query(rune(letter[0]))
			fmt.Println(result)
		}
	}
}

