func roastLegacy(s string) string {
	cpn := countComplaints(s)
	points := extractPoints(s)
	p := calculatePoints(points)

	if p > 0 || cpn > 0 {
		return fmt.Sprintf("Burn baby burn disco inferno %d points earned in this roasting and %d complaints resolved!", p, cpn)
	}
	return "These guys are already DevOps and in the Cloud and the business is happy!"
}

func countComplaints(s string) int {
	complaintWords := []string{"slow!", "expensive!", "manual!", "down!", "hostage!", "security!"}
	count := 0

	for _, word := range complaintWords {
		re := regexp.MustCompile("(?i)" + regexp.QuoteMeta(word))
		found := re.FindAllString(s, -1)
		count += len(found)
	}
	return count
}

func extractPoints(s string) []string {
	pointWords := []string{"COBOL", "nonobject", "monolithic", "fax", "modem", "thickclient", "tape", "floppy", "oldschoolIT"}
	points := []string{}

	for _, word := range pointWords {
		re := regexp.MustCompile("(?i)" + regexp.QuoteMeta(word))
		found := re.FindAllString(s, -1)
		for _, f := range found {
			points = append(points, strings.ToLower(f))
		}
	}
	return points
}

func calculatePoints(points []string) int {
	total := 0

	for _, i := range points {
		if len(i) > 0 {
			if strings.HasPrefix(i, "fa") || strings.HasPrefix(i, "mo") {
				total += 50
			} else if strings.HasPrefix(i, "no") {
				total += 500
			} else if i[0] == 'c' {
				total += 1000
			} else {
				total += 100
			}
		}
	}
	return total
}

