func gcd(a, b int64) int64 {
    if b == 0 {
        return a
    }
    return gcd(b, a%b)
}

func lcm(a, b int64) int64 {
    return (a * b) / gcd(a, b)
}

func pow(a, b int64) int64 {
    result := int64(1)
    for b > 0 {
        if b&1 == 1 {
            result = (result * a)
        }
        a = (a * a)
        b >>= 1
    }
    return result
}

