	for Cx := 0; Cx <= 100; Cx++ {
		for Cy := 0; Cy <= 100; Cy++ {
			H := XYH[0][2] + abs(XYH[0][0]-Cx) + abs(XYH[0][1]-Cy)
			cnt := 0
			for _, coords := range XYH {
				X := coords[0]
				Y := coords[1]
				h := coords[2]
				tmp := H - abs(X-Cx) - abs(Y-Cy)
				if h == max(tmp, 0) {
					cnt++
				}
			}
			if cnt == N {
				fmt.Println(Cx, Cy, H)
				return
			}
		}
	}
}

