	"os"
)

func main() {
	reader := bufio.NewReader(os.Stdin)
	var N, X, M int
	fmt.Fscan(reader, &N, &X, &M)

	preLoopSum := 0
	allLoopSum := 0
	incompleteLoopSum := 0
	loopFlag := false
	L := make([]int, 0)
	L = append(L, X % M)
	S := make(map[int]bool)

	for i := 1; i < N; i++ {
		X = pow(X, 2, M)
		if S[X] {
			loopFlag = true
			break
		} else {
			L = append(L, X)
			S[X] = true
		}
	}

	index := findIndex(L, X)
	lenL := len(L)

	if loopFlag {
		preLoopSum = sum(L[:index])
		loopSum := sum(L[index:lenL])
		loopLen := lenL - index
		loopCount := (N - index) / loopLen
		allLoopSum = loopCount * loopSum
		incompleteLoopLen := (N - index) % loopLen
		incompleteLoopSum = sum(L[index:index + incompleteLoopLen])
	} else {
		preLoopSum = sum(L)
	}

	ans := preLoopSum + allLoopSum + incompleteLoopSum
	fmt.Println(ans)
}

func pow(base, exp, mod int) int {
	if exp == 0 {
		return 1
	}
	base = base % mod
	result := 1
	for exp > 0 {
		if exp % 2 == 1 {
			result = (result * base) % mod
		}
		base = (base * base) % mod
		exp = exp / 2
	}
	return result
}

func findIndex(L []int, value int) int {
	for i, v := range L {
		if v == value {
			return i
		}
	}
	return -1 // Should not reach here if inputs are valid
}

func sum(slice []int) int {
	total := 0
	for _, v := range slice {
		total += v
	}
	return total
}

