func postOrder(node *TreeNode) []int {
	stck1 := make([]*TreeNode, 0)
	stck2 := make([]*TreeNode, 0)

	stck1 = append(stck1, node)

	for len(stck1) > 0 {
		popped := stck1[len(stck1)-1]
		stck1 = stck1[:len(stck1)-1]
		if popped != nil {
			stck2 = append(stck2, popped)
			stck1 = append(stck1, popped.left)
			stck1 = append(stck1, popped.right)
		}
	}

	res := make([]int, 0)

	for len(stck2) > 0 {
		popped := stck2[len(stck2)-1]
		stck2 = stck2[:len(stck2)-1]
		res = append(res, popped.data)
	}

	return res
}

