type Solution struct {}

func (s *Solution) findDiff(a []int, n int) int {
	d := make(map[int]int)
	if len(a) <= 1 {
		return 0
	}

	for _, i := range a {
		if _, ok := d[i]; !ok {
			d[i] = 1
		} else {
			d[i] += 1
		}
	}

	maxi := -1 << 63 // This works like -sys.maxsize
	mini := 1 << 63 - 1 // This works like sys.maxsize

	for _, value := range d {
		if value > maxi {
			maxi = value
		}
		if value < mini {
			mini = value
		}
	}

	if maxi > mini {
		return maxi - mini
	} else {
		return mini - maxi
	}
}

