func isvalid(x, y int, vis [][]int, n, m int) bool {
	if x < 0 || x >= n || y < 0 || y >= m {
		return false
	}
	if vis[x][y] == 0 {
		return true
	}
	return false
}

func checkcycle(x, y int, vis [][]int, n, m int, grid [][]rune) bool {
	dx := []int{0, 1, 0, -1}
	dy := []int{-1, 0, 1, 0}
	s := [][]int{{x, y}}
	pr := grid[x][y]
	parent := make([][][]int, n)
	for i := range parent {
		parent[i] = make([][]int, m)
		for j := range parent[i] {
			parent[i][j] = []int{-1, -1}
		}
	}

	for len(s) > 0 {
		u := s[len(s)-1]
		if vis[u[0]][u[1]] == 0 {
			vis[u[0]][u[1]] = 1
			check := 0
			checktwo := 0
			for i := 0; i < 4; i++ {
				newX := u[0] + dx[i]
				newY := u[1] + dy[i]
				if isvalid(newX, newY, vis, n, m) && vis[newX][newY] == 0 && pr == grid[newX][newY] {
					s = append(s, []int{newX, newY})
					check = 1
					parent[newX][newY] = []int{u[0], u[1]}
				}
				if x == newX && y == newY && parent[u[0]][u[1]][0] != x && parent[u[0]][u[1]][1] != y {
					checktwo = 1
				}
			}
			if check == 0 && checktwo == 1 {
				return true
			}
		} else {
			s = s[:len(s)-1]
		}
	}
	return false
}

func main() {
