	grid := make([][]rune, n)
	for i := 0; i < n; i++ {
		s := input()
		grid[i] = []rune(s)
	}

	f := 0
	for i := 0; i < n; i++ {
		for j := 0; j < m; j++ {
			vis := make([][]int, n)
			for k := range vis {
				vis[k] = make([]int, m)
			}
			ans := checkcycle(i, j, vis, n, m, grid)
			if ans {
				f = 1
				break
			}
		}
		if f == 1 {
			break
		}
	}
	if f == 1 {
		fmt.Println("Yes")
	} else {
		fmt.Println("No")
	}
}

