func productExceptSelf(nums []int, n int) []int {
	if n == 1 {
		return []int{1}
	}
	res := make([]int, 0)
	l := make([]int, 0)
	r := make([]int, n)
	tmp := 1

	for _, i := range nums {
		tmp = tmp * i
		l = append(l, tmp)
	}
	tmp = 1

	for i := n - 1; i >= 0; i-- {
		tmp *= nums[i]
		r[i] = tmp
	}

	res = append(res, r[1])
	for i := 1; i < n; i++ {
		if i == n - 1 {
			res = append(res, l[i - 1])
		} else {
			product := l[i - 1] * r[i + 1]
			res = append(res, product)
		}
	}
	return res
}

