	}
}

// Function to check if '0' is in the number
func containsZero(n int) bool {
	strN := strconv.Itoa(n)
	for _, ch := range strN {
		if ch == '0' {
			return true
		}
	}
	return false
}

// Function to get minimum and maximum digit from n
func getMinMaxDigits(n int) (int, int) {
	strN := strconv.Itoa(n)
	minDigit := 9
	maxDigit := 0

	for _, ch := range strN {
		digit := int(ch - '0')
		if digit < minDigit {
			minDigit = digit
		}
		if digit > maxDigit {
			maxDigit = digit
		}
	}
	return minDigit, maxDigit
}

