func solve(X int, Y int, S string) int {
	check_1 := "pr"
	check_2 := "rp"
	if Y > X {
		tmp := X
		X = Y
		Y = tmp
		tmp2 := check_2
		check_2 = check_1
		check_1 = tmp2
	}
	count := 0
	stack := []byte{}

	for i := 0; i < len(S); i++ {
		ch := S[i]
		if len(stack) == 0 || stack[len(stack)-1] + ch != check_1 {
			stack = append(stack, ch)
		} else {
			stack = stack[:len(stack)-1]
			count += X
		}
	}

	S = string(stack) 
	stack = []byte{}

	for i := 0; i < len(S); i++ {
		ch := S[i]
		if len(stack) == 0 || stack[len(stack)-1] + ch != check_2 {
			stack = append(stack, ch)
		} else {
			stack = stack[:len(stack)-1]
			count += Y
		}
	}

	return count
}

