func doWork1(H int, n int, arr []int) int {
	sm := 0
	gap := 0
	h := H

	for i, e := range arr {
		sm -= e
		h += e
		if h <= 0 {
			return i + 1
		}
		gap = max(gap, sm)
	}

	if sm <= 0 {
		return -1
	}

	whole := (H - gap) / sm
	H -= whole * sm
	res := whole * n

	i := 0
	for H > 0 {
		H += arr[i % n]
		res += 1
		if H <= 0 {
			return res
		}
		i += 1
	}
	return res
