)

var m [][]int

func superEggDrop(K int, N int) int {
	m = make([][]int, K + 1)
	for i := 0; i <= K; i++ {
		m[i] = make([]int, N + 1)
	}

	return find(K, N)
}

func find(k int, n int) int {
	if k == 1 {
		return n
	}
	if n == 0 {
		return 0
	}
	if m[k][n] > 0 {
		return m[k][n]
	}

	st, end := 1, n
	st, end = bsearch(k, n, st, end)

	v_st := math.MaxInt32
	if st <= N {
		v_st = max(find(k - 1, st - 1), find(k, n - st))
	}
	v_end := math.MaxInt32
	if end >= 1 {
		v_end = max(find(k - 1, end - 1), find(k, n - end))
	}
	m[k][n] = min(v_st, v_end) + 1
	return m[k][n]
}

func bsearch(k int, n int, st int, end int) (int, int) {
	for st <= end {
		mid := (st + end) / 2
		if predicate(mid, k, n) {
			end = mid - 1
		} else {
			st = mid + 1
		}
	}
	return st, end
}

func predicate(x int, k int, n int) bool {
	return find(k - 1, x - 1) >= find(k, n - x)
}

func min(a int, b int) int {
	if a < b {
		return a
	}
	return b
}

func max(a int, b int) int {
	if a > b {
		return a
	}
	return b
}

func main() {
	scanner := bufio.NewReader(os.Stdin)
	var K, N int
	fmt.Fscan(scanner, &K, &N)
	result := superEggDrop(K, N)
	fmt.Println(result)
}

