func minJumps(arr []int, n int) int {
	if n == 0 {
		return -1
	}
	if n == 1 {
		return 0
	}

	curr_jumps := arr[0]
	next_jumps := 0
	res := 0

	for i := 1; i < n-1; i++ {
		curr_jumps -= 1
		next_jumps = max(next_jumps-1, arr[i])

		if curr_jumps == 0 {
			curr_jumps = next_jumps
			res += 1
		}

		if curr_jumps <= 0 {
			return -1
		}
	}

	if curr_jumps >= 1 {
		res += 1
	}

	return res
}

