type Queue struct {
	s1 []int
	s2 []int
}

func NewQueue() *Queue {
	return &Queue{s1: []int{}, s2: []int{}}
}

func (q *Queue) enqueue(X int) {
	// Move elements to s2
	for len(q.s1) != 0 {
		tmp := q.s1[len(q.s1)-1]
		q.s2 = append(q.s2, tmp)
		q.s1 = q.s1[:len(q.s1)-1]
	}
	// Add new element
	q.s1 = append(q.s1, X)
	// Move back to s1
	for len(q.s2) != 0 {
		tmp2 := q.s2[len(q.s2)-1]
		q.s1 = append(q.s1, tmp2)
		q.s2 = q.s2[:len(q.s2)-1]
	}
}

func (q *Queue) dequeue() int {
	if len(q.s1) == 0 {
		fmt.Println("Q is Empty")
		return -1 // using -1 as a flag for empty
	}
	x := q.s1[len(q.s1)-1]
	q.s1 = q.s1[:len(q.s1)-1]
	return x
}

func main() {
	reader := bufio.NewReader(os.Stdin)
	q := NewQueue()

	fmt.Println("Enter commands: enqueue <number> or dequeue")

	for {
		var cmd string
		var num int
		_, err := fmt.Fscan(reader, &cmd)
		if err != nil {
			fmt.Println("Error reading command, exiting.")
			break
		}

		if cmd == "enqueue" {
			_, err := fmt.Fscan(reader, &num)
			if err != nil {
				fmt.Println("Error reading number.")
				continue
			}
			q.enqueue(num)
			fmt.Printf("Enqueued: %d\n", num)
		} else if cmd == "dequeue" {
			val := q.dequeue()
			if val != -1 {
				fmt.Printf("Dequeued: %d\n", val)
			}
		} else {
			fmt.Println("Unknown command.")
		}
	}
}

