func maxMoves(arr []int, total int) int {
	half := total / 2
	curr := 0
	if total == 0 {
		return len(arr) - 1
	} else if total % 2 == 1 {
		return 0
	}
	for i := 0; i < len(arr); i++ {
		if curr == half {
			left := arr[:i]
			right := arr[i:]
			moveLeft := maxMoves(left, half)
			moveRight := maxMoves(right, half)
			return max(moveLeft, moveRight) + 1
		} else if curr > half {
			break
		}
		curr = curr + arr[i]
	}
	return 0
}

