func eval_object(a string, operation string, b string) float64 {
	aFloat := convertToFloat64(a)
	bFloat := convertToFloat64(b)
	result := doOperation(aFloat, operation, bFloat)
	return result
}

func convertToFloat64(numStr string) float64 {
	numFloat, err := strconv.ParseFloat(numStr, 64)
	if err != nil {
		fmt.Println("Error converting number:", err)
		return 0
	}
	return numFloat
}

func doOperation(x float64, op string, y float64) float64 {
	var res float64
	switch op {
	case "+":
		res = add(x, y)
	case "-":
		res = subtract(x, y)
	case "*":
		res = multiply(x, y)
	case "/":
		if y != 0 {
			res = divide(x, y)
		} else {
			fmt.Println("Error: Division by zero")
			return 0
		}
	default:
		fmt.Println("Invalid operation")
	}
	return res
}

func add(x float64, y float64) float64 {
	return x + y
}

func subtract(x float64, y float64) float64 {
	return x - y
}

func multiply(x float64, y float64) float64 {
	return x * y
}

func divide(x float64, y float64) float64 {
	return x / y
}

