func main() {
	reader := bufio.NewReader(os.Stdin)
	var sX, sY, eX, eY int
	fmt.Fscan(reader, &sX, &sY, &eX, &eY)
	var N int
	fmt.Fscan(reader, &N)
	circles := make([](struct {
		x, y, r int
	}), 0, N+2)
	circles = append(circles, struct{x, y, r int}{sX, sY, 0})

	for i := 0; i < N; i++ {
		var x, y, r int
		fmt.Fscan(reader, &x, &y, &r)
		circles = append(circles, struct{x, y, r int}{x, y, r})
	}
	circles = append(circles, struct{x, y, r int}{eX, eY, 0})

	edges := make([][]float64, N+2)
	for i := range edges {
		edges[i] = make([]float64, N+2)
		for j := range edges[i] {
			edges[i][j] = math.Inf(1)
		}
	}

	for i, c1 := range circles {
		for j, c2 := range circles {
			distance := calculateDistance(c1, c2)
			edges[i][j] = distance
		}
	}

	minDist := make([]float64, N+2)
	for i := range minDist {
		minDist[i] = math.Inf(1)
	}
	confilm := make([]bool, N+2)
	minDist[0] = 0

	for i := 0; i < N+2; i++ {
		minNode := findMinNode(minDist, confilm)
		confilm[minNode] = true

		updateDistances(minNode, edges, minDist)
	}

	fmt.Println(minDist[N+1])
}

func calculateDistance(c1, c2 struct{x, y, r int}) float64 {
	dx := float64(c1.x - c2.x)
	dy := float64(c1.y - c2.y)
	rSum := float64(c1.r + c2.r)
	d := math.Max(0, math.Sqrt(dx*dx + dy*dy) - rSum)
	return d
}

func findMinNode(minDist []float64, confilm []bool) int {
	minNode := -1
	minValue := math.Inf(1)
	for to := 0; to < len(minDist); to++ {
		if !confilm[to] && minDist[to] < minValue {
			minValue = minDist[to]
			minNode = to
		}
	}
	return minNode
}

func updateDistances(minNode int, edges [][]float64, minDist []float64) {
	for to := 0; to < len(minDist); to++ {
		newDist := minDist[minNode] + edges[minNode][to]
		if newDist < minDist[to] {
			minDist[to] = newDist
		}
	}
}

