type ListNode struct {
	val  int
	next *ListNode
}

type Solution struct{}

func (s *Solution) mergeNodes(head *ListNode) *ListNode {
	tmp := []int{}
	p := head
	for p != nil {
		tmp = append(tmp, p.val)
		p = p.next
	}

	res := []int{}
	tot := 0
	for i := 1; i < len(tmp); i++ {
		tot += tmp[i]
		if tmp[i] == 0 {
			res = append(res, tot)
			tot = 0
		}
	}

	dummy := &ListNode{val: 0}
	p2 := dummy
	for j := 0; j < len(res); j++ {
		node := &ListNode{val: res[j]}
		p2.next = node
		p2 = p2.next
	}
	return dummy.next
}

