	var tail *ListNode

	for i := 0; i < n; i++ {
		val := 0
		fmt.Fscan(reader, &val)
		node := &ListNode{val: val}
		if head == nil {
			head = node
			tail = node
		} else {
			tail.next = node
			tail = tail.next
		}
	}

	s := &Solution{}
	result := s.mergeNodes(head)

	cur := result
	for cur != nil {
		if cur.next != nil {
			fmt.Print(cur.val, " -> ")
		} else {
			fmt.Print(cur.val)
		}
		cur = cur.next
	}
	fmt.Println()
}

