const MOD = 1e9 + 7
const NN = 1e7 + 10

var fact []int64

func gcd(a int64, b int64) int64 {
    if b == 0 {
        return a
    }
    return gcd(b, a%b)
}

func mod_mul(a int64, b int64) int64 {
    a = a % MOD
    b = b % MOD
    return ((a * b) % MOD + MOD) % MOD
}

func mod_inv(i int64) int64 {
    if i == 1 {
        return 1
    }
    return (MOD - ((MOD / i) * mod_inv(MOD % i)) % MOD) % MOD
}

func calFact() {
    fact = make([]int64, NN)
    fact[0] = 1
    fact[1] = 1
    for i := int64(2); i < NN; i++ {
        fact[i] = mod_mul(fact[i-1], i)
    }
}

func ncr(n int64, r int64) int64 {
    ans := fact[n]
    ans = mod_mul(ans, mod_inv(fact[n-r]))
    ans = mod_mul(ans, mod_inv(fact[r]))
    return ans
}

func f1(a int64, b int64, c int64) int64 {
    a++
    b++
    c++
    fmt.Printf("? %d %d %d\n", a, b, c)
    os.Stdout.Sync()
    var x int64
    fmt.Scan(&x)
    return x
}

func f1_array(a []int64) int64 {
    return f1(a[0], a[1], a[2])
}

func solve3(a []int64, val int64, zero int64, one int64) []int64 {
    res := make([]int64, 3)
    if val == 1 {
        vl := f1(zero, a[0], a[1])
        if vl == 0 {
            res[2] = 1
            res[1] = f1(zero, one, a[1])
            res[0] = 1 - res[1]
        } else {
            res[0] = 1
            res[1] = 1
            res[2] = f1(zero, one, a[2])
        }
    } else {
        vl := f1(one, a[0], a[1])
        if vl == 1 {
            res[2] = 0
            res[1] = f1(zero, one, a[1])
            res[0] = 1 - res[1]
        } else {
            res[0] = 0
            res[1] = 0
            res[2] = f1(zero, one, a[2])
        }
    }
    return res
}

func get_zeone(a []int64, b []int64) (int64, int64) {
    if f1(a[1], a[2], b[0]) != 0 {
        return a[0], b[0]
    }
    if f1(a[2], b[0], b[1]) != 0 {
        return a[1], b[1]
    }
    return a[2], b[2]
}

func solve() {
    var n int64
    fmt.Scan(&n)
    nums := make([][]int64, n/3)
    val := make([]int64, n/3)
    resik := make([][]int64, n/3)

    for i := range nums {
        nums[i] = make([]int64, 0)
        for j := int64(0); j < 3; j++ {
            nums[i] = append(nums[i], i*3+j)
        }
    }

    fz, fo := int64(-1), int64(-1)

    for i := int64(0); i < n/3; i++ {
        val[i] = f1_array(nums[i])
        if val[i] == 0 {
            fz = i
        } else {
            fo = i
        }
    }

    zero, one := get_zeone(nums[fz], nums[fo])
    resik[one/3] = append(resik[one/3], 1)

    for i := int64(0); i < n/3; i++ {
        if i == fz || i == fo {
            for j := int64(0); j < 3; j++ {
                pos := i*3 + j
                if pos != zero && pos != one {
                    resik[i] = append(resik[i], f1(zero, one, pos))
                }
            }
        } else {
            resik[i] = solve3(nums[i], val[i], zero, one)
        }
    }

    res := make([]int64, 0)
    for i := int64(0); i < n/3; i++ {
        for j := int64(0); j < 3; j++ {
            if resik[i][j] == 0 {
                res = append(res, i*3+j+1)
            }
        }
    }

    fmt.Print("! ", len(res), " ")
    for _, val := range res {
        fmt.Print(val, " ")
    }
    fmt.Println()
}

func main() {
    reader := bufio.NewReader(os.Stdin)
    var t int64
    fmt.Fscan(reader, &t)
    calFact()
    for t > 0 {
        solve()
        t--
    }
}

