func abs(x int) int {
	if x < 0 {
		return -x
	}
	return x
}

func calcTide(d int) int {
	if d % 2 == 0 {
		return 2 * tri(d / 2)
	} else {
		t1 := tri((d - 1) / 2) 
		t2 := tri((d + 1) / 2) 
		return t1 + t2
	}
}

func tri(n int) int {
	return n * (n + 1) / 2 
}

