func rep_and_adj(rem_list []int, to_fit int, ans int, tables []int) int {
	if len(rem_list) == 0 {
		for _, each := range tables {
			if each != to_fit {
				pos := indexOf(tables, each)
				tables[pos] = to_fit
				ans = ans + 1
				return ans
			}
		}
	} else {
		flag := false
		for _, each := range tables {
			if each != -1 && !isInSlice(each, rem_list) {
				pos := indexOf(tables, each)
				tables[pos] = to_fit
				ans = ans + 1
				flag = true
				break
			}
		}
		if flag == false {
			rem_list2 := []int{}
			for _, e := range rem_list {
				if isInSlice(e, tables) {
					rem_list2 = append(rem_list2, e)
				}
			}
			if len(rem_list2) > 0 {
				dist := []int{}
				to_replace := -1
				for _, each := range rem_list2 {
					if !isInSlice(each, dist) && len(dist) == len(tables)-1 {
						to_replace = each
						break
					} else if !isInSlice(each, dist) {
						dist = append(dist, each)
					}
				}
				for n, z := range tables {
					if z == to_replace {
						tables[n] = to_fit
						ans = ans + 1
						break
					}
				}
			}
		}
	}
	return ans
}

func isInSlice(val int, slice []int) bool {
	for _, s := range slice {
		if s == val {
			return true
		}
	}
	return false
}

func indexOf(slice []int, value int) int {
	for i, v := range slice {
		if v == value {
			return i
		}
	}
	return -1
}

