		t--
		var n int
		fmt.Fscan(reader, &n)
		l := make([]int, n)
		for i := 0; i < n; i++ {
			fmt.Fscan(reader, &l[i])
		}
		u := uniqueAndSort(l)
		d := make(map[int][]int)
		// Filling the dictionary
		for _, val := range u {
			d[val] = []int{}
		}
		for i := 0; i < n; i++ {
			d[l[i]] = append(d[l[i]], i)
		}
		f := d[u[0]][0]
		p := 1
		m := 1
		for p < len(u) {
			if d[u[p]][len(d[u[p]]) - 1] > f {
				for j := 0; j < len(d[u[p]]); j++ {
					if d[u[p]][j] > f {
						f = d[u[p]][j]
						p += 1
						break
					}
				}
			} else {
				m += 1
				f = d[u[p]][0]
				p += 1
			}
		}
		fmt.Println(m)
	}
}

func uniqueAndSort(arr []int) []int {
	uniqueMap := make(map[int]struct{})
	for _, val := range arr {
		uniqueMap[val] = struct{}{}
	}
	uniques := make([]int, 0, len(uniqueMap))
	for key := range uniqueMap {
		uniques = append(uniques, key)
	}
	sort.Ints(uniques)
	return uniques
}

