type Node struct {
	data  int
	left  *Node
	right *Node
}

func postOrder(root *Node) []int {
	if root == nil {
		return []int{}
	}
	nodes := []int{}
	nodes2 := postOrder(root.left)
	nodes3 := postOrder(root.right)

	for _, v := range nodes2 {
		nodes = append(nodes, v)
	}
	for _, v := range nodes3 {
		nodes = append(nodes, v)
	}
	nodes = append(nodes, root.data)
	return nodes
}

func createNode(data int) *Node {
	return &Node{data: data, left: nil, right: nil}
}

func main() {
	reader := bufio.NewReader(os.Stdin)
	fmt.Print("Enter number of nodes: ")
	var n int
	fmt.Fscan(reader, &n)

	var root *Node = nil
	for i := 0; i < n; i++ {
		fmt.Print("Enter node value: ")
		var tmp int
		fmt.Fscan(reader, &tmp)
		root = insertNode(root, tmp)
	}

	fmt.Println("Post Order Traversal:", postOrder(root))
}

func insertNode(root *Node, data int) *Node {
	if root == nil {
		return createNode(data)
	}
	if data < root.data {
		root.left = insertNode(root.left, data)
	} else {
		root.right = insertNode(root.right, data)
	}
	return root
}

