	for i := 0; i < t; i++ {
		solve(reader)
	}
}

func solve(reader *bufio.Reader) {
	var n int
	fmt.Fscan(reader, &n)
	v := make([]int, 0)

	for i := 0; i < n; i++ {
		var c int
		fmt.Fscan(reader, &c)

		if c == 1 {
			v = append(v, c)
		} else {
			// Unroll the pop operation
			for len(v) > 0 && v[len(v)-1] != c-1 {
				v = v[:len(v)-1]
			}
			if len(v) > 0 {
				v[len(v)-1] = c
			}
		}

		printVector(v)
	}
}

func printVector(v []int) {
	for i := 0; i < len(v); i++ {
		fmt.Print(v[i])
		if i != len(v)-1 {
			fmt.Print(".")
		}
	}
	fmt.Println()
}

