func minimizeMax(r []int, m int) int {
	if m == 0 {
		return 0
	}
	n := len(r)
	sort.Ints(r)

	return bs(-1, 1e9, func(a int64) bool {
		s := 0
		for i := 0; i < n-1; i++ {
			if int64(r[i])+a >= int64(r[i+1]) {
				s++
				i++
			}
		}
		return s >= m
	})
}

func bs(a, c int64, cmp func(int64) bool) int64 {
	if cmp(a) {
		for a+1 < c {
			b := (a + c) >> 1
			if cmp(b) {
				a = b
			} else {
				c = b
			}
		}
		return a
	}
	for a+1 < c {
		b := (a + c) >> 1
		if cmp(b) {
			c = b
		} else {
			a = b
		}
	}
	return c
}

