	fmt.Fscan(reader, &N, &A, &B)

	if A + B - 1 > N || A * B < N {
		fmt.Println(-1)
		return
	}

	ans := make([]int, 0)
	for i := B; i >= 1; i-- {
		ans = append(ans, i)
	}

	if A > 1 {
		x := (N - B) / (A - 1)
		y := (N - B) % (A - 1)
		st := B + 1

		for i := 0; i < y; i++ {
			tmp := make([]int, 0)
			for j := st; j <= st + x; j++ {
				tmp = append(tmp, j)
			}
			for j := len(tmp) - 1; j >= 0; j-- {
				ans = append(ans, tmp[j])
			}
			st += x + 1
		}

		for i := 0; i < A - 1 - y; i++ {
			tmp2 := make([]int, 0)
			for j := st; j < st + x; j++ {
				tmp2 = append(tmp2, j)
			}
			for j := len(tmp2) - 1; j >= 0; j-- {
				ans = append(ans, tmp2[j])
			}
			st += x
		}
	}

	for i, v := range ans {
