func main() {
	reader := bufio.NewReader(os.Stdin)
	var n int
	fmt.Fscan(reader, &n)

	line1, _ := reader.ReadString('\n')
	line1 = strings.TrimSpace(line1)
	aStrs := strings.Split(line1, " ")
	a := make([]int, n-1)
	for i := 1; i < n; i++ {
		a[i-1], _ = strconv.Atoi(aStrs[i])
	}

	line2, _ := reader.ReadString('\n')
	line2 = strings.TrimSpace(line2)
	bStrs := strings.Split(line2, " ")
	b := make([]int, n-1)
	for i := 1; i < n; i++ {
		b[i-1], _ = strconv.Atoi(bStrs[i])
	}

	dict := make(map[string]struct{})
	moves := 0

	for {
		if len(a) == 0 || len(b) == 0 || checkInDict(a, b, dict) {
			break
		}

		addToDict(a, b, dict)

		winner := []int{}
		looser := []int{}

		if a[0] > b[0] {
			winner = append(winner, a...)
			looser = b
		} else {
			winner = append(winner, b...)
			looser = a
		}

		winner = append(winner, looser[0])
		winner = append(winner, winner[0])

		a = winner[1:] // Remove the old first
		b = looser[1:] // Remove the old first
		moves += 1
	}

	if len(a) == 0 {
		fmt.Printf("%d 2\n", moves)
	} else if len(b) == 0 {
		fmt.Printf("%d 1\n", moves)
	} else {
		fmt.Println("-1")
	}
}

func checkInDict(a []int, b []int, dict map[string]struct{}) bool {
	key := makeKey(a, b)
	_, exists := dict[key]
	return exists
}

func addToDict(a []int, b []int, dict map[string]struct{}) {
	key := makeKey(a, b)
	dict[key] = struct{}{}
}

func makeKey(a []int, b []int) string {
	aStr := convertSliceToString(a)
	bStr := convertSliceToString(b)
	return aStr + "." + bStr
}

func convertSliceToString(s []int) string {
	res := ""
	for _, v := range s {
		res += strconv.Itoa(v)
	}
	return res
}

