func readInt(reader *bufio.Reader) int {
	var tmp int
	fmt.Fscan(reader, &tmp) // Using Fscan to read an integer
	return tmp
}

func readInts(reader *bufio.Reader) []int {
	line, _ := reader.ReadString('\n') // Read line and ignore error
	splitLine := strings.Fields(line) // Split by whitespace
	res := make([]int, len(splitLine)) // Create result slice
	for i := 0; i < len(splitLine); i++ {
		res[i] = toInt(splitLine[i]) // Convert to int
	}
	return res
}

func readStrings(reader *bufio.Reader) []string {
	line, _ := reader.ReadString('\n') // Read line and ignore error
	return strings.Fields(line) // Return split line
}

func toInt(s string) int {
	i, _ := strconv.Atoi(s) // Converting string to int, ignoring error
	return i
}

func parseInts(arr []string) (int, int, int) {
	j := toInt(arr[0]) // Convert j
	t := toInt(arr[1]) // Convert t
	s := toInt(arr[2]) // Convert s
	return j, t, s
}

func countInRange(x []int, j int, t int, s int) int {
	count := 0
	for _, p := range x[j:t] { // Iterate over the range
		if p == s { // Check if equal to s
			count++ // Increment count
		}
	}
	return count // Return the final count
}

