var par []int

func find(x int) int {
	if par[x] < 0 {
		return x
	} else {
		tmp := par[x]
		par[x] = find(tmp)
		return par[x]
	}
}

func unite(x int, y int) bool {
	xx := find(x)
	yy := find(y)
	if xx == yy {
		return false
	} else {
		if par[xx] > par[yy] {
			tmp := xx
			xx = yy
			yy = tmp
		}
		par[xx] += par[yy]
		par[yy] = xx
		return true
	}
}

func same(x int, y int) bool {
	return find(x) == find(y)
}

func size(x int) int {
	return -par[find(x)]
}

