func main() {
	reader := bufio.NewReader(os.Stdin)
	writer := bufio.NewWriter(os.Stdout)
	defer writer.Flush()
	in := NewInputReader(reader)

	task := &Task{}
	task.solve(in, writer)
}

type Task struct {
	dirs [][]int
}

func NewTask() *Task {
	return &Task{
		dirs: [][]int{{0, 1}, {0, -1}, {1, 0}, {-1, 0}},
	}
}

func (t *Task) solve(in *InputReader, out *bufio.Writer) {
	n := in.nextInt()
	m := in.nextInt()
	times := in.nextInt()
	grid := make([][]int, n)
	isgood := make([][]bool, n)
	minDist := make([][]int, n)
	mark := make([][]bool, n)

	for i := 0; i < n; i++ {
		grid[i] = make([]int, m)
		isgood[i] = make([]bool, m)
		minDist[i] = make([]int, m)
		mark[i] = make([]bool, m)
		line := in.nextToken()
		for j := 0; j < m; j++ {
			grid[i][j] = int(line[j] - '0')
		}
	}

	isBad := true

	for i := 0; i < n; i++ {
		for j := 0; j < m; j++ {
			for _, dir := range t.dirs {
				new_i := i + dir[0]
				new_j := j + dir[1]
				if new_i >= 0 && new_j >= 0 && new_i < n && new_j < m {
					if grid[i][j] == grid[new_i][new_j] {
						isgood[i][j] = true
						isBad = false
						break
					}
				}
			}
		}
	}

	if !isBad {
		t.dfs(isgood, minDist, mark)
	}

	for time := 0; time < times; time++ {
		i := in.nextInt() - 1
		j := in.nextInt() - 1
		p := in.nextLong()

		if isBad {
			out.WriteString(fmt.Sprintf("%d\n", grid[i][j]))
		} else if p <= int64(minDist[i][j]) {
			out.WriteString(fmt.Sprintf("%d\n", grid[i][j]))
		} else {
			if p%2 == int64(minDist[i][j])%2 {
				out.WriteString(fmt.Sprintf("%d\n", grid[i][j]))
			} else {
				out.WriteString(fmt.Sprintf("%d\n", 1^grid[i][j]))
			}
		}
	}
}

func (t *Task) dfs(isgood [][]bool, minDist [][]int, mark [][]bool) {
	n := len(isgood)
	m := len(isgood[0])
	queue := make([]Pair, 0)

	for i := 0; i < n; i++ {
		for j := 0; j < m; j++ {
			if isgood[i][j] {
				minDist[i][j] = 0
				mark[i][j] = true
				queue = append(queue, NewPair(i, j))
			}
		}
	}

	for len(queue) > 0 {
		top := queue[0]
		queue = queue[1:]
		x, y := top.x, top.y

		for _, dir := range t.dirs {
			new_x := x + dir[0]
			new_y := y + dir[1]
			if new_x >= 0 && new_y >= 0 && new_x < n && new_y < m && !mark[new_x][new_y] {
				minDist[new_x][new_y] = minDist[x][y] + 1
				mark[new_x][new_y] = true
				queue = append(queue, NewPair(new_x, new_y))
			}
		}
	}
}

type Pair struct {
	x, y int
}

func NewPair(x, y int) Pair {
	return Pair{x, y}
}

type InputReader struct {
	br *bufio.Reader
}

func NewInputReader(br *bufio.Reader) *InputReader {
	return &InputReader{br: br}
}

func (in *InputReader) nextToken() string {
	res, _ := in.br.ReadString('\n')
	return res
}

func (in *InputReader) nextInt() int {
	val, _ := strconv.Atoi(in.nextToken())
	return val
}

func (in *InputReader) nextLong() int64 {
	val, _ := strconv.ParseInt(in.nextToken(), 10, 64)
	return val
}

