	}

	c := make([]int, n+1)

	for i := 1; i <= n; i++ {
		c[i] = 10e9
	}

	for i := n; i > 0; i-- {
		if i + b[i] <= n {
			c[i] = max(0, i + b[i] - a[i + b[i]])
		} else {
			c[i] = max(0, i)
		}
	}

	mn := make([]int, n+2)
	rs := make([]int, n+1)

	for i := range mn {
		mn[i] = 10e9
	}

	for i := n; i >= 1; i-- {
		if min(i, c[i]) < mn[i+1] {
			mn[i] = min(i, c[i])
			rs[i] = i
		} else {
			mn[i] = mn[i+1]
			rs[i] = rs[i+1]
		}
	}

	hi := n
	ans := []int{}

	i := 1
	for i <= n && hi > 0 {
		ans = append(ans, rs[hi])
		if mn[hi] >= hi {
			break
		}
