	for i := 0; i < n; i++ {
		fmt.Fscan(reader, &a[i])
	}

	// Call our max_sum function
	result := max_sum(a, n)
	fmt.Println(result)
}

func max_sum(a []int, n int) int {
	sum1 := 0
	csum1 := 0

	// First pass to calculate initial sums
	for i := 0; i < n; i++ {
		sum1 += a[i]
		csum1 += i * a[i]
	}

	// Start with the initial M
	M := csum1

	// Second pass to find max
	for j := 1; j < n; j++ {
		csum1 = doWork1(csum1, sum1, n, a, j)
		if csum1 > M {
			M = csum1
		}
	}
	return M
}

func doWork1(csum1, sum1, n int, a []int, j int) int {
	tmp := n * a[n-j]
	csum1 += sum1 - tmp
	return csum1
}

