var (
	vertices   int
	distance   []float64
	queue      = make([]int, 0)
	initAdjTable [][]map[int]float64
)

func generateAdjTable(vTable [][]string) [][]map[int]float64 {
	tmpAdjTable := make([][]map[int]float64, vertices)
	for i := range tmpAdjTable {
		tmpAdjTable[i] = make(map[int]float64)
	}
	for _, each := range vTable {
		vFrom, _ := strconv.Atoi(each[0])
		vTo, _ := strconv.Atoi(each[1])
		edgeWeight, _ := strconv.ParseFloat(each[2], 64)
		tmpAdjTable[vFrom][vTo] = edgeWeight
		tmpAdjTable[vTo][vFrom] = edgeWeight
	}
	return tmpAdjTable
}

func graphBfs(vInit int, adjTable [][]map[int]float64) {
	for i := 0; i < vertices; i++ {
		distance[i] = math.Inf(1)
	}
	distance[vInit] = 0
	queue = append(queue, vInit)
	for len(queue) > 0 {
		current := queue[0]
		queue = queue[1:]
		adjWeight := adjTable[current]
		for adj := range adjWeight {
			if math.IsInf(distance[adj], 1) {
				distance[adj] = distance[current] + adjWeight[adj]
				queue = append(queue, adj)
			}
		}
	}
}

func solve(adjTable [][]map[int]float64, initV int) float64 {
	graphBfs(initV, adjTable)
	diameter := 0.0
	bridgeV := 0
	for v := 0; v < vertices; v++ {
		if math.IsInf(distance[v], 1) {
			continue
		}
		if diameter < distance[v] {
			diameter = distance[v]
			bridgeV = v
		}
	}
	graphBfs(bridgeV, adjTable)
	diameter = 0.0
	for v := 0; v < vertices; v++ {
		if math.IsInf(distance[v], 1) {
			continue
		}
		if diameter < distance[v] {
			diameter = distance[v]
		}
	}
	return diameter
}

func main() {
	reader := bufio.NewReader(os.Stdin)
	fmt.Fscan(reader, &vertices)
	tmpInput := make([][]string, 0)
	for {
		line, err := reader.ReadString('\n')
		if err != nil {
			break
		}
		each := make([]string, 0)
		for _, str := range line[:len(line)-1] {
			each = append(each, string(str))
		}
		tmpInput = append(tmpInput, each)
	}
	initAdjTable = generateAdjTable(tmpInput)
	distance = make([]float64, vertices)
	initV := 0
	result := solve(initAdjTable, initV)
	fmt.Println(result)
}

