func shift(a []int, l, r int) {
	carry := a[l]
	a[l] = a[r]
	for i := l + 1; i <= r; i++ {
		temp := carry
		carry = a[i]
		a[i] = temp
	}
}

func main() {
	reader := bufio.NewReader(os.Stdin)
	var t int
	fmt.Fscan(reader, &t)
	ans := make([]string, t)

	for i := 0; i < t; i++ {
		var n int
		fmt.Fscan(reader, &n)
		arr := make([]int, n)
		brr := make([]int, n)

		for j := 0; j < n; j++ {
			fmt.Fscan(reader, &arr[j])
		}
		for j := 0; j < n; j++ {
			fmt.Fscan(reader, &brr[j])
		}

		sort.Ints(arr)
		sort.Ints(brr)

		var flag bool
		if s := 1; s == 1 {
			flag = true
			dic1 := make(map[int]int)
			dic2 := make(map[int]int)

			for _, j := range brr {
				dic2[j] = 1
			}

			if brr[0] <= arr[0] {
				flag = false
			} else {
				dic1[arr[0]] = 1
				dic1[brr[0]] = 1

				for j := 1; j < n; j++ {
					if _, found := dic1[arr[j]]; found {
						if brr[j] <= arr[j] {
							flag = false
							break
						}
						dic1[brr[j]] = 1
					} else if _, found := dic2[arr[j]]; found {
						for k := j; k < n; k++ {
							if brr[k] == arr[j] {
								shift(brr, j, k)
							}
						}
						if brr[j] <= arr[j] {
							flag = false
							break
						}
						dic1[arr[j]] = 1
						dic1[brr[j]] = 1
					} else {
						flag = false
						break
					}
				}
			}
		} else {
			flag = true
			dic := make(map[int]int)

			for _, j := range arr {
				dic[j]++
			}
			for _, j := range brr {
				dic[j]++
			}

			for _, j := range dic {
				if j > n {
					flag = false
					break
				}
			}

			if flag {
				asmall, bsmall, asame, bsame := 1, 1, 1, 1
				crr := make([]int, 2*n)
				counter := 0

				for _, j := range arr {
					crr[counter] = j
					counter++
				}
				for _, j := range brr {
					crr[counter] = j
					counter++
				}

				sort.Ints(crr)

				for j := 0; j < n; j++ {
					if crr[j] != arr[j] {
						asmall = 0
						break
					}
				}

				for j := 0; j < n; j++ {
					if crr[j] != brr[j] {
						bsmall = 0
						break
					}
				}

				for _, j := range arr {
					if j != arr[0] {
						asame = 0
						break
					}
				}

				for _, j := range brr {
					if j != brr[0] {
						bsame = 0
						break
					}
				}

				if n == 2 {
					if arr[1] == brr[0] {
						flag = true
					} else if asame == 1 && asmall == 1 {
						flag = true
					} else if asmall + bsmall == 0 {
						flag = true
					} else {
						flag = false
					}
				} else if bsmall*(asame+bsame) != 0 {
					flag = false
				}
			}
		}

		if flag {
			ans[i] = "YES"
		} else {
			ans[i] = "NO"
		}
	}

	for _, result := range ans {
		fmt.Println(result)
	}
}

