func maxNonDecreasingLength(nums1 []int, nums2 []int) int {
	a := 1 
	b := 1 
	y := 1 

	for i := 1; i < len(nums1); i++ {
		var tmp1, tmp2 int
		tmp1 = 1 
		tmp2 = 1 

		if nums1[i] >= nums1[i-1] {
			tmp1 = a + 1
		}
		if nums1[i] >= nums2[i-1] {
			tmp1 = max(tmp1, b + 1)
		}
		a = tmp1

		if nums2[i] >= nums1[i-1] {
			tmp2 = a + 1
		}
		if nums2[i] >= nums2[i-1] {
			tmp2 = max(tmp2, b + 1)
		}
		b = tmp2

		y = max(y, a, b)
	}
	return y
}

func max(x int, nums ...int) int {
	maxVal := x
	for _, n := range nums {
		if n > maxVal {
			maxVal = n
		}
	}
	return maxVal
