func updateAns(ans int, s1, s2 string, i int) int {
	if s1[i] == s1[i-1] {
		// Do nothing
	} else if s1[i] == s2[i] && s1[i-1] == s2[i-1] {
		ans *= 2
	} else if s1[i] == s2[i] && s1[i-1] != s2[i-1] {
