func checkPalindrome(s string, n int) bool {
	for i := 0 ; i < n/2 ; i++ {
		if s[i] != s[n-1-i] {
			return false
		}
	}
	return true
}

func checkMirroring(s1, s2 string, n1 int) bool {
	for i := 0 ; i < n1/4 ; i++ {
		if s1[i] != s1[n1-1-i] {
			return false
		}
		if s2[i] != s1[n1-1-i] {
			return false
		}
	}
	return true
}

