typedef long long LL;

int enlarge(int* a, int b) { return (*a < b) ? (*a = b, 1) : 0; }
int minify(int* a, int b) { return (*a > b) ? (*a = b, 1) : 0; }

struct Solver {
    int L, n;
    int* a;

    void solve(int ca, FILE* reader) {
        fscanf(reader, "%d %d", &L, &n);
        a = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            fscanf(reader, "%d", &a[i]);
        }

        int rbound = search_rbound();
        int lbound = search_lbound();
        if (lbound > rbound) {
            // Handle error case, should not occur according to the logic
            return;
        }

        int* start = (int*)malloc(n * sizeof(int));
        int* end = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            int ps = (i == 0) ? 0 : start[i - 1];
            int pe = (i == 0) ? 0 : end[i - 1];

            start[i] = (ps + lbound > a[i]) ? (ps + lbound) : a[i];
            end[i] = (i + 1 < n) ? (pe + rbound < a[i + 1]) ? (pe + rbound) : a[i + 1] : L;
        }

        // Debug output (not much done since DUMP not used)
        for (int i = 0; i < n; i++) {
            printf("start[%d]: %d, end[%d]: %d\n", i, start[i], i, end[i]);
        }

        int* result = (int*)malloc(n * sizeof(int));
        result[n - 1] = L;
        for (int i = n - 2; i >= 0; i--) {
            int left = (start[i] > result[i + 1] - rbound) ? start[i] : (result[i + 1] - rbound);
            int right = (end[i] < result[i + 1] - lbound) ? end[i] : (result[i + 1] - lbound);
            if (left > right) {
                // Handle error case, left should not exceed right
                return;
            }
            result[i] = right;
        }

        for (int i = 0; i < n; i++) {
            printf("%d %d\n", (i == 0) ? 0 : result[i - 1], result[i]);
        }

        free(start);
        free(end);
        free(result);
        free(a);
    }

    int search_lbound() {
        int l = 0, r = L;
        while (l <= r) {
            int mid = (l + r) >> 1;
            if (check_lbound(mid)) l = mid + 1;
            else r = mid - 1;
        }
        return l - 1;
    }

    int check_lbound(int bar) {
        int cur = 0;
        for (int i = 0; i < n; i++) {
            if (cur + bar > (i + 1 < n ? a[i + 1] : L)) return 0;
            cur = (cur + bar > a[i]) ? cur + bar : a[i];
        }
        return 1;
    }

    int search_rbound() {
        int l = 0, r = L;
        while (l <= r) {
            int mid = (l + r) >> 1;
            if (check_rbound(mid)) r = mid - 1;
            else l = mid + 1;
        }
        return r + 1;
    }

    int check_rbound(int bar) {
        int cur = 0;
        for (int i = 0; i < n; i++) {
            if (a[i] - cur > bar) return 0;
            cur = (cur + bar < (i + 1 < n ? a[i + 1] : L)) ? cur + bar : (i + 1 < n ? a[i + 1] : L);
        }
        return (cur == L);
    }
};

