#include <stdio.h>
#include <stdlib.h>

struct Node {
    int key;
    int value;
    struct Node* next;
};

struct HashMap {
    struct Node** table;
    int size;
};

struct HashMap* createMap(int size) {
    struct HashMap* map = malloc(sizeof(struct HashMap));
    map->table = malloc(sizeof(struct Node*) * size);
    for (int i = 0; i < size; i++) {
        map->table[i] = NULL;
    }
    map->size = size;
    return map;
}

unsigned int hash(int key, int size) {
    return key % size;
}

void put(struct HashMap* map, int key) {
    unsigned int idx = hash(key, map->size);
    struct Node* current = map->table[idx];

    while (current != NULL) {
        if (current->key == key) {
            current->value++;
            return;
        }
        current = current->next;
    }

    struct Node* newNode = malloc(sizeof(struct Node));
    newNode->key = key;
    newNode->value = 1;
    newNode->next = map->table[idx];
    map->table[idx] = newNode;
}

int countUnique(struct HashMap* map) {
    int count = 0;
    for (int i = 0; i < map->size; i++) {
        struct Node* current = map->table[i];
        while (current != NULL) {
            count++;
            current = current->next;
        }
    }
    return count;
}

void freeMap(struct HashMap* map) {
    for (int i = 0; i < map->size; i++) {
        struct Node* current = map->table[i];
        while (current != NULL) {
            struct Node* tmp = current;
            current = current->next;
            free(tmp);
        }
    }
    free(map->table);
    free(map);
}

int distributeCandies(int* c, int len) {
    struct HashMap* map = createMap(len);
    for (int i = 0; i < len; i++) {
        put(map, c[i]);
    }

    int uniqueCount = countUnique(map);
    int maxCandies = len / 2;

    freeMap(map);

    if (uniqueCount >= maxCandies) {
        return maxCandies;
    } else {
        return uniqueCount;
    }
}

int main() {
    int candies[] = {1, 1, 2, 2, 3, 3};
    int len = sizeof(candies) / sizeof(candies[0]);
    int result = distributeCandies(candies, len);
    printf("%d\n", result);
    return 0;
}

