struct Graph* createGraph(int N, int M) {
    struct Graph* g = (struct Graph*)malloc(sizeof(struct Graph));
    g->N = N;
    g->M = M;
    g->adj = (struct Edge**)malloc((N + 1) * sizeof(struct Edge*));
    for (int i = 1; i <= N; i++) {
        g->adj[i] = (struct Edge*)malloc((M + 1) * sizeof(struct Edge));
    }
    for (int i = 0; i < M; i++) {
        int u, v, w;
        scanf("%d %d %d", &u, &v, &w);
        g->adj[u][0].node = v;
        g->adj[u][0].weight = w;
        g->adj[v][0].node = u;
        g->adj[v][0].weight = w;
    }
    return g;
}

void shortest_distance(struct Graph* g, int s) {
    int* dist = (int*)malloc((g->N + 1) * sizeof(int));
    int* processed = (int*)malloc((g->N + 1) * sizeof(int));
    for (int i = 1; i <= g->N; i++) {
        dist[i] = -1; // -1 means unreachable
        processed[i] = 0;
    }
    dist[s] = 0;
    int v = s;

    while(1) {
        processed[v] = 1;

        for (int i = 0; i < g->M; i++) {
            if (g->adj[v][i].node == 0) break; // no more edges
            int node = g->adj[v][i].node;
            int weight = g->adj[v][i].weight;

            if (processed[node]) {
                continue;
            }
            int new_dist = dist[v] + weight;

            if (dist[node] == -1 || dist[node] > new_dist) {
                dist[node] = new_dist;
            }
        }
        int min_dist = -1, next_node = -1;

        for (int i = 1; i <= g->N; i++) {
            if (processed[i]) continue;
            if (dist[i] == -1) continue;
            if (min_dist == -1 || dist[i] < min_dist) {
                min_dist = dist[i];
                next_node = i;
            }
        }
        if (next_node == -1) break;
        v = next_node;
    }

    for (int n = 1; n <= g->N; n++) {
        if (n == s) continue;
        if (dist[n] == -1) {
            printf("-1 ");
        } else {
            printf("%d ", dist[n]);
        }
    }
    printf("\n");

    free(dist);
    free(processed);
}

int main() {
    int T;
    scanf("%d", &T);
    for (int i = 0; i < T; i++) {
        int N, M;
        scanf("%d %d", &N, &M);
        struct Graph* g = createGraph(N, M);
        int s;
        scanf("%d", &s);
        shortest_distance(g, s);
        for (int j = 1; j <= N; j++) {
            free(g->adj[j]);
        }
        free(g->adj);
        free(g);
    }
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct {
    int m;
    int k;
    int *Q;
    int front;
    int rear;
    int count;
    int *sorted;
} MKAverage;

MKAverage* mkaverageCreate(int m, int k) {
    MKAverage *obj = (MKAverage *)malloc(sizeof(MKAverage));
    obj->m = m;
    obj->k = k;
    obj->Q = (int *)malloc(m * sizeof(int));
    obj->sorted = (int *)malloc(m * sizeof(int));
    obj->front = 0;
    obj->rear = 0;
    obj->count = 0;
    return obj;
}

void addToSorted(int *sorted, int count, int value) {
    int i = 0;
    while(i < count && sorted[i] < value) {
        i++;
    }
    for(int j = count; j > i; j--) {
        sorted[j] = sorted[j - 1];
    }
    sorted[i] = value;
}

void removeFromSorted(int *sorted, int count, int value) {
    int index = -1;
    for(int i = 0; i < count; i++) {
        if (sorted[i] == value) {
            index = i;
            break;
        }
    }
    if (index != -1) {
        for(int j = index; j < count - 1; j++) {
            sorted[j] = sorted[j + 1];
        }
    }
}

void mkaverageAddElement(MKAverage* obj, int num) {
    if (obj->count == obj->m) {
        removeFromSorted(obj->sorted, obj->count, obj->Q[obj->front]);
        obj->front = (obj->front + 1) % obj->m;
    } else {
        obj->count++;
    }
    obj->Q[obj->rear] = num;
    obj->rear = (obj->rear + 1) % obj->m;
    addToSorted(obj->sorted, obj->count - 1, num);
}

int mkaverageCalculateMKAverage(MKAverage* obj) {
    if (obj->count < obj->m) {
        return -1;
    }
    int sum = 0;
    int start = obj->k;
    int end = obj->count - obj->k - 1;
    for(int i = start; i <= end; i++) {
        sum += obj->sorted[i];
    }
    return sum / (obj->m - (obj->k * 2));
}

void mkaverageFree(MKAverage* obj) {
    free(obj->Q);
    free(obj->sorted);
    free(obj);
}

int main() {
    MKAverage* obj = mkaverageCreate(3, 1);
    mkaverageAddElement(obj, 3);
    mkaverageAddElement(obj, 1);
    mkaverageAddElement(obj, 10);
    printf("%d\n", mkaverageCalculateMKAverage(obj)); // Output: 5
    mkaverageAddElement(obj, 5);
    printf("%d\n", mkaverageCalculateMKAverage(obj)); // Output: 5
    mkaverageFree(obj);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int num = 0;
    printf("Enter the number of elements: ");
    scanf("%d", &num);

    // Temporarily hold input line
    char str_line[1000];
    printf("Enter the numbers separated by spaces: ");
    getchar();  // to consume the newline character after int input
    fgets(str_line, 1000, stdin);

    // Split and convert to integers
    int *num_line = malloc(num * sizeof(int));
    char *token = strtok(str_line, " ");
    int i = 0;

    while (token != NULL && i < num) {
        num_line[i] = atoi(token);
        token = strtok(NULL, " ");
        i++;
    }

    // Calculate average
    int ave = 0;
    for (int j = 0; j < num; j++) {
        ave += num_line[j];
    }

    // Process average
    if (ave % num == 0) {
        ave /= num;
    } else {
        if (ave % num <= num / 2) {
            ave /= num;
        } else {
            ave = (ave / num) + 1;
        }
    }

    // Calculate weighted average (wa)
    int wa = 0;
    for (int j = 0; j < num; j++) {
        int temp = num_line[j] - ave;
        wa += temp * temp;
    }

    printf("Weighted average: %d\n", wa);

    // Clean up
    free(num_line);
    return 0;
}

