#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int closestMeetingNode(int* edges, int edgesSize, int node1, int node2) {
    int* dist1 = (int*)malloc(edgesSize * sizeof(int));
    int* dist2 = (int*)malloc(edgesSize * sizeof(int));

    for (int i = 0; i < edgesSize; i++) {
        dist1[i] = -1;
    }
    dist1[node1] = 0; 
    int t = node1; 
    while (1) {
        int x = edges[t]; 
        if (x == -1 || dist1[x] != -1) { 
            break; 
        }
        dist1[x] = dist1[t] + 1; 
        t = x; 
    }

    for (int i = 0; i < edgesSize; i++) { 
        dist2[i] = -1; 
    }
    dist2[node2] = 0; 
    t = node2; 
    while (1) {
        int x = edges[t]; 
        if (x == -1 || dist2[x] != -1) { 
            break; 
        }
        dist2[x] = dist2[t] + 1; 
        t = x; 
    }

    int min = 1000000000; 
    int res = -1; 

    for (int i = 0; i < edgesSize; i++) {
        if (dist1[i] != -1 && dist2[i] != -1) {
            int maxDist = (dist1[i] > dist2[i]) ? dist1[i] : dist2[i]; 
            if (min > maxDist) {
                min = maxDist; 
                res = i; 
            }
        }
    }

    free(dist1); 
    free(dist2); 

    return res; 
}

int main() {
    int edges[] = {1,2,-1,4,5,-1,7,-1}; // Example edges
    int node1 = 0; 
    int node2 = 3; 
    int result = closestMeetingNode(edges, 8, node1, node2); 
    printf("Result: %d\n", result); 
    return 0; 
}

