#define MOD 1000000007
#define MAX_LEN 1000

int n;
long long m[101][MAX_LEN];

int d(const char *s) {
	if (strstr(s, "AGC") != NULL) {
		return 0; // false
	}
	for (int i = 0; i < 3; i++) {
		char tmp[MAX_LEN];
		strcpy(tmp, s);
		char c = tmp[i], d = tmp[i + 1];
		tmp[i] = d;
		tmp[i + 1] = c;
		if (strstr(tmp, "AGC") != NULL) {
			return 0; // false
		}
	}
	return 1; // true
}

long long f(int num, const char *s) {
	if (num > n) return 0;
	if (m[num][s[0]] != -1) return m[num][s[0]];
	if (num == n) return 1;

	long long ans = 0;
	for (int i = 0; i < 4; i++) { 
		char c;
		if (i == 0) c = 'A';
		else if (i == 1) c = 'C';
		else if (i == 2) c = 'G';
		else c = 'T';

		char new_s[MAX_LEN];
		snprintf(new_s, sizeof(new_s), "%s%c", s + 1, c);
		if (d(new_s)) {
			ans = (ans + f(num + 1, new_s)) % MOD;
		}
	}
	m[num][s[0]] = ans;
	return ans;
}

int main() {
	scanf("%d", &n);
	memset(m, -1, sizeof(m));

	char initial[4] = "PPP";
	long long result = f(0, initial);
	printf("%lld\n", result);
	return 0;
}

#include <stdio.h>
#include <stdlib.h>

struct Node {
    int value;
    struct Node* next;
};

void insert(struct Node** head, int new_value) {
    struct Node* new_node = (struct Node*)malloc(sizeof(struct Node));
    new_node->value = new_value;
    new_node->next = *head;
    *head = new_node;
}

int contains(struct Node* head, int target) {
    struct Node* current = head;
    while (current != NULL) {
        if (current->value == target) {
            return 1; // found
        }
        current = current->next;
    }
    return 0; // not found
}

void freeList(struct Node* head) {
    struct Node* tmp;
    while (head != NULL) {
        tmp = head;
        head = head->next;
        free(tmp);
    }
}

int findFinalValue(int* nums, int size, int original) {
    struct Node* S = NULL;

    for (int i=0; i<size; i++) {
        insert(&S, nums[i]);
    }

    int ret = original;
    while (contains(S, ret)) {
        ret *= 2;
    }

    freeList(S);
    return ret;
}

int main() {
    int nums[] = {1, 2, 3, 4};
    int original = 3;
    int finalValue = findFinalValue(nums, 4, original);
    printf("Final Value: %d\n", finalValue);
    return 0;
}

