#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int N; 
    scanf("%d", &N);
    char *Ss = (char*) malloc((N * 2 + 1) * sizeof(char));
    scanf("%s", Ss);

    int maxStates = 1 << N; // 2^N
    char **Fss = (char**) malloc(maxStates * sizeof(char*));

    for (int sels = 0; sels < maxStates; sels++) {
        Fss[sels] = (char*) malloc((N + 1) * sizeof(char));
        int k = 0;
        for (int i = 0; i < N; i++) {
            if (sels & (1 << i)) {
                Fss[sels][k++] = Ss[i];
            }
        }
        Fss[sels][k] = '\0';
    }

    long long ans = 0;

    for (int iFs = 0; iFs < maxStates; iFs++) {
        char *Fs = Fss[iFs];
        char *Gs = Fss[maxStates - 1 - iFs];
        int lenF = strlen(Fs);
        int lenG = N - lenF;

        long long *dp = (long long*) malloc((lenF + 1) * sizeof(long long));
        dp[0] = 1;
        for (int j = 1; j <= lenF; j++) {
            dp[j] = 0;
        }

        for (int i = 0; i < strlen(Ss + N); i++) {
            char s = Ss[N + i];
            long long *dp2 = (long long*) malloc((lenF + 1) * sizeof(long long));
            for (int j = 0; j <= lenF; j++) {
                dp2[j] = 0;
            }

            for (int j = 0; j <= lenF; j++) {
                if (dp[j] == 0) {
                    continue;
                }
                if (j < lenF && s == Fs[j]) {
                    dp2[j + 1] += dp[j];
                }
                if (i - j >= 0 && i - j < lenG && s == Gs[i - j]) {
                    dp2[j] += dp[j];
                }
            }
            free(dp);
            dp = dp2;
        }
        ans += dp[lenF];
        free(dp);
    }

    printf("%lld\n", ans);

    for (int i = 0; i < maxStates; i++) {
        free(Fss[i]);
    }
    free(Fss);
    free(Ss);

    return 0;
}

