int main() {
    int n;
    scanf("%d", &n);

    double temp = sqrt(4 * n);
    temp = ceil(temp);

    double sx = sqrt(fabs(temp * temp - 4 * n));

    if (sx != (int)sx && sx <= 10) {
        while (sx < sqrt(n) && sx <= 10) {
            temp += 1;
            sx = sqrt(fabs(temp * temp - 4 * n));
            if (sx == (int)sx) {
                break;
            }
        }
    }

    int x = (int)((-sx + temp) / 2);
    char check[20];
    sprintf(check, "%d", x);

    int check_sum = 0;
    for (int i = 0 ; i < strlen(check); i++) {
        check_sum += check[i] - '0'; // converting char to int
    }

    if (check_sum == (int)sx) {
        printf("%d\n", x);
    } else {
        printf("%d\n", -1);
    }

    return 0;
}

