int cmpfunc(const void * a, const void * b) {
    return (*(int*)b - *(int*)a);
}

int main() {
    int t;
    scanf("%d", &t);
    while (t > 0) {
        t -= 1;
        int n, x;
        scanf("%d %d", &n, &x);
        int *a = malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &a[i]);
        }
        qsort(a, n, sizeof(int), cmpfunc);

        int k = 1;
        int team = 0;

        for (int i = 0; i < n; i++) {
            int current = a[i];
            if (current * k < x) {
                k += 1 ;
            } else {
                team += 1 ;
                k = 1;
            }
        }
        printf("%d\n", team);

        free(a);
    }
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int cmpfunc(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int t;
    scanf("%d", &t);

    int *a = (int*)malloc(t * sizeof(int));
    int *b = (int*)malloc(t * sizeof(int));
    int *c = (int*)malloc(t * sizeof(int));

    for(int i = 0; i < t; i++) {
        scanf("%d", &a[i]);
    }

    for(int j = 0; j < t; j++) {
        scanf("%d", &b[j]);
    }

    for(int k = 0; k < t; k++) {
        c[k] = a[k] - b[k];
    }

    qsort(c, t, sizeof(int), cmpfunc);

    long long ans = 0;
    for(int i = 0; i < t; i++) {
        if(c[i] <= 0) {
            continue;
        }

        int find = -c[i] + 1;
        int l = 0, r = i;

        while(l < r) {
            int mid = l + (r - l) / 2;
            if(c[mid] < find) {
                l = mid + 1;
            } else {
                r = mid;
            }
        }

        ans += (i - l);
    }

    printf("%lld\n", ans);

    free(a);
    free(b);
    free(c);

    return 0;
}

