int bin_to_dec(char *bin_str) {
    int dec = 0;
    int base = 1;
    int len = strlen(bin_str);
    for (int i = len - 1; i >= 0; i--) {
        if (bin_str[i] == '1') {
            dec += base;
        }
        base *= 2;
    }
    return dec;
}

void process_data(int n, int m) {
    if (n == 1) {
        printf("%d\n", m % 2);
    } 
    else if (n == 0) {
        printf("0\n");
    } 
    else {
        // Binary conversion
        char bin[64]; // enough to hold binary representation
        int len = 0;
        int tmp = m;
        while (tmp > 0) {
            bin[len++] = (tmp % 2) + '0'; // store as char
            tmp /= 2;
        }
        // Reverse the binary string
        for (int i = 0; i < len / 2; i++) {
            char swap = bin[i];
            bin[i] = bin[len - 1 - i];
            bin[len - 1 - i] = swap;
        }
        bin[len] = '\0'; // null terminate

        // Get the last l bits
        if (n + 1 > len) {
            printf("%d\n", m);
        } 
        else {
            char a[64];
            for (int i = 0; i < n; i++) {
                a[i] = bin[len - n + i];
            }
            a[n] = '\0'; // null terminate
            int result = bin_to_dec(a);
            printf("%d\n", result);
        }
    }
}

int main() {
    int n, m;
    get_input(&n, &m);
    process_data(n, m);
    return 0;
}

