    char color[10];

    scanf("%d %d %s", &n, &m, color);

    char **grid = (char **)malloc(n * sizeof(char *));
    for(int i = 0; i < n; i++) {
        grid[i] = (char *)malloc((m + 1) * sizeof(char));
        scanf("%s", grid[i]);
    }

    int **visited = (int **)malloc(n * sizeof(int *));
    for(int i = 0; i < n; i++) {
        visited[i] = (int *)malloc(m * sizeof(int));
        memset(visited[i], 0, m * sizeof(int));
    }

    char colors[100][10];
    int color_count = 0;

    // Adding color to "colors" set
    strcpy(colors[color_count++], color);

    for(int i = 0; i < n; i++) {
        for(int j = 0; j < m; j++) {
            if(visited[i][j] == 0 && grid[i][j] == color[0]) {
                int to_visit[100][2], to_visit_size = 0;
                to_visit[to_visit_size][0] = i; 
                to_visit[to_visit_size][1] = j; 
                to_visit_size++;
                visited[i][j] = 1;

                while(to_visit_size > 0) {
                    to_visit_size--;
                    int i_ = to_visit[to_visit_size][0];
                    int j_ = to_visit[to_visit_size][1];

                    for(int di = -1; di <= 1; di += 2) {
                        for(int dj = -1; dj <= 1; dj += 2) {
                            if(bus_di(di, dj) == 1) {
                                int ni = i_ + di;
                                int nj = j_ + dj;

                                if(ni >= 0 && ni < n && nj >= 0 && nj < m) {
                                    if(visited[ni][nj] == 0) {
                                        char candidate = grid[ni][nj];
                                        int found = 0;
                                        for(int k = 0; k < color_count; k++) {
                                            if(strcmp(colors[k], &candidate) == 0) {
                                                found = 1;
                                                break;
                                            }
                                        }
                                        if(!found) {
                                            strcpy(colors[color_count++], &candidate);
                                        }
                                        visited[ni][nj] = 1;
                                        if(grid[ni][nj] == color[0]) {
                                            to_visit[to_visit_size][0] = ni;
                                            to_visit[to_visit_size][1] = nj;
                                            to_visit_size++;
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    }

    // Discarding '.' if it exists
    for(int i = 0; i < color_count; i++) {
        if(strcmp(colors[i], ".") == 0) {
            color_count--;
            for(int j = i; j < color_count; j++) {
                strcpy(colors[j], colors[j + 1]);
            }
            i--;
        }
    }

    int ans = color_count - 1;
    printf("%d\n", ans);

    // Free allocated memory
    for(int i = 0; i < n; i++) {
        free(grid[i]);
    }
    free(grid);

    for(int i = 0; i < n; i++) {
        free(visited[i]);
    }
    free(visited);

    return 0;
}

