#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <assert.h>

#define MAXN 200005

struct Pair {
    int first;
    int second;
};

int seen[MAXN], indx[MAXN];
int in_deg[MAXN], out_deg[MAXN], val[MAXN];
int edges[MAXN][MAXN];
int edge_count[MAXN];

void insert_edge(int from, int to) {
    edges[from][edge_count[from]++] = to;
}

void dfs(int now, int *path, int *path_index) {
    for (int i = 0; i < edge_count[now]; i++) {
        int neighbor = edges[now][i];
        if (neighbor != -1) {
            edges[now][i] = -1; // mark as visited
            dfs(neighbor, path, path_index);
        }
    }
    path[(*path_index)++] = now;
}

int* validArrangement(struct Pair* pairs, int pairsSize, int* returnSize) {
    memset(seen, 0, sizeof(seen));
    memset(indx, -1, sizeof(indx));
    memset(in_deg, 0, sizeof(in_deg));
    memset(out_deg, 0, sizeof(out_deg));

    int id = 0;
    for (int i = 0; i < pairsSize; i++) {
        if (!seen[pairs[i].first]) {
            seen[pairs[i].first] = 1;
            indx[pairs[i].first] = id++;
            val[indx[pairs[i].first]] = pairs[i].first;
        }
        if (!seen[pairs[i].second]) {
            seen[pairs[i].second] = 1;
            indx[pairs[i].second] = id++;
            val[indx[pairs[i].second]] = pairs[i].second;
        }
    }

    for (int i = 0; i < pairsSize; i++) {
        int u = indx[pairs[i].first];
        int v = indx[pairs[i].second];
        in_deg[v]++;
        out_deg[u]++;
        insert_edge(u, v);
    }

    int outliers[2], outlier_count = 0;
    for (int i = 0; i < MAXN; i++) {
        if (in_deg[i] != out_deg[i]) {
            outliers[outlier_count++] = i;
        }
    }
    assert(outlier_count == 0 || outlier_count == 2);

    int dummy = 200004;
    int from = -1, to = -1;

    if (outlier_count == 2) {
        from = (in_deg[outliers[0]] < out_deg[outliers[0]]) ? outliers[0] : outliers[1];
        to = (in_deg[outliers[0]] < out_deg[outliers[0]]) ? outliers[1] : outliers[0];

        if (edges[to][indx[from]] != -1) {
            insert_edge(to, dummy);
            insert_edge(dummy, from);
        }
        insert_edge(to, from);
    }

    if (from == -1) {
        from = indx[pairs[0].first];
    }

    int path[MAXN];
    int path_index = 0;

    dfs(from, path, &path_index);

    for (int i = 0; i < path_index / 2; i++) {
        int temp = path[i];
        path[i] = path[path_index - i - 1];
        path[path_index - i - 1] = temp;
    }

    int start_index = 0;
    if (outlier_count == 2) {
        for (int i = 0; i < path_index; i++) {
            if (path[i] == to && path[(i + 1) % path_index] == from) {
                start_index = (i + 1) % path_index;
                break;
            }
        }
    }

    int **result = malloc(sizeof(int *) * (path_index + 1));
    *returnSize = 0;

    for (int i = 0; i < path_index; ) {
        result[*returnSize] = malloc(sizeof(int) * 2);
        if (path[(start_index + i + 1) % path_index] == dummy) {
            result[*returnSize][0] = val[path[(start_index + i) % path_index]];
            result[*returnSize][1] = val[path[(start_index + i + 2) % path_index]];
            i += 2;
        } else {
            result[*returnSize][0] = val[path[(start_index + i) % path_index]];
            result[*returnSize][1] = val[path[(start_index + i + 1) % path_index]];
            i++;
        }
        (*returnSize)++;
    }
    if (outlier_count == 2) {
        free(result[*returnSize - 1]);
        (*returnSize)--;
    }

    return result;
}

