int countSubstringWithEqualEnds(char *s) {
    int res = strlen(s);
    int *k = (int*) calloc(256, sizeof(int));
    if (!k) return -1; // Just in case calloc fails

    for (int j = 0; j < strlen(s); j++) {
        char i = s[j];
        k[(int)i] += 1;
    }

    for (int x = 0; x < 256; x++) {
        if (k[x] > 1) {
            int count = k[x];
            res += count * (count - 1) / 2;
        }
    }

    free(k);
    return res;
}

