int* encode(const char* m, int k, int* size) {
    int len = strlen(m);
    int* result = (int*)malloc(len * sizeof(int));
    if (result == NULL) {
        *size = 0; 
        return NULL; 
    }

    char* k_str = (char*)malloc(30 * sizeof(char));
    if (k_str == NULL) {
        free(result);
        *size = 0; 
        return NULL; 
    }
    sprintf(k_str, "%d", k);
    int k_len = strlen(k_str);
    if (k_len > 30) {
        k_len = 30;
    }
    for (int i = 0; i < 30; i++) {
        k_str[i] = k_str[i % k_len]; 
    }

    for (int i = 0; i < len; i++) {
        char a = m[i];
        int b = k_str[i % 30] - '0'; 
        if (a >= 'a' && a <= 'z') {
            result[i] = (int)(a - 'a' + 1) + b;
        } else {
            result[i] = 0; 
        }
    }

    free(k_str);
    *size = len;
    return result;
}

