#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_T 10000

int C[MAX_T];
int P[MAX_T];
int Y[MAX_T];
int X[MAX_T][MAX_T];
int degree[MAX_T];

void addEdge(int a, int b) {
    X[a][degree[a]] = b;
    degree[a]++;
    X[b][degree[b]] = a;
    degree[b]++;
}

void bfs(int *R, int *Q, int *front, int *rear) {
    Q[(*rear)++] = 0;
    while (*front < *rear) {
        int x = Q[(*front)++];
        R[(*front) - 1] = x;
        for (int i = 0; i < degree[x]; i++) {
            int c = X[x][i];
            if (P[c] == -1) {
                P[c] = x;
                addEdge(x, c);
                Q[(*rear)++] = c;
            }
        }
    }
}

int main() {
    int t;
    scanf("%d", &t);

    for (int i = 0; i < t; i++) {
        P[i] = -1;
        degree[i] = 0;
    }

    for (int i = 0; i < t; i++) {
        int a, b, c;
        scanf("%d %d %d", &a, &b, &c);
        C[i] = a;
        Y[i] = b - c;
    }

    for (int i = 0; i < t - 1; i++) {
        int a, b;
        scanf("%d %d", &a, &b);
        a -= 1;
        b -= 1;
        addEdge(a, b);
    }

    if (sum(Y, t) != 0) {
        printf("-1\n");
        return 0;
    } else {
        int R[MAX_T];
        int Q[MAX_T];
        int front = 0, rear = 0;
        bfs(R, Q, &front, &rear);

        for (int j = front; j > 0; j--) {
            int idx = R[j - 1];
            if (idx > 0) {
                C[idx] = (C[idx] < C[P[idx]]) ? C[idx] : C[P[idx]];
            }
        }

        int ans = 0;
        for (int i = front - 1; i > 0; i--) {
            int idx = R[i];
            if (Y[idx] * Y[P[idx]] < 0) {
                ans += C[P[idx]] * ((Y[idx] < 0) ? -Y[idx] : Y[idx]);
                Y[P[idx]] += Y[idx];
            }
        }
        printf("%d\n", ans * 2);
    }
    return 0;
}

