#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>

#define MAXN 100
#define INF 1000000

void initList(int List[MAXN][MAXN], int N) {
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            List[i][j] = INF;
        }
    }
}

void readGraph(int List[MAXN][MAXN], int M) {
    for (int i = 0; i < M; i++) {
        int a, b, c;
        scanf("%d %d %d", &a, &b, &c);
        if (List[a - 1][b - 1] > c) {
            List[a - 1][b - 1] = c;
            List[b - 1][a - 1] = c;
        }
    }
}

void floydWarshall(int List[MAXN][MAXN], int d[MAXN][MAXN], int N) {
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            d[i][j] = List[i][j];
        }
    }
    for (int k = 0; k < N; k++) {
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (d[i][k] + d[k][j] < d[i][j]) {
                    d[i][j] = d[i][k] + d[k][j];
                }
            }
        }
    }
}

void permute(int *machi, int *arr, int n, int r, int *result, int *minVal) {
    if (r == 1) {
        int ans = 0;
        for (int j = 0; j < n - 1; j++) {
            ans += result[machi[j] - 1][machi[j + 1] - 1];
        }
        if (ans < *minVal) {
            *minVal = ans;
        }
        return;
    }
    for (int i = 0; i < r; i++) {
        permute(machi, arr, n, r - 1, result, minVal);
        if (r % 2 == 0) {
            int tmp = machi[i];
            machi[i] = machi[r - 1];
            machi[r - 1] = tmp;
        } else {
            int tmp = machi[0];
            machi[0] = machi[r - 1];
            machi[r - 1] = tmp;
        }
    }
}

int main() {
    int N, M, R;
    scanf("%d %d %d", &N, &M, &R);
    int machi[MAXN];
    for (int i = 0; i < R; i++) {
        scanf("%d", &machi[i]);
    }

    int List[MAXN][MAXN];
    initList(List, N);
    readGraph(List, M);

    int d[MAXN][MAXN];
    floydWarshall(List, d, N);

    int minVal = INT_MAX;
    permute(machi, NULL, R, R, d, &minVal);

    printf("%d\n", minVal);
    return 0;
}

