#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int maximum_alternating_subsequence(int* values, int len) {
    int* maximums = (int*)malloc((len + 1) * sizeof(int));
    int* minimums = (int*)malloc((len + 1) * sizeof(int));

    for (int i = 0; i <= len; i++) {
        maximums[i] = 0;
        minimums[i] = 0;
    }

    for (int index = 0; index < len; index++) {
        maximums[index + 1] = maximums[index] > (values[index] - minimums[index]) ? maximums[index] : (values[index] - minimums[index]);
        minimums[index + 1] = minimums[index] < (values[index] - maximums[index]) ? minimums[index] : (values[index] - maximums[index]);
    }

    int result = maximums[len];

    free(maximums);
    free(minimums);

    return result;
}

