#define BUFSIZE 8192
#define INF INT_MAX

typedef struct {
    FILE *file;
    char *buffer;
    size_t buf_size;
    size_t buf_pos;
    int newlines;
    int writable;
} FastIO;

typedef struct {
    FastIO *fast_io;
} IOWrapper;

void init_fastio(FastIO *fio, FILE *file) {
    fio->file = file;
    fio->buffer = malloc(BUFSIZE);
    fio->buf_size = 0;
    fio->buf_pos = 0;
    fio->newlines = 0;
    fio->writable = (file != stdin);
}

void read_fastio(FastIO *fio) {
    fio->buf_size = fread(fio->buffer, 1, BUFSIZE, fio->file);
    fio->buf_pos = 0;
    fio->newlines = 0;
    for (size_t i = 0; i < fio->buf_size; ++i) {
        if (fio->buffer[i] == '\n') {
            fio->newlines++;
        }
    }
}

char *fastio_readline(FastIO *fio) {
    if (fio->newlines == 0) {
        read_fastio(fio);
    }
    if (fio->buf_pos >= fio->buf_size) {
        return NULL;
    }

    size_t line_start = fio->buf_pos;
    while (fio->buf_pos < fio->buf_size && fio->buffer[fio->buf_pos] != '\n') {
        fio->buf_pos++;
    }
    size_t line_length = fio->buf_pos - line_start;
    char *line = malloc(line_length + 1);
    strncpy(line, fio->buffer + line_start, line_length);
    line[line_length] = '\0';
    fio->buf_pos++;
    fio->newlines--;
    return line;
}

int *read_ints() {
    char *line = fastio_readline(&fio);
    if (!line) return NULL;

    int *ints = malloc(10 * sizeof(int));
    int count = 0;
    char *token = strtok(line, " ");

    while (token) {
        if (count >= 10) {
            ints = realloc(ints, (count + 10) * sizeof(int));
        }
        ints[count++] = atoi(token);
        token = strtok(NULL, " ");
    }
    free(line);
    return ints;
}

int main() {
