int n;
int **dp;
int *nind;
int *a, *b;

void init_arrays(){
    dp = (int **)malloc(n * sizeof(int *));
    for (int j = 0; j < n; j++) {
        dp[j] = (int *)malloc(2 * sizeof(int));
        dp[j][0] = -1;
        dp[j][1] = -1;
    }
    nind = (int *)malloc(n * sizeof(int));
    a = (int *)malloc(n * sizeof(int));
    b = (int *)malloc(n * sizeof(int));
}

void free_arrays(){
    for (int j = 0; j < n; j++) {
        free(dp[j]);
    }
    free(dp);
    free(nind);
    free(a);
    free(b);
}

int solve(int i, int turn){
	if (i == n){
		return 0;
	}
	if (dp[i][turn] != -1){
		return dp[i][turn];
	}
    int ans = 0;
	if (turn == 0) {
		ans = solve(nind[i], 1) + b[i];
		int temp = solve(nind[i], 0);
		if (temp > ans) {
			ans = temp;
		}
	} else {
		ans = solve(nind[i], 0) - b[i];
		int temp = solve(nind[i], 1);
		if (temp < ans) {
			ans = temp;
		}
	}
	dp[i][turn] = ans;
	return ans;
}

int answer(){
	global nind;
	for (int i = 0; i < n; i++) {
		nind[i] = n;
	}
    int *s = (int *)malloc(n * sizeof(int));
    int top = -1;
	for (int i = 0; i < n; i++) {
		while (top >= 0 && a[i] & 1) {
			nind[s[top--]] = i;
		}
		s[++top] = i;
	}
	free(s);
	dp = (int **)malloc(n * sizeof(int *));
	for (int j = 0; j < n; j++) {
		dp[j] = (int *)malloc(2 * sizeof(int));
		dp[j][0] = -1;
		dp[j][1] = -1;
	}
	int start = n;
	for (int i = 0; i < n; i++) {
		if (a[i] & 1) {
			start = i;
			break;
		}
	}
	int ans = solve(start, 0);
	return ans;
}

int main() {
	int T;
	scanf("%d", &T);
	while (T--) {
		scanf("%d", &n);
        init_arrays();
		for (int i = 0; i < n; i++) {
			scanf("%d", &a[i]);
		}
		for (int i = 0; i < n; i++) {
			scanf("%d", &b[i]);
		}
		int result = answer();
		printf("%d\n", result);
		free_arrays();
	}
	return 0;
}

