int countTriplets(int* arr, int n) {
    int* tmpArr = (int*) malloc(n * sizeof(int));
    if (tmpArr == NULL) return 0;

    int prv = 0;
    for (int i = 0; i < n; i++) {
        tmpArr[i] = arr[i] ^ prv;
        prv = tmpArr[i];
    }

    int res = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            for (int k = j; k < n; k++) {
                int a = tmpArr[j - 1] ^ (i ? tmpArr[i - 1] : 0);
                int b = tmpArr[k] ^ tmpArr[j - 1];
                if (a == b) {
                    res++;
                }
            }
        }
    }

    free(tmpArr);
    return res;
}

