int minOperationsMaxProfit(int* customers, int customersSize, int boardingCost, int runningCost) {
    int ans = -1;
    int wait = 0;
    long long profit = 0;
    long long best = 0;
    int i;

    for (i = 0; i < customersSize; i++) {
        wait += customers[i];
        int board = (wait < 4) ? wait : 4;
        profit += board * boardingCost - runningCost;
        wait -= board;

        if (profit > best) {
            best = profit;
            ans = i + 1;
        }
    }

    int j = customersSize;
    while (wait > 0) {
        int board2 = (wait < 4) ? wait : 4;
        profit += board2 * boardingCost - runningCost;
        wait -= board2;

        if (profit > best) {
            best = profit;
            ans = j + 1;
        }
        j++;
    }

    return ans;
}

