#define MOD 1000000007

int min(int x, int y) {
    if (x < y) return x;
    return y;
}

int **create2DArray(int rows, int cols) {
    int **array = (int **)malloc(rows * sizeof(int *));
    for (int i = 0; i < rows; i++) {
        array[i] = (int *)malloc(cols * sizeof(int));
    }
    return array;
}

void free2DArray(int **array, int rows) {
    for (int i = 0; i < rows; i++) {
        free(array[i]);
    }
    free(array);
}

int solve(int m, int k, int *cnt) {
    if (m < k) return 0;
    int **f = create2DArray(m + 1, k + 1);
    f[0][0] = 1;

    for (int i = 1; i <= m; i++) {
        for (int j = 0; j <= min(k, i); j++) {
            if (j == 0) {
                f[i][j] = 1;
            } else {
                f[i][j] = (f[i - 1][j] + (cnt[i] * f[i - 1][j - 1]) % MOD) % MOD;
            }
        }
    }
    int result = f[m][k];
    free2DArray(f, m + 1);
    return result;
}

int process(int x, int *check, int *cnt, int **a, int n) {
    check[x] = 1;
    int res = 0;
    int **q = (int **)malloc(n * sizeof(int *));
    for (int i = 0; i < n; i++) {
        q[i] = (int *)malloc(2 * sizeof(int));
    }
    int q_len = 0;

    for (int i = 0; a[x][i] != -1; i++) {
        int v = a[x][i];
        check[v] = 1;
        q[q_len][0] = v; 
        q[q_len][1] = i + 1; 
        q_len++;
    }

    res = solve(n, x, cnt);
    while (q_len > 0) {
        int **cur = (int **)malloc(n * sizeof(int *));
        for (int i = 0; i < n; i++) {
            cur[i] = (int *)malloc(2 * sizeof(int));
        }
        int cur_len = 0;

        for (int i = 0; i < q_len; i++) {
            int u = q[i][0];
            int j = q[i][1];
            cnt[j] -= 1;

            for (int k = 0; a[u][k] != -1; k++) {
                if (check[a[u][k]] == 0) {
                    cur[cur_len][0] = a[u][k];
                    cur[cur_len][1] = j;
                    check[a[u][k]] = 1;
                    cnt[j] += 1;
                    cur_len++;
                }
            }
        }

        for (int i = 0; i < cur_len; i++) {
            q[i][0] = cur[i][0];
            q[i][1] = cur[i][1];
        }
        q_len = cur_len;
        free(cur);
        res = (res + solve(n, x, cnt)) % MOD;
    }
    free(q);
    return res;
}

int main() {
    int test;
    scanf("%d", &test);
    for (int t = 0; t < test; t++) {
        int n, k;
        scanf("%d", &n);
        scanf("%d %d", &n, &k);
        int **a = (int **)malloc((n + 1) * sizeof(int *));
        for (int i = 0; i <= n; i++) {
            a[i] = (int *)malloc((n + 1) * sizeof(int));
            for (int j = 0; j < n + 1; j++) {
                a[i][j] = -1; 
            }
        }

        for (int i = 0; i < n - 1; i++) {
            int x, y;
            scanf("%d %d", &x, &y);
            a[x][i] = y;
            a[y][i] = x;
        }

        long long ans = 0;
        if (k == 2) {
            printf("%lld\n", (long long)n * (n - 1) / 2);
            continue;
        }

        for (int x = 1; x <= n; x++) {
            int *check = (int *)malloc((n + 1) * sizeof(int));
            int *cnt = (int *)malloc((n + 1) * sizeof(int));
            for (int i = 0; i <= n; i++) {
                check[i] = 0;
                cnt[i] = 1;
            }
            ans = (ans + process(x, check, cnt, a, n)) % MOD;
            free(check);
            free(cnt);
        }

        printf("%lld\n", ans);
        for (int i = 0; i <= n; i++) {
            free(a[i]);
        }
        free(a);
    }
    return 0;
}

