            printf("0 0\n");
        } else {
            printf("-1 -1\n");
        }
    } else {
        int sg = s;
        int sd = s;
        char cmin[100]; // assuming m won't exceed 99
        char cmax[100]; // assuming m won't exceed 99
        memset(cmin, 0, sizeof(cmin));
        memset(cmax, 0, sizeof(cmax));

        for (int i = 0 ; i < m ; i++) {
            int c = 1 ; // default carry for the first digit
            if (i != 0) {
                c = 0 ; // no carry for subsequent digits
            }

            int g = (sg - 9 * (m - i - 1) < c) ? c : (sg - 9 * (m - i - 1));
            if (g < 0) g = 0 ; // safety check

            sg -= g;

            int d = (sd < 9) ? sd : 9 ;
            sd -= d;

            cmin[i] = g + '0' ;
            cmax[i] = d + '0' ;
        }

        printf("%s %s\n", cmin, cmax);
    }

    return 0;
}

