    for (int k = 1; k <= n; k++) {
        scanf("%d", &c[k]); // mimicking list(map(int, input().split()))
    }
    c[0] = 0; // similar to c.insert(0, 0)

    long long ans = 0; // using long long for larger sums

    for (int i = 1; i <= n; i += 2) { // for odd i
        long long bal = 0; // balance
        long long lo = 1; // lowest value

        for (int j = i + 1; j <= n; j++) { 
            if (j % 2 == 0) { // j is even
                long long L = lo; 
                long long R = (bal + lo < 1) ? 1 : bal + lo; // max(1, bal + lo)

                long long addVal = c[i] - L + 1; // calc for max
                long long reduceVal = c[j] - R + 1; 

                ans += (addVal < 0) ? 0 : (addVal < reduceVal ? addVal : reduceVal); // nested max and min

                bal -= c[j]; // j even, reduce bal
            } else { // j is odd
                bal += c[j]; // increase balance
            }
            lo = (lo > -bal) ? lo : -bal; // update lo
        }
    }

    printf("%lld\n", ans); // print answer
    free(c); // clean up memory
    return 0;
}

