void helper(int idx, char* s, char** lst, int* lstSize, char*** res, int* resSize);
bool checkpalindrome(int a, int b, char* s);
void addToList(char*** res, int* resSize, char** lst, int lstSize);

void allPalindromicPerms(char* S, char*** res, int* resSize) {
    char** lst = malloc(strlen(S) * sizeof(char*));
    int lstSize = 0;

    helper(0, S, lst, &lstSize, res, resSize);

    free(lst);
}

void addToList(char*** res, int* resSize, char** lst, int lstSize) {
    (*resSize)++;
    *res = realloc(*res, (*resSize) * sizeof(char*));
    (*res)[*resSize - 1] = malloc((lstSize + 1) * sizeof(char*));

    for (int k = 0; k < lstSize; k++) {
        (*res)[*resSize - 1][k] = malloc((strlen(lst[k]) + 1) * sizeof(char));
        strcpy((*res)[*resSize - 1][k], lst[k]);
    }
    (*res)[*resSize - 1][lstSize] = NULL;
}

bool checkpalindrome(int a, int b, char* s) {
    while (a <= b) {
        if (s[a] != s[b]) {
            return false;
        }
        a++;
        b--;
    }
    return true;
}

void helper(int idx, char* s, char** lst, int* lstSize, char*** res, int* resSize) {
    if (idx == strlen(s)) {
        addToList(res, resSize, lst, *lstSize);
        return;
    }

    for (int i = idx; i < strlen(s); i++) {
        if (checkpalindrome(idx, i, s) == true) {
            lst[*lstSize] = malloc((i - idx + 2) * sizeof(char));
            strncpy(lst[*lstSize], s + idx, i - idx + 1);
            lst[*lstSize][i - idx + 1] = '\0';  
            (*lstSize)++;
            helper(i + 1, s, lst, lstSize, res, resSize);
            (*lstSize)--;
            free(lst[*lstSize]);
        }
    }
}

