#define INF 1000000000000000000
#define MOD (1000000007)
#define M (300000)

long long fac[M];

void init_fact() {
    fac[0] = 1;
    for (int i = 1; i < M; i++) {
        fac[i] = (fac[i - 1] * i) % MOD;
    }
}

long long pow_mod(long long base, long long exp, long long mod) {
    long long result = 1;
    while (exp > 0) {
        if (exp % 2 == 1) {
            result = (result * base) % mod;
        }
        base = (base * base) % mod;
        exp /= 2;
    }
    return result;
}

long long nCk(int n, int k) {
    if (n < k) {
        return 0;
    }
    long long numerator = fac[n];
    long long denom1 = pow_mod(fac[n - k], MOD - 2, MOD);
    long long denom2 = pow_mod(fac[k], MOD - 2, MOD);
    return (numerator * denom1 % MOD) * denom2 % MOD;
}

void solve() {
    int n, m, k;
    scanf("%d %d %d", &n, &m, &k);
    int *a = malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
    }

    // Sorting a
    for (int i = 0; i < n-1; i++) {
        for (int j = i + 1; j < n; j++) {
            if (a[i] > a[j]) {
                int tmp = a[i];
                a[i] = a[j];
                a[j] = tmp;
            }
        }
    }

    long long ans = 0;
    int i = m - 1, j = 0;
    while(i < n) {
        while(j < i && a[i] - a[j] > k) {
            j++;
        }
        int length = i - j;
        ans = (ans + nCk(length, m - 1)) % MOD;
        i++;
    }

    printf("%lld\n", ans);
    free(a);
}

int main() {
    init_fact();
    int t;
    scanf("%d", &t);
    while(t > 0) {
        solve();
        t--;
    }
    return 0;
}

