struct Node {
    int key;
    int *values;
    int size;
    int capacity;
};

struct HashMap {
    struct Node *table;
    int size;
};

struct HashMap* createHashMap(int size) {
    struct HashMap* map = malloc(sizeof(struct HashMap));
    map->table = malloc(sizeof(struct Node) * size);
    for (int i = 0; i < size; i++) {
        map->table[i].key = -1;
        map->table[i].values = NULL;
        map->table[i].size = 0;
        map->table[i].capacity = 0;
    }
    map->size = size;
    return map;
}

void insert(struct HashMap* map, int key, int value) {
    int index = key % map->size;
    while (map->table[index].key != -1 && map->table[index].key != key) {
        index = (index + 1) % map->size;
    }
    if (map->table[index].key != key) {
        map->table[index].key = key;
    }
    if (map->table[index].size >= map->table[index].capacity) {
        map->table[index].capacity = map->table[index].capacity == 0 ? 2 : map->table[index].capacity * 2;
        map->table[index].values = realloc(map->table[index].values, sizeof(int) * map->table[index].capacity);
    }
    map->table[index].values[map->table[index].size++] = value;
}

int get(struct HashMap* map, int key, int* arr) {
    int index = key % map->size;
    while (map->table[index].key != -1) {
        if (map->table[index].key == key) {
            memcpy(arr, map->table[index].values, sizeof(int) * map->table[index].size);
            return map->table[index].size;
        }
        index = (index + 1) % map->size;
    }
    return 0;
}

int calcDigitSum(int num) {
    int sum = 0;
    while (num) {
        sum += num % 10;
        num /= 10;
    }
    return sum;
}

int RulingPair(int* arr, int n) {
    struct HashMap* map = createHashMap(100);
    for (int i = 0; i < n; i++) {
        int sum = calcDigitSum(arr[i]);
        insert(map, sum, arr[i]);
    }
    int ans = 0;
    for (int i = 0; i < map->size; i++) {
        if (map->table[i].key != -1 && map->table[i].size >= 2) {
            int size = map->table[i].size;
            int *values = map->table[i].values;
            for (int j = 0; j < size - 1; j++) {
                for (int k = j + 1; k < size; k++) {
                    if (values[j] < values[k]) {
                        int tmp = values[j];
                        values[j] = values[k];
                        values[k] = tmp;
                    }
                }
            }
            ans = ans > (values[0] + values[1]) ? ans : (values[0] + values[1]);
        }
    }
    return ans != 0 ? ans : -1;
}

int main() {
    int arr[] = {51, 71, 17, 42}; 
    int n = sizeof(arr) / sizeof(arr[0]);
    int result = RulingPair(arr, n);
    printf("%d\n", result);
    return 0;
}

