    for (int i = 0; i < num_pages; i++) {
        int page = pages[i];
        int found = 0;

        // Check if page already exists in page_set
        for(int j = 0; j < page_count; j++) {
            if(page_set[j] == page) {
                found = 1;
                break;
            }
        }
        if(!found) {
            page_set[page_count] = page;
            page_count++;
