#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int* RopeCutting(int* arr, int n, int* returnSize) {
    qsort(arr, n, sizeof(int), compare);
    int* res = (int*)malloc(n * sizeof(int));
    if (res == NULL) return NULL;

    int tmpResSize = 0;
    arr[n] = 0;
    int i = 0, j = 1;

    while (1) {
        while (j < n && arr[j] == arr[i]) {
            j++;
        }
        if (j == n) {
            break;
        }
        res[tmpResSize] = n - j;
        tmpResSize++;
        i = j;
        j++;
    }
    *returnSize = tmpResSize;
    return res;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t-- > 0) {
