        if (arr == NULL) return 1;

        for (int k = 0; k < n; k++) {
            scanf("%d", &arr[k]);
        }

        int returnSize = 0;
        int* result = RopeCutting(arr, n, &returnSize);

        if (result != NULL) {
            for (int k = 0; k < returnSize; k++) {
                printf("%d", result[k]);
                if (k < returnSize - 1) {
                    printf(" ");
                }
            }
            printf("\n");
            free(result);
        }
        free(arr);
    }
    return 0;
}

