#define MAXN 100000

int ans = 0;
int *before, *after;
int n;
int *a, *b;
int d[MAXN][MAXN];
int visited[MAXN];

void tree(int d[MAXN][MAXN], int i) {
    if (d[i][0] == 0) {
        return;
    }
    for (int j = 0; d[i][j] != 0; j++) {
        int idx = d[i][j];
        for (int k = 0; d[idx][k] != 0; k++) {
            if (d[idx][k] == i) {
                d[idx][k] = 0; 
                break;
            }
        }
        tree(d, idx);
    }
}

void traverse(int d[MAXN][MAXN], int i, int a[], int b[]) {
    for (int j = 0; d[i][j] != 0; j++) {
        traverse(d, d[i][j], a, b);
    }
    ans += a[i];
    if (a[i] > 0 && b[i] != -1) {
        a[b[i] - 1] += a[i];
        before[before[0]++] = i + 1;
    } else if (a[i] > 0) {
        before[before[0]++] = i + 1;
    } else {
        after[after[0]++] = i + 1;
    }
}

void solve() {
    before = (int *)malloc((MAXN + 1) * sizeof(int));
    after = (int *)malloc((MAXN + 1) * sizeof(int));
    memset(before, 0, (MAXN + 1) * sizeof(int));
    memset(after, 0, (MAXN + 1) * sizeof(int));
    before[0] = after[0] = 0;

    scanf("%d", &n);
    a = (int *)malloc(n * sizeof(int));
    b = (int *)malloc(n * sizeof(int));

    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
    }
    for (int i = 0; i < n; i++) {
        scanf("%d", &b[i]);
    }

    int terminators[MAXN];
    int t_count = 0;
    for (int i = 0; i < n; i++) {
        if (b[i] == -1) {
            terminators[t_count++] = i;
        }
    }

    memset(d, 0, sizeof(d));
    for (int i = 0; i < n; i++) {
        d[i][0] = 0; 
        if (b[i] != -1) {
            d[i][0] = b[i] - 1; 
            d[b[i] - 1][1] = i; 
        }
    }

    for (int t = 0; t < t_count; t++) {
        tree(d, terminators[t]);
    }

    for (int t = 0; t < t_count; t++) {
        traverse(d, terminators[t], a, b);
    }

    printf("%d\n", ans);
    for (int i = after[0] - 1; i >= 1; i--) {
        printf("%d ", after[i]);
    }
    for (int i = 1; i < before[0]; i++) {
        printf("%d ", before[i]);    
    }
    printf("\n");

    free(a);
    free(b);
    free(before);
    free(after);
