#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int canWork(int* blooms, int days, int m, int k, int n) {
    int flowers = 0;
    int i = 0;
    for(i = 0; i < n; i++) {
        if(blooms[i] <= days) {
            flowers++;
        } else {
            flowers = 0;
        }
        if(flowers == k) {
            m--;
            flowers = 0;
        }
    }
    return m <= 0;
}

int solve(int m, int k, int* bloomDay, int n) {
    if(n < m * k) return -1;
    int left = 1;
    int right = 0;

    for (int i = 0; i < n; i++) {
        if(bloomDay[i] > right) {
            right = bloomDay[i];
        }
    }

    while(left < right) {
        int mid = (left + right) / 2;
        int canDo = canWork(bloomDay, mid, m, k, n);
        if(canDo) {
            right = mid;
        } else {
            left = mid + 1;
        }
    }
    return left;
}

int main() {
    int m = 3, k = 1;
    int bloomDay[] = {1, 10, 3, 10, 2}; 
    int n = sizeof(bloomDay) / sizeof(bloomDay[0]);

    int result = solve(m, k, bloomDay, n);
    printf("%d\n", result); // Output the result
    return 0;
}

#include <stdio.h>
