struct TreeNode {
    int data;
    struct TreeNode* left;
    struct TreeNode* right;
};

struct TreeNode* toSumTree(struct TreeNode* root) {
    int ll = 0, rr = 0;
    if (root == NULL) {
        return NULL;
    }

    if (root->left != NULL) {
        int l = root->left->data;
        toSumTree(root->left);
        ll = l + root->left->data;
    }

    if (root->right != NULL) {
        int r = root->right->data;
        toSumTree(root->right);
        rr = r + root->right->data;
    }

    root->data = ll + rr;
    return root;
}

struct TreeNode* createNode(int data) {
    struct TreeNode* newNode = (struct TreeNode*)malloc(sizeof(struct TreeNode));
    newNode->data = data;
    newNode->left = NULL;
    newNode->right = NULL;
    return newNode;
}

void freeTree(struct TreeNode* root) {
    if (root != NULL) {
        freeTree(root->left);
        freeTree(root->right);
        free(root);
    }
}

void printTree(struct TreeNode* root) {
    if (root == NULL) return;
    printf("%d ", root->data);
    printTree(root->left);
    printTree(root->right);
}

int main() {
    struct TreeNode* root = createNode(10);
    root->left = createNode(5);
    root->right = createNode(15);
    root->left->left = createNode(3);
    root->left->right = createNode(7);
    root->right->right = createNode(20);

    printf("Original Tree: ");
    printTree(root);
    printf("\n");

    toSumTree(root);

    printf("Sum Tree: ");
    printTree(root);
    printf("\n");

    freeTree(root);
    return 0;
}

