void _subsetSums(int ind, int *arr, int N, int **ans, int *summ, int *count) {
    if (ind == N) {
        (*ans)[*count] = *summ;
        (*count)++;
        return;
    }

    *summ += arr[ind];
    _subsetSums(ind + 1, arr, N, ans, summ, count);

    *summ -= arr[ind];
    _subsetSums(ind + 1, arr, N, ans, summ, count);
}

int* subsetSums(int *arr, int N, int *size) {
    int *ans = (int *)malloc(1 << N * sizeof(int)); // 2^N possible sums
    int summ = 0;
    int count = 0;

    _subsetSums(0, arr, N, &ans, &summ, &count);

    *size = count;
    return ans;
}

