int check(int* a, int size) {
	int first = 0, second = 0;
	int first_result = 0; // false
	for (int i = 0; i < size; i++) {
		int el = a[i];
		if (el > first) {
			first = el;
		} else if (el > second) {
			second = el;
		} else {
			first_result = 1; // true
			break;
		}
	}

	first = 2147483648; // 2**32
	second = 2147483648;
	int second_result = 0; // false
	for (int i = 0; i < size; i++) {
		int el = a[i];
		if (el < first) {
			first = el;
		} else if (el < second) {
			second = el;
		} else {
			second_result = 1; // true
			break;
		}
	}
	return first_result || second_result;
}

int solve(int* a, int len) {
	int result = 2 * len - 1;
	for (int i = 0; i < len - 2; i++) {
		if (!check(&a[i], 3)) {
			result += 1;
		}
	}
	for (int i = 0; i < len - 3; i++) {
		if (!check(&a[i], 4)) {
			result += 1;
		}
	}
	return result;
}

