int checkArray(int* nums, int n, int k) {
    int tot = 0;
    for(int i = 0; i < n; i++) {
        tot += nums[i];
    }

    if(tot % k != 0) {
        return 0; // false
    }

    int* delta = (int*) malloc((2 * n) * sizeof(int));
    for(int i = 0; i < 2 * n; i++) {
        delta[i] = 0;
    }

    int t = 0;

    for(int i = 0; i < n; i++) {
        t += delta[i];

        if(nums[i] < t) {
            free(delta);
            return 0; // false
        }

        delta[i + k] -= nums[i] - t;
        t = nums[i];
    }

    for(int i = n; i < 2 * n; i++) {
        t += delta[i];

        if(t != 0) {
            free(delta);
            return 0; // false
        }
    }

    free(delta);
    return 1; // true
}

