#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int n, k;
    char s[1001]; // Assuming the max length of input string s is 1000
    int tmp = 0;
    int counts[256] = {0}; // For ASCII characters, using an array to store counts
    int F[1001]; // to store counts for sorting later
    int ans = 0;

    // Read n and k from input
    scanf("%d %d", &n, &k);
    // Read string s
    scanf("%s", s);

    // Count occurrences of each character
    for (int i = 0; s[i] != '\0'; i++) {
        counts[(int)s[i]]++;
    }

    // Fill F array with counts
    for (int j = 0; j < 256; j++) {
        if (counts[j] > 0) {
            F[tmp] = counts[j];
            tmp++;
        }
    }

    // Sort F array in descending order (simple bubble sort)
    for (int m = 0; m < tmp - 1; m++) {
        for (int l = 0; l < tmp - m - 1; l++) {
            if (F[l] < F[l + 1]) {
                int swap = F[l];
                F[l] = F[l + 1];
                F[l + 1] = swap;
            }
        }
    }

    // Calculate the answer
    for (int x = 0; x < tmp; x++) {
        int minVal = (k < F[x]) ? k : F[x];
        ans += minVal * minVal;
        k -= minVal;
        if(k <= 0) break; // If k is exhausted, no need to continue
    }

    // Print the final answer
    printf("%d\n", ans);
    return 0;
}

