char *findSmallestRegion(char regions[MAX_REGIONS][MAX_REGION_LEN][MAX_NAME_LEN], int numRegions, char* region1, char* region2) {
    char f1[MAX_NAME_LEN] = "";
    char f2[MAX_NAME_LEN] = "";

    for(int i = 0; i < numRegions; i++) {
        int found1 = 0, found2 = 0;
        for(int j = 0; j < MAX_REGIONS; j++) {
            if(strcmp(regions[i][j], "") == 0) break;

            if(strcmp(regions[i][j], region1) == 0) {
                strcpy(f1, regions[i][0]);
                found1 = 1;
            }
            if(strcmp(regions[i][j], region2) == 0) {
                strcpy(f2, regions[i][0]);
                found2 = 1;
            }

            if(found1 && found2) break;
        }

        if(f1[0] != '\0' && f2[0] != '\0') break;
    }

    if(strcmp(f1, f2) == 0) {
        char *result = malloc(strlen(f1) + 1);
        strcpy(result, f1);
        return result;
    } else {
        return findSmallestRegion(regions, numRegions, f1, f2);
    }
}

