#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAXN 1000

int cost[MAXN * MAXN];
int occ[MAXN * MAXN];

void init_cost(int n) {
    for (int i = 0 ; i < n ; i++) {
        for (int j = 0; j < n ; j++) {
            cost[i * n + j] = (i < j ? (i < (n - i - 1) ? i : (n - i - 1)) : (j < (n - j - 1) ? j : (n - j - 1)));
        }
    }
}

void process_next(int n, int *q, int *front, int *back, int ij) {
    int i = ij / n ; 
    int j = ij % n ;

    int tmpIj = (i + 1) * n + j;
    if (i + 1 < n && j >= 0 && j < n) {
        if (!occ[ij] && cost[tmpIj] > cost[ij]) {
            cost[tmpIj] = cost[ij];
            q[(*back)++] = tmpIj;
        } 
        else if (cost[tmpIj] > cost[ij] + 1) {
            cost[tmpIj] = cost[ij] + 1;
            q[(*back)++] = tmpIj;
        }
    }

    tmpIj = (i - 1) * n + j;
    if (i - 1 >= 0 && j >= 0 && j < n) {
        if (!occ[ij] && cost[tmpIj] > cost[ij]) {
            cost[tmpIj] = cost[ij];
            q[(*back)++] = tmpIj;
        } 
        else if (cost[tmpIj] > cost[ij] + 1) {
            cost[tmpIj] = cost[ij] + 1;
            q[(*back)++] = tmpIj;
        }
    }

    tmpIj = i * n + (j + 1);
    if (i >= 0 && j + 1 < n) {
        if (!occ[ij] && cost[tmpIj] > cost[ij]) {
            cost[tmpIj] = cost[ij];
            q[(*back)++] = tmpIj;
        } 
        else if (cost[tmpIj] > cost[ij] + 1) {
            cost[tmpIj] = cost[ij] + 1;
            q[(*back)++] = tmpIj;
        }
    }

    tmpIj = i * n + (j - 1);
    if (i >= 0 && j - 1 >= 0) {
        if (!occ[ij] && cost[tmpIj] > cost[ij]) {
            cost[tmpIj] = cost[ij];
            q[(*back)++] = tmpIj;
        } 
        else if (cost[tmpIj] > cost[ij] + 1) {
            cost[tmpIj] = cost[ij] + 1;
            q[(*back)++] = tmpIj;
        }
    }
}

int main() {
    int n;
    scanf("%d", &n);
    int p[MAXN];

    for (int i = 0; i < n ; i++) {
        scanf("%d", &p[i]);
        p[i]--;
    }

    memset(cost, 0, sizeof(cost));
    memset(occ, 1, sizeof(occ));

    init_cost(n);

    int ans = 0;
    for (int start = 0 ; start < n ; start++) {
        int idx = p[start];
        ans += cost[idx];
        occ[idx] = 0;

        int queue[MAXN * MAXN];
        int front = 0, back = 0;
        queue[back++] = idx;

        while (front < back) {
            int ij = queue[front++];
            process_next(n, queue, &front, &back, ij);
        }
    }

    printf("%d\n", ans);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

typedef struct {
    double value;
    int index;
} Pair;

int cmp(const void *a, const void *b) {
    Pair *pairA = (Pair *)a;
    Pair *pairB = (Pair *)b;
    if (pairA->value < pairB->value) return -1;
    if (pairA->value > pairB->value) return 1;
    return pairA->index - pairB->index;
}

int main() {
    int n;
    scanf("%d", &n);

    int l, r;
    scanf("%d %d", &l, &r);

    Pair ly[n];
    Pair ry[n];

    for (int i = 0; i < n; i++) {
        int k, m;
        scanf("%d %d", &k, &m);

        double l_tmp = k * (l + 1e-8) + m; // l + 10 ** (-8)
        double r_tmp = k * (r - 1e-8) + m; // r - 10 ** (-8)

        ly[i].value = l_tmp;
        ly[i].index = i;
        ry[i].value = r_tmp;
        ry[i].index = i;
    }

    qsort(ly, n, sizeof(Pair), cmp);
    qsort(ry, n, sizeof(Pair), cmp);

    int found = 0;  // to check if pairs are different
    for (int i = 0; i < n; i++) {
        if (ly[i].index != ry[i].index) {
            printf("YES\n");
            found = 1;
            break;
        }
    }

    if (found == 0) {
        printf("NO\n");
