int isBeau(int x) {
    char binary[32];
    int len = 0;
    while (x > 0) {
        binary[len++] = (x % 2) + '0';
        x = x / 2 ; 
    }
    binary[len] = '\0';

    for (int j = 0 ; j < len / 2 ; j++) {
        binary[j] = binary[len - j - 1];
    }

    if (len % 2 == 0) {
        return 0;
    } else {
        int half = len / 2 + 1;
        for (int k = 0 ; k < half; k++) {
            if (binary[k] != '1') {
                return 0;
            }
        }
        for (int m = half ; m < len; m++) {
            if (binary[m] != '0') {
                return 0;
            }
        }
    }
    return 1;
}

