typedef struct {
    int modulo;
} ModInt;

typedef struct {
    FILE *writer;
} OutputWriter;

typedef struct {
    unsigned char buf[1024];
    int curChar;
    int numChars;
    FILE *stream;
} InputReader;

ModInt* createModInt(int m) {
    ModInt *modInt = malloc(sizeof(ModInt));
    modInt->modulo = m;
    return modInt;
}

int add(ModInt *mod, int x, int y) {
    x += y;
    if (x >= mod->modulo) x -= mod->modulo;
    return x;
}

int multiply(ModInt *mod, int x, int y) {
    return (int)((x * 1LL * y) % mod->modulo);
}

OutputWriter* createOutputWriter(FILE *outputStream) {
    OutputWriter *out = malloc(sizeof(OutputWriter));
    out->writer = outputStream;
    return out;
}

void println(OutputWriter *out, const char *str) {
    fputs(str, out->writer);
    fputc('\n', out->writer);
}

void closeOutputWriter(OutputWriter *out) {
    free(out);
}

InputReader* createInputReader(FILE *stream) {
    InputReader *in = malloc(sizeof(InputReader));
    in->stream = stream;
    in->curChar = 0;
    in->numChars = 0;
    return in;
}

int read(InputReader *in) {
    if (in->numChars == -1) {
        return -1;
    }
    if (in->curChar >= in->numChars) {
        in->curChar = 0;
        in->numChars = fread(in->buf, 1, sizeof(in->buf), in->stream);
        if (in->numChars <= 0) {
            return -1;
        }
    }
    return in->buf[in->curChar++];
}

int nextInt(InputReader *in) {
    int c = read(in);
    while (c != -1 && (c == ' ' || c == '\n' || c == '\r' || c == '\t')) c = read(in);

    int sgn = 1;
    if (c == '-') {
        sgn = -1;
        c = read(in);
    }

    int res = 0;
    do {
        if (c < '0' || c > '9') {
            // Error handling
            fprintf(stderr, "InputMismatchException\n");
            exit(1);
        }
        res = res * 10 + (c - '0');
        c = read(in);
    } while (c != -1 && ! (c == ' ' || c == '\n' || c == '\r' || c == '\t'));
    return res * sgn;
}

void solve(int testNumber, InputReader *in, OutputWriter *out) {
    int n = nextInt(in);
    int m = nextInt(in);
    ModInt *mod = createModInt(m);
    int *factorial = malloc((n + 1) * sizeof(int));
    factorial[0] = n;

    for (int i = 1; i < n; i++) {
        factorial[i] = multiply(mod, factorial[i - 1], n - i);
    }

    int middle = (n * (n - 1)) / 2;
    int *dp = calloc(n * (n - 1) + 1, sizeof(int));
    dp[middle] = 1;

    int answer = 0;

    for (int i = n - 1; i >= 0; i--) {
        int c = n - 1 - i;
        int *temp = malloc((n * (n - 1) + 1) * sizeof(int));
        memcpy(temp, dp, (n * (n - 1) + 1) * sizeof(int));
        memset(dp, 0, (n * (n - 1) + 1) * sizeof(int));

        int limit = (c * (c - 1)) / 2;
        int count = 0;

        for (int cur = -c; cur < 0; cur++) {
            int pairs = c + cur + 1;
            for (int j = middle - cur + 1; j <= middle + limit; j++) {
                count = add(mod, count, multiply(mod, temp[j], pairs));
            }
        }

        answer = add(mod, answer, multiply(mod, count, i == 0 ? 1 : factorial[i - 1]));

        for (int j = middle - limit; j <= middle + limit; j++) {
            for (int cur = -c; cur <= c; cur++) {
                int pairs = c - abs(cur) + 1;
                dp[j + cur] = add(mod, dp[j + cur], multiply(mod, pairs, temp[j]));
            }
        }

        free(temp);
    }

    printf("%d\n", answer);
    free(factorial);
    free(mod);
}

