struct Problem {
    int n;
    int k;
    char *a;
};

void initProblem(struct Problem *p, int n, int k, char *s) {
    p->n = n;
    p->k = k;
    p->a = (char *)malloc(n + 1);
    strcpy(p->a, s);
}

void freeProblem(struct Problem *p) {
    free(p->a);
}

char *solve(struct Problem *p) {
    int le = 0;
    int ri = 0;
    int count0 = 0, count1 = 0, countq = 0;

    while (ri < p->k) {
        if (p->a[ri] == '0') count0++;
        else if (p->a[ri] == '1') count1++;
        else if (p->a[ri] == '?') countq++;
        ri++;
    }

    while (le <= p->n - p->k) {
        if (count0 * 2 > p->k || count1 * 2 > p->k) {
            return "NO";
        }

        if (ri < p->n && p->a[le] != p->a[ri]) {
            if (p->a[le] == '0') count0--;
            else if (p->a[le] == '1') count1--;
            else if (p->a[le] == '?') countq--;

            if (p->a[ri] == '?') {
                p->a[ri] = p->a[le];
            } else if (p->a[le] != '?') {
                return "NO";
            }

            if (p->a[ri] == '0') count0++;
            else if (p->a[ri] == '1') count1++;
            else if (p->a[ri] == '?') countq++;
        }

        ri++;
        le++;
    }

    return "YES";
}

