            scanf("%d", &aa[j]);
        }

        for (j = 0; j < aa[0]; j++) {
            scanf("%d", &bb[j]);
        }

        // Sort bb array using a simple bubble sort
        for (int k = 0; k < aa[0]; k++) {
            for (int l = 0; l < aa[0] - k - 1; l++) {
                if (bb[l] > bb[l + 1]) {
                    int tmp = bb[l];
                    bb[l] = bb[l + 1];
                    bb[l + 1] = tmp;
                }
            }
        }

        num1 = aa[1];
        num2 = aa[2];
        count = 0;

        for (j = 0; j < aa[0]; j++) {
            kk = bb[j];
            cc = kk / 2;

            if (cc <= num2) {
                kk -= cc * 2;
                if (num1 >= kk) {
                    count += 1;
                    num1 -= kk;
                    num2 -= cc;
                }
            } else {
                kk -= num2 * 2;
                num2 = 0;
                if (num1 >= kk) {
                    count += 1;
                    num1 -= kk;
                }
            }
        }

        printf("%d\n", count);

        free(bb); // Free memory
    }

