struct Node {
    int data;
    struct Node* next;
};

struct Node* segregate(struct Node* head) {
    struct Node* temp = head;
    int* l = malloc(sizeof(int) * 100); // Assume max length 100 for simplicity
    int n = 0;

    while (temp != NULL) {
        l[n] = temp->data;
        n++;
        temp = temp->next;
    }

    // Simple bubble sort for l
    for (int i = 0; i < n-1; i++) {
        for (int j = 0; j < n-i-1; j++) {
            if (l[j] > l[j + 1]) {
                int tmp = l[j];
                l[j] = l[j + 1];
                l[j + 1] = tmp;
            }
        }
    }

    struct Node* t = head;
    int index = 0;
    while (t != NULL) {
        t->data = l[index];
        index++;
        t = t->next;
    }

    free(l); // Freeing memory for l
    return head;
}

