#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

#define N 20000005 

int primes[1000000];
bool isprime[N] = {0};
int prime_count = 0;

void sieve() {
    for (int i = 2; i < N; i++) {
        isprime[i] = true;
    }

    for (int i = 2; i < N; i++) {
        if (isprime[i]) {
            primes[prime_count++] = i;
        }
        for (int j = 0; j < prime_count; j++) {
            if (i * primes[j] >= N) break;
            isprime[i * primes[j]] = false;
            if (i % primes[j] == 0) break;
        }
    }
}

int* get_factors(int n, int* size) {
    int* res = malloc(N * sizeof(int));
    *size = 0;
    int x = n;

    for (int i = 0; i < prime_count; i++) {
        if (primes[i] * primes[i] > x) break;
        while (x % primes[i] == 0) {
            x /= primes[i];
            res[(*size)++] = primes[i];
        }
    }
    if (x > 1) res[(*size)++] = x;

    return res;
}

int power(int exp) {
    int result = 1;
    for (int i = 0; i < exp; i++) {
        result *= 2;
    }
    return result;
}

int get_count(int n, int* memo1) {
    if (memo1[n] != -1) return memo1[n];
    int res = 0;
    int x = n;

    for (int i = 0; i < prime_count; i++) {
        if (primes[i] * primes[i] > x) break;
        if (x % primes[i] == 0) res++;
        while (x % primes[i] == 0) {
            x /= primes[i];
        }
    }
    if (x > 1) res++;
    memo1[n] = power(res);
    return memo1[n];
}

int main() {
    sieve();
    int memo1[N];
    memset(memo1, -1, sizeof(memo1));

    int t;
    scanf("%d", &t);

    while (t--) {
        int c, d, x;
        scanf("%d %d %d", &c, &d, &x);
        int ans = 0;

        int size;
        int* factors = get_factors(x, &size);

        for (int i = 0; i < size; i++) {
            int g = factors[i];
            if (((x / g) + d) % c == 0) {
                int r = ((x / g) + d) / c;
                ans += get_count(r, memo1);
            }
        }
        free(factors);
        printf("%d\n", ans);
    }

    return 0;
}

