#include <stdio.h>
#include <stdlib.h>

#define MAX_SIZE 10000

typedef struct Node {
    int data;
    struct Node* next;
} Node;

typedef struct Deque {
    Node* front;
    Node* rear;
} Deque;

Deque* createDeque() {
    Deque* dq = (Deque*)malloc(sizeof(Deque));
    dq->front = NULL;
    dq->rear = NULL;
    return dq;
}

void addFirst(Deque* dq, int value) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->data = value;
    newNode->next = dq->front;
    dq->front = newNode;
    if (dq->rear == NULL) {
        dq->rear = newNode;
    }
}

void addLast(Deque* dq, int value) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->data = value;
    newNode->next = NULL;
    if (dq->rear) {
        dq->rear->next = newNode;
    }
    dq->rear = newNode;
    if (dq->front == NULL) {
        dq->front = newNode;
    }
}

void printDeque(Deque* dq) {
    Node* current = dq->front;
    while (current != NULL) {
        printf("%d ", current->data);
        current = current->next;
    }
    printf("\n");
}

void freeDeque(Deque* dq) {
    Node* current = dq->front;
    while (current != NULL) {
        Node* tmp = current;
        current = current->next;
        free(tmp);
    }
    free(dq);
}

int main() {
    int t;
    scanf("%d", &t);
    for (int p = 0; p < t; p++) {
        int n;
        scanf("%d", &n);
        Deque* list1 = createDeque();

        if (n > 0) {
            int firstValue;
            scanf("%d", &firstValue);
            addLast(list1, firstValue);
        }

        for (int i = 1; i < n; i++) {
            int k;
            scanf("%d", &k);
            if ( k < list1->front->data) {
                addFirst(list1, k);
            } else {
                addLast(list1, k);
            }
        }

        printDeque(list1);
        freeDeque(list1);
    }
    return 0;
}

