typedef struct {
    int number;
    int count;
} ElementCount;

void addElement(ElementCount *arr, int *size, int num) {
    for (int i = 0; i < *size; i++) {
        if (arr[i].number == num) {
            arr[i].count++;
            return;
        }
    }
    arr[*size].number = num;
    arr[*size].count = 1;
    (*size)++;
}

int main() {
    int t;
    scanf("%d", &t); // Read number of test cases

    while (t--) {
        int n;
        scanf("%d", &n); // Read size of array
        int *data = (int *)malloc(n * sizeof(int));
        ElementCount counts[1000]; 
        int countSize = 0;

        for (int i = 0; i < n; i++) {
            scanf("%d", &data[i]); // Read elements
            addElement(counts, &countSize, data[i]); // Count elements
        }

        long long c = 0;
        int odd[1000], even[1000];
        int oddIndex = 0, evenIndex = 0;

        for (int i = 0; i < countSize; i++) {
            if (counts[i].number % 2 == 1) {
                odd[oddIndex++] = counts[i].number;
            } else {
                even[evenIndex++] = counts[i].number;
            }
        }

        // Calculate pairs for odd and even
        for (int i = 0; i < 2; i++) {
            ElementCount *list = (i == 0) ? (ElementCount *)odd : (ElementCount *)even;
            int listSize = (i == 0) ? oddIndex : evenIndex;

            for (int idx = 0; idx < listSize; idx++) {
                int li = list[idx];
                int x = 0;
                for (int k = 0; k < countSize; k++) {
                    if (counts[k].number == li) {
                        x = counts[k].count;
                        break;
                    }
                }
                c += (long long)x * (x - 1) / 2;

                for (int j = 0; j < idx; j++) {
                    int lj = list[j];
                    int mid = (li + lj) / 2;

                    for (int k = 0; k < countSize; k++) {
                        if (counts[k].number == mid) {
                            c += (long long)x * counts[k].count;
                            break;
                        }
                    }
                }
            }
        }

        printf("%lld\n", c);
        free(data);
    }

    return 0;
}

