#include <stdio.h>
#include <stdlib.h>

int cmpfunc(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int find_height(int* tree, int n, int k) {
    qsort(tree, n, sizeof(int), cmpfunc);
    int low = tree[0]; 
    int high = tree[n - 1];
    if(n == 1) {
        return tree[0] - k;
    }

    while(low <= high) {
        int mid = (high + low) / 2;
        int sum = 0;
        for(int i = 0; i < n; i++) {
            if(mid < tree[i]) {
                sum += tree[i] - mid;
            }
        }

        if(k == sum) {
            return mid;
        } else if(k < sum) {
            high = mid - 1; 
        } else if(k > sum) {
            low = mid + 1; 
        }
    }
    return -1;
}

int main() {
    int n = 5; 
    int k = 7; 
    int tree[] = {4, 1, 2, 5, 3};

    int result = find_height(tree, n, k);
    printf("%d\n", result);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int minOperationsMaxProfit(int* customers, int customersSize, int boardingCost, int runningCost) {
    int profit = 0, people = 0, res = 0, board = 0;
    int minPeople = runningCost / boardingCost;

    int totalCustomers = 0;
    for (int i = 0; i < customersSize; i++) {
        totalCustomers += customers[i];
    }

    if (totalCustomers < minPeople) {
        return -1;
    }

    for (int i = 0; i < customersSize; i++) {
        people += customers[i];
        res += 1;

        if (people >= 4) {
            people -= 4;
            board += 4;
        } else {
            board += people;
            people = 0;
        }
    }

    int count = 0, m = 0;
    count = people / 4;
    m = people % 4;
    board += count * 4;

    if (m > minPeople) {
        count += 1;
        board += m;
    }

    res += count;
    profit = board * boardingCost - res * runningCost;

    if (profit >= 0) {
        return res;
    } else {
        return -1;
    }
}

int main() {
    int customers[] = {8, 3};
    int boardingCost = 5;
    int runningCost = 2;
    int result = minOperationsMaxProfit(customers, 2, boardingCost, runningCost);
    printf("%d\n", result);
    return 0;
}

