#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>

char* reformatString(const char* S, int K) {
    char tmp[10000]; // Temporary buffer to hold concatenated parts
    int length = 0;
    int pos = 0;

    // Remove dashes and calculate total length
    for (int i = 0; S[i] != '\0'; i++) {
        if (S[i] != '-') {
            tmp[length++] = S[i];
        }
    }
    tmp[length] = '\0';

    // Convert everything to uppercase
    for (int i = 0; i < length; i++) {
        tmp[i] = toupper(tmp[i]);
    }

    char* result = (char*)malloc(10000); // We've gotta allocate memory for the result
    if (!result) return NULL;

    int firstStrLength = length % K; 

    if (firstStrLength > 0) {
        strncpy(result, tmp, firstStrLength);
        result[firstStrLength] = '\0'; // Making sure it's null-terminated
        pos = firstStrLength;
    } else {
        result[0] = '\0'; // Just in case we need to start with an empty string
    }

    // Add dashes for K parts
    for (int i = 0; i < length / K; i++) {
        if (pos > 0) {
            result[pos++] = '-';
        }

        strncpy(result + pos, tmp + firstStrLength + i * K, K);
        pos += K;
    }

    result[pos] = '\0'; // Final null-termination

    // If there's no leading segment, need to remove the first dash
    if (firstStrLength == 0 && pos > 0) {
        memmove(result, result + 1, strlen(result)); // Shift left to remove first dash
    }

    return result; // Return the formatted string
}

int main() {
    const char* testString = "5-Fg-gh-216";
    int K = 2;

    char* formatted = reformatString(testString, K);

    printf("%s\n", formatted);

    free(formatted); // Don't forget to free the allocated memory

    return 0;
}

