int minCharacters(char* a, char* b) {
    int times[1000][2] = {0};

    for (int i = 0; i < strlen(a); i++) {
        times[(int)a[i]][0]++;
    }

    for (int i = 0; i < strlen(b); i++) {
        times[(int)b[i]][1]++;
    }

    int t1 = 0 ;
    int t2 = 0 ;
    int res = INT_MAX;

    for (int first = 'a'; first < 'z'; first++) {
        t1 += times[first][0];
        t2 += times[first][1];
        int tmp1 = 0 ; int tmp2 = 0 ;
        tmp1 = a.length() - t1 ;
        tmp2 = t2 ;
        res = (tmp1 < res) ? tmp1 : res ;
        res = (tmp2 < res) ? tmp2 : res ;

        int tmp3 = b.length() - t2 ;
        res = (tmp3 < res) ? tmp3 : res ;
    }

    for (int first = 'a'; first <= 'z'; first++) {
        int combined = strlen(a) + strlen(b) - times[first][0] - times[first][1];
        if (combined < res) {
            res = combined ;
        }
    }

    return res;
}

