void complexNumberMultiply(char *a, char *b, char *result)
{
	int i, temp;
	int a1, a2, b1, b2;

	for(i = 0; a[i] != '+'; i++);
	a1 = str2num(strndup(a, i));
	temp = i + 1;
	for(i; a[i] != 'i'; i++);
	a2 = str2num(strndup(a + temp, i - temp));

	for(i = 0; b[i] != '+'; i++);
	b1 = str2num(strndup(b, i));
	temp = i + 1;
	for(i; b[i] != 'i'; i++);
	b2 = str2num(strndup(b + temp, i - temp));

	int a3 = a1 * b1 - a2 * b2;
	int b3 = a1 * b2 + a2 * b1;

	char strA[20], strB[20];
	int2str(a3, strA);
	int2str(b3, strB);

	strcpy(result, strA);
	strcat(result, "+");
	strcat(result, strB);
	strcat(result, "i");
}

