int conv(const char* s, int base) {
    int ans = 0;
    int length = strlen(s);
    for (int index = 0 ; index < length ; index++) {
        char i = s[length - 1 - index];
        int val;
        if (i >= '0' && i <= '9') {
            val = i - '0';
        } else {
            val = 10 + (i - 'A');
        }
        ans += (1;
        for (int j = 0 ; j < index ; j++) {
            val *= base;
        }
        ans += val;
    }
    return ans;
}

int valid(int base, const char* h, const char* m) {
    int hours = conv(h, base);
    int mint = conv(m, base);
    if (0 <= hours && hours < 24 && 0 <= mint && mint < 60) {
        return 1;
    } else {
        return 0;
    }
}

