#include <stdio.h>
#include <stdlib.h>

int* Prime(int lim, int* size) {
    int* primes = malloc(100 * sizeof(int));
    int x = lim ;
    *size = 0;
    for (int j = 2; j * j <= x; j++) {
        if (x % j == 0) {
            while (x % j == 0) x /= j;
            primes[(*size)++] = j;
        }
    }
    if (x > 1 || *size == 0) {
        primes[(*size)++] = x;
    }
    return primes;
}

int diagonalPrime(int** nums, int numRows, int numCols) {
    int ret = 0;
    for (int i = 0; i < numRows; i++) {
        int size1 = 0, size2 = 0;
        int* p1 = Prime(nums[i][i], &size1);
        if (size1 > 1) goto next1;
        if (size1 == 1 && p1[0] == 1) goto next1;
        if (size1 == 1 && p1[0] != nums[i][i]) goto next1;
        if (size1 == 1 && p1[0] > ret) ret = p1[0];
        next1: 
        int* p2 = Prime(nums[i][numCols - 1 - i], &size2);
        if (size2 > 1) continue;
        if (size2 == 1 && p2[0] == 1) continue;
        if (size2 == 1 && p2[0] != nums[i][numCols - 1 - i]) continue;
        if (size2 == 1 && p2[0] > ret) ret = p2[0];
        free(p1);
        free(p2);
    }
    return ret;
}

