    int *a = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
    }

    int *r = (int *)malloc(n * sizeof(int));
    int r_size = 0;
    int d[MAX] = {0}; // frequency dictionary for counting

    qsort(a, n, sizeof(int), cmpfunc);

    for (int i = 0; i < n; i++) {
        int found = 0;
        for (int j = 0; j < r_size; j++) {
            if (r[j] == a[i]) {
                found = 1;
                break;
            }
        }
        if (!found) {
            r[r_size] = a[i];
            r_size++;
        }
    }

    if (n == r_size) {
        printf("0\n");
        free(a);
        free(r);
        return 0;
    }

    int k = 0;
    int c = 0;

    for (int i = 0; i < r_size; i++) {
        for (int j = 0; j < n; j++) {
            if (r[i] == a[j]) {
                d[r[i]]++;
            }
        }
    }

    for (int i = 0; i < r_size; i++) {
        if (d[r[i]] > 1) {
            k = d[r[i]] - 1;
            int t = 0;
            for (int j = r[i] + 1; j < MAX; j++) {
                if (t == k) {
                    break;
                }
                int is_present = 0;
                for (int m = 0; m < r_size; m++) {
                    if (r[m] == j) {
                        is_present = 1;
                        break;
                    }
                }
                if (!is_present) {
                    r[r_size] = j;
                    r_size++;
                    c += abs(j - r[i]);
                    t++;
                }
            }
        }
    }

    printf("%d\n", c);

    free(a);
    free(r);
    return 0;
}

