#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int *p;
    int *rank;
    int n;
} UnionFind;

UnionFind* create_union_find(int n) {
    UnionFind* uf = malloc(sizeof(UnionFind));
    uf->p = malloc(n * sizeof(int));
    uf->rank = malloc(n * sizeof(int));
    uf->n = n;
    for (int i=0; i<n; i++) {
        uf->p[i] = i;
        uf->rank[i] = 0;
    }
    return uf;
}

int find_root(UnionFind* uf, int x) {
    if (x != uf->p[x]) {
        uf->p[x] = find_root(uf, uf->p[x]);
    }
    return uf->p[x];
}

int is_same(UnionFind* uf, int x, int y) {
    return find_root(uf, x) == find_root(uf, y);
}

void unite(UnionFind* uf, int x, int y) {
    int u = find_root(uf, x);
    int v = find_root(uf, y);
    if (u == v) return;
    if (uf->rank[u] < uf->rank[v]) {
        uf->p[u] = v;
    } else {
        uf->p[v] = u;
        if (uf->rank[u] == uf->rank[v]) {
            uf->rank[u]++;
        }
    }
}

int main() {
    int N, K, L;
    scanf("%d %d %d", &N, &K, &L);
    UnionFind* uf1 = create_union_find(N);
    UnionFind* uf2 = create_union_find(N);

    for (int i=0; i<K; i++) {
        int p, q;
        scanf("%d %d", &p, &q);
        p = p - 1 ; q = q - 1 ;
        unite(uf1, p, q);
    }

    for (int i=0; i<L; i++) {
        int r, s;
        scanf("%d %d", &r, &s);
        r = r - 1 ; s = s - 1 ;
        unite(uf2, r, s);
    }

    int* count = calloc(N * N, sizeof(int)); 
    for (int i=0; i<N; i++) {
        int u = find_root(uf1, i);
        int v = find_root(uf2, i);
        count[u * N + v]++;
    }

    for (int i=0; i<N; i++) {
        int u = find_root(uf1, i);
        int v = find_root(uf2, i);
        printf("%d ", count[u * N + v]);
    }

