#include <stdio.h>
#include <stdlib.h>
#include <math.h>

double calcC(int A, int B, int degree) {
    double radian = degree * M_PI / 180.0;
    double C = sqrt(A * A + B * B - 2 * A * B * cos(radian));
    return C;
}

double calcS(int A, int B, int degree) {
    double radian = degree * M_PI / 180.0;
    double S = A * B * sin(radian) / 2.0;
    return S;
}

double calcH(double S, int A) {
    double h = (S * 2) / A;
    return h;
}

int main() {
    int A, B, degree;
    printf("Enter A, B and degree: ");
    scanf("%d %d %d", &A, &B, &degree);

    double C = calcC(A, B, degree);
    double S = calcS(A, B, degree);
    double h = calcH(S, A);

    printf("%lf\n", S);
    printf("%lf\n", A + B + C);
    printf("%lf\n", h);
    return 0;
}

