#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAXN 100000
#define INF 1000000000000000000

typedef struct {
    int key;
    int value;
} Item;

Item hashTable[MAXN];
int hashCount = 0;

void insertHash(int key, int value) {
    int found = 0;
    for (int j = 0; j < hashCount; j++) {
        if (hashTable[j].key == key) {
            if (value < hashTable[j].value) {
                hashTable[j].value = value;
            }
            found = 1;
            break;
        }
    }
    if (!found) {
        hashTable[hashCount].key = key;
        hashTable[hashCount].value = value;
        hashCount++;
    }
}

int getHash(int key) {
    for (int j = 0; j < hashCount; j++) {
        if (hashTable[j].key == key) {
            return hashTable[j].value;
        }
    }
    return -1;
}

int main() {
    int n, k;
    scanf("%d %d", &n, &k);

    int la[MAXN];
    for (int i = 0; i < n; i++) {
        scanf("%d", &la[i]);
    }

    long long mini = INF;

    for (int i = 0; i < n; i++) {
        int z1 = i + 1;
        int z2 = n - i;
        int z = (z1 < z2) ? z1 : z2;

        // Insert into hash
        insertHash(la[i], z);
    }

    for (int i = 0; i < n; i++) {
        int z = k - la[i];

        if (z != la[i]) {
            int hashZ = getHash(z);
            if (hashZ != -1) {
                int hashA = getHash(la[i]);
                int ans = (hashZ > hashA) ? hashZ : hashA;
                if (ans < mini) {
                    mini = ans;
                }
            }
        }
    }

    if (mini == INF) {
        printf("-1\n");
    } else {
        printf("%lld\n", mini);
    }

    return 0;
}

