int bisect_left(int* arr, int size, int y) {
    int low = 0, high = size;
    while (low < high) {
        int mid = (low + high) / 2;
        if (arr[mid] < y) 
            low = mid + 1;
        else 
            high = mid;
    }
    return low;
}

void init_index(char *S, int **index, int *lengths, int LS) {
    for (int i = 0; i < LS; i++) {
        char s = S[i];
        if (index[s]) {
            index[s][lengths[s]] = i;
            lengths[s]++;
        }
    }
}

int main() {
    char S[100005], T[100005];
    fgets(S, sizeof(S), stdin);
    fgets(T, sizeof(T), stdin);

    S[strcspn(S, "\n")] = 0; 
    T[strcspn(T, "\n")] = 0;

    int LS = strlen(S);
    int length_t = strlen(T);

    int *index[256] = {0};
    int lengths[256] = {0};
    for (int i = 0; i < 256; i++) {
        index[i] = (int*)malloc(LS * sizeof(int));
    }

    init_index(S, index, lengths, LS);

    int x = -1;

    for (int j = 0; j < length_t; j++) {
        char t = T[j];
        int* arr = index[t];
        int arr_len = lengths[t];

        if (arr_len == 0) {
            printf("-1\n");
            return 0;
        }

        int y = (x + 1) % LS;
        int i = bisect_left(arr, arr_len, y);
        int next_x = 0;

        if (i < arr_len) {
            next_x = x + 1 + arr[i] - y;
        } else {
            next_x = x + 1 + arr[0] + LS - y;
        }

        x = next_x;
    }

    int ans = x + 1;
    printf("%d\n", ans);

    for (int i = 0; i < 256; i++) {
        free(index[i]);
    }

    return 0;
}

