typedef struct {
    int a;
    int b;
} CostPair;

int compare(const void *p1, const void *p2) {
    CostPair *cp1 = (CostPair *)p1;
    CostPair *cp2 = (CostPair *)p2;
    return cp2->a - cp1->a; // sort in descending order of a
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);

        CostPair *costs = (CostPair *)malloc(n * sizeof(CostPair));

        for (int i = 0; i < n; i++) {
            int tmpA;
            scanf("%d", &tmpA);
            costs[i].a = tmpA;
        }

        for (int i = 0; i < n; i++) {
            int tmpB;
            scanf("%d", &tmpB);
            costs[i].b = tmpB;
        }

        qsort(costs, n, sizeof(CostPair), compare);

        int petya = 0;

        for (int i = 0; i < n; i++) {
            if (petya + costs[i].b < costs[i].a) {
                petya += costs[i].b;
            } else {
                if (petya < costs[i].a) {
                    petya = costs[i].a;
                } // max is done implicitly
                break; // break out of the loop if else condition is reached
            }
        }

        printf("%d\n", petya);
        free(costs);
    }
    return 0;
}

