int* findIntersectionValues(int* nums1, int size1, int* nums2, int size2) {
    int* ans = (int*)malloc(2 * sizeof(int));
    ans[0] = 0 ; ans[1] = 0 ;

    for (int i = 0; i < size1; i++) {
        int found = 0;
        for (int j = 0; j < size2; j++) {
            if (nums1[i] == nums2[j]) {
                found = 1;
                break;
            }
        }
        if (found) {
            ans[0] += 1;
        }
    }

    for (int k = 0; k < size2; k++) {
        int found2 = 0;
        for (int l = 0; l < size1; l++) {
            if (nums2[k] == nums1[l]) {
                found2 = 1;
                break;
            }
        }
        if (found2) {
            ans[1] += 1;
        }
    }

    return ans;
}

