#include <stdio.h>
#include <stdlib.h>
#include <string.h>

struct Counter {
    int key;
    int count;
};

int cmp(const void *a, const void *b) {
    return ((struct Counter*)a)->key - ((struct Counter*)b)->key;
}

int main() {
    int testCases;
    scanf("%d", &testCases);

    while (testCases--) {
        int n;
        scanf("%d", &n);

        int *a = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &a[i]);
        }

        struct Counter *b = (struct Counter*)malloc(n * sizeof(struct Counter));
        int uniqueCount = 0;

        for (int i = 0; i < n; i++) {
            int found = 0;
            for (int j = 0; j < uniqueCount; j++) {
                if (b[j].key == a[i]) {
                    b[j].count++;
                    found = 1;
                    break;
                }
            }
            if (!found) {
                b[uniqueCount].key = a[i];
                b[uniqueCount].count = 1;
                uniqueCount++;
            }
        }

        int isValid = 1;
        int *t = (int*)malloc(uniqueCount * sizeof(int));
        for (int i = 0; i < uniqueCount; i++) {
            t[i] = b[i].key;
            if (b[i].count % 2 != 0 || b[i].key % 2 != 0) {
                isValid = 0;
            }
        }

        if (uniqueCount != n) {
            isValid = 0;
        }

        qsort(b, uniqueCount, sizeof(struct Counter), cmp);

        if (isValid) {
            int vl = 0;
            int divide_by = 2 * n;

            for (int i = 0; i < uniqueCount; i++) {
                int ck = b[i].key - vl;
                if (ck <= 0 || ck % divide_by != 0) {
                    isValid = 0;
                    break;
                }

                vl += (ck / divide_by) * 2;
                divide_by -= 2;
            }
        }

        printf("%s\n", isValid ? "YES" : "NO");

        free(a);
        free(b);
        free(t);
    }

    return 0;
}

