#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int cache[10000]; // just a large enough array
int computed[10000]; // for marking if computed or not
int helperA(int x, int count) {
    if (x < 10000 && computed[x]) {
        return cache[x] + count;
    }
    int nextX;
    if (x % 2 == 1) {
        nextX = 3 * x + 1;
    }
    else {
        nextX = x / 2;
    }
    count++;
    return helperA(nextX, count);
}

void fill_cache(int lo, int hi) {
    for (int i = lo; i <= hi; i++) {
        if (!computed[i]) {
            cache[i] = helperA(i, 0);
            computed[i] = 1;
        }
    }
}

int compare(const void *a, const void *b) {
    return (*(int *)a) - (*(int *)b);
}

int getKth(int lo, int hi, int k) {
    fill_cache(lo, hi);

    int *data = malloc((hi - lo + 1) * sizeof(int));
    int cnt = 0;

    for (int i = lo; i <= hi; i++) {
        if (computed[i]) {
            data[cnt++] = i;
        }
    }

    // Here we create a sortable array based on cache values
    int *values = malloc(cnt * sizeof(int));
    for (int j = 0; j < cnt; j++) {
        values[j] = cache[data[j]];
    }

    // Now sort based on the values obtained
    qsort(data, cnt, sizeof(int), compare);

    int result = data[k - 1];
    free(data);
    free(values);
    return result;
}

