#define MAX_D 100
#define MAX_N 100

int dp[MAX_D + 1][MAX_N]; 
int d[MAX_D]; 
int J[MAX_N][3]; 

int main() {
    int D, N;
    scanf("%d %d", &D, &N);

    for (int i = 0; i < D; i++) {
        scanf("%d", &d[i]);
    }

    for (int j = 0; j < N; j++) {
        scanf("%d %d %d", &J[j][0], &J[j][1], &J[j][2]);
    }

    // Initialize dp with -1
    for (int i = 0; i <= D; i++) {
        for (int j = 0; j < N; j++) {
            dp[i][j] = -1;
        }
    }

    int t = d[0];
    int h[MAX_N]; 
    for (int j = 0; j < N; j++) {
        h[j] = -1; 
        int a = J[j][0];
        int b = J[j][1];
        int c = J[j][2];
        if (t < a || b < t) {
            continue; 
        }
        h[j] = c; 
    }

    for (int i = 2; i <= D; i++) {
        t = d[i - 1];
        for (int j = 0; j < N; j++) {
            int a = J[j][0];
            int b = J[j][1];
            int c = J[j][2];
            if (t < a || b < t) {
                continue; 
            }

            for (int k = 0; k < N; k++) {
                if (i == 2) {
                    if (h[k] == -1) {
                        continue; 
                    }
                    dp[i][j] = max(abs(J[k][2] - c), dp[i][j]);
                }

                if (dp[i - 1][k] == -1) {
                    continue; 
                }

                dp[i][j] = max(dp[i - 1][k] + abs(J[k][2] - c), dp[i][j]);
            }
        }
    }

    int ans = 0; 
    for (int i = 0; i < N; i++) {
        ans = max(dp[D][i], ans);
    }

    printf("%d\n", ans); 
    return 0; 
}

