#define MAX_WORDS 100

int countUnique(char* arr[], int n) {
    int uniqueCount = 0; 
    for(int i = 0; i < n; i++) {
        int isUnique = 1; 
        for(int j = 0; j < i; j++) {
            if(strcmp(arr[i], arr[j]) == 0) {
                isUnique = 0; 
                break; 
            }
        }
        if(isUnique) {
            uniqueCount++;
        }
    }
    return uniqueCount; 
}

void tokenizeInput(char* input, char* output[], int* count) {
    char* token = strtok(input, " ");
    int idx = 0; 
    while(token != NULL && idx < MAX_WORDS) {
        output[idx] = token; 
        idx++; 
        token = strtok(NULL, " ");
    }
    *count = idx; 
}

