struct Solution {
    int res;
};

void dfs(int node, int parent, int* values, struct Solution* sol, int** tree, int k) {
    int val = values[node];
    for (int i = 0; i < 100; i++) {
        int child = tree[node][i];
        if (child != -1 && child != parent) {
            int child_val = dfs(child, node, values, sol, tree, k);
            if (child_val % k == 0) {
                sol->res += 1;
            } else {
                val += child_val;
            }
        }
    }
    return val;
}

int maxKDivisibleComponents(int n, int** edges, int* values, int k) {
    struct Solution sol;
    sol.res = 0;
    int** tree = (int**)malloc(n * sizeof(int*));
    for (int i = 0; i < n; i++) {
        tree[i] = (int*)malloc(100 * sizeof(int));
        for (int j = 0; j < 100; j++) {
            tree[i][j] = -1;
        }
    }

    for (int i = 0; i < n - 1; i++) {
        int u = edges[i][0];
        int v = edges[i][1];
        for (int j = 0; j < 100; j++) {
            if (tree[u][j] == -1) {
                tree[u][j] = v;
                break;
            }
        }
        for (int j = 0; j < 100; j++) {
            if (tree[v][j] == -1) {
                tree[v][j] = u;
                break;
            }
        }
    }

    int total_val = dfs(0, -1, values, &sol, tree, k);
    if (total_val % k == 0) {
        sol.res -= 1;
    }

    for (int i = 0; i < n; i++) {
        free(tree[i]);
    }
    free(tree);

    return sol.res + 2;
}

