typedef struct {
    long key;
    int value;
} HashMapLong;

typedef struct {
    int key;
    int value;
} HashMapInt;

typedef struct {
    int* keys;
    int* values;
    int size;
} TreeMap;

typedef struct {
    int* elements;
    int size;
} TreeSet;

void addToHashMapLong(HashMapLong* map, long key, int value, int* size) {
    for (int i = 0; i < *size; i++) {
        if (map[i].key == key) {
            map[i].value = value;
            return;
        }
    }
    map[*size].key = key;
    map[*size].value = value;
    (*size)++;
}

int containsKeyLong(HashMapLong* map, long key, int size) {
    for (int i = 0; i < size; i++) {
        if (map[i].key == key) return 1;
    }
    return 0;
}

void addToHashMapInt(HashMapInt* map, int key, int value, int* size) {
    for (int i = 0; i < *size; i++) {
        if (map[i].key == key) {
            map[i].value += value;
            return;
        }
    }
    map[*size].key = key;
    map[*size].value = value;
    (*size)++;
}

int getValueInt(HashMapInt* map, int key, int size) {
    for (int i = 0; i < size; i++) {
        if (map[i].key == key) return map[i].value;
    }
    return 0;
}

void sortTreeMap(TreeMap* map) {
    for (int i = 0; i < map->size - 1; i++) {
        for (int j = i + 1; j < map->size; j++) {
            if (map->values[j] > map->values[i] || (map->values[j] == map->values[i] && map->keys[j] < map->keys[i])) {
                int tmpKey = map->keys[i];
                int tmpValue = map->values[i];
                map->keys[i] = map->keys[j];
                map->values[i] = map->values[j];
                map->keys[j] = tmpKey;
                map->values[j] = tmpValue;
            }
        }
    }
}

int cmpTreeSet(const void* a, const void* b) { return (*(int*)b - *(int*)a); }

long long solve(int n, int b, int* a) {
    HashMapLong bad[200] = {0};
    int badSize = 0;
    int u, v;
    for (int i = 0; i < b; i++) {
        u = rand()%n; // this should accept input
        v = rand()%n; // this should accept input
        addToHashMapLong(bad, u + ((long)v << 32), 1, &badSize);
        addToHashMapLong(bad, v + ((long)u << 32), 1, &badSize);
    }

    HashMapInt c[200] = {0};
    int cSize = 0;
    for (int i = 0; i < n; i++) addToHashMapInt(c, a[i], 1, &cSize);

    TreeMap cnt;
    cnt.keys = malloc(cSize * sizeof(int));
    cnt.values = malloc(cSize * sizeof(int));
    cnt.size = 0;

    for (int i = 0; i < cSize; i++) {
        addToHashMapInt(cnt.keys, c[i].value, c[i].key, &cnt.size);
    }

    sortTreeMap(&cnt);

    long long max = -1;
    for (int i = 0; i < cnt.size; i++) {
        for (int j = 0; j < cnt.size; j++) {
            if (i == j) continue;

            int x = cnt.keys[i];
            int y = cnt.keys[j];
            if (!containsKeyLong(bad, x + ((long)y << 32), badSize)) {
                long long value = (long long)(x + y) * (cnt.values[i] + cnt.values[j]);
                if (value > max) {
                    max = value;
                }
            }
        }
    }

    free(cnt.keys);
    free(cnt.values);
    return max;
}

