#include <stdio.h>
#include <stdlib.h>

#define N 200005
#define mod 998244353

long long fac[N];

long long fastpow(long long x, long long y) {
    long long res = 1;
    while (y) {
        if (y & 1) res = (res * x) % mod;
        x = (x * x) % mod;
        y >>= 1;
    }
    return res;
}

void init(int mx) {
    fac[0] = 1; 
    fac[1] = 1;
    int i;
    for (i = 2; i <= mx; i++) {
        fac[i] = (fac[i - 1] * i) % mod;
    }
}

long long c(int n, int m) {
    if (m > n) return 0; 
    return fac[n] * fastpow(fac[m], mod - 2) % mod * fastpow(fac[n - m], mod - 2) % mod;
}

int main() {
    long long n, m;
    scanf("%lld %lld", &n, &m);

    if (n == 2) {
        printf("0\n");
        exit(0);
    }

    init(m);

    long long tmp1 = c(m, n - 1);
    long long tmp2 = (n - 2) % mod;
    long long tmp3 = fastpow(2, n - 3) % mod;

    long long result = tmp1 * tmp2 % mod * tmp3 % mod;

    printf("%lld\n", result);

    return 0;
}

