    }

    static int GetMostCommonCount(List<double> c) {
        if (c.Count == 0) return 0;

        var freq = new Dictionary<double, int>();
        foreach(var item in c) {
            if (freq.ContainsKey(item)) {
                freq[item]++;
            } else {
                freq[item] = 1;
            }
        }

        int maxCount = 0;
        foreach(var kvp in freq) {
            if (kvp.Value > maxCount) {
                maxCount = kvp.Value;
            }
        }

        return maxCount;
    }
}

