            if (A[i] > A[i + 1]) {
                dcounter += 1; 
            }
            if (A[i] < A[i + 1]) {
                icounter += 1; 
            }
            if (A[i] == A[i + 1]) {
                icounter += 1; 
                dcounter += 1; 
            }
        }

