class Program
{
    static void Main()
    {
        int t = int.Parse(Console.ReadLine());
        for (int i = 0; i < t; i++)
        {
            solve();
        }
    }

    static void solve()
    {
        int n = int.Parse(Console.ReadLine());
        int[] a = Console.ReadLine().Split().Select(int.Parse).ToArray();

        List<int>[] pos = new List<int>[n + 1];
        for (int i = 0; i <= n; i++) 
        {
            pos[i] = new List<int>();
        }

        for (int i = 0; i < n; i++) 
        {
            int v = a[i];
            pos[v].Add(i);
        }

        int[] ans = new int[n];
        for (int j = 0; j < n; j++) 
        {
            ans[j] = -1;
        }

        HashSet<int> q = new HashSet<int>(Enumerable.Range(0, n + 1).Where(x => pos[x].Count > 0));

        while (q.Count > 0) 
        {
            List<(int, int)> values = new List<(int, int)>();
            List<int> toremove = new List<int>();

            foreach (int i in q) 
            {
                int x = pos[i][pos[i].Count - 1];
                pos[i].RemoveAt(pos[i].Count - 1);
                values.Add((x, i));

                if (pos[i].Count == 0) 
                {
                    toremove.Add(i);
                }
            }

            foreach (int x in toremove) 
            {
                q.Remove(x);
            }

            if (values.Count == 1) 
            {
                int p = values[0].Item1;
                int v = values[0].Item2;
