class Program {
    static void Main() {
        string input = Console.ReadLine();
        var inputArr = input.Split(' ').Select(int.Parse).ToArray();
        int n = int.Parse(Console.ReadLine());
        int result = pairwise(inputArr, n);
        Console.WriteLine(result);
    }

    static int pairwise(int[] arr, int n) {
        int res = 0;
        for (int i = 0; i < arr.Length; i++) {
            int d = n - arr[i];
            if (helperContains(arr, d, i)) {
                int j = helperIndexOf(arr, d, i);
                res += i + j;
                arr[i] = n + 1; // Marking as used
                arr[j] = n + 1; // Marking as used
            }
        }
        return res;
    }

    static bool helperContains(int[] arr, int value, int startIndex) {
        for (int x = startIndex + 1; x < arr.Length; x++) {
            if (arr[x] == value) {
                return true;
            }
        }
        return false;
    }

    static int helperIndexOf(int[] arr, int value, int startIndex) {
        for (int x = startIndex + 1; x < arr.Length; x++) {
            if (arr[x] == value) {
                return x;
            }
        }
        return -1; // Just in case
    }
}

