class Program {
    static void Main() {
        var lines = Console.ReadLine().Split(new[] { '\n' }, StringSplitOptions.RemoveEmptyEntries);

        int n = int.Parse(lines[0]); // read first line for n
        var a = new int[n]; // create an array of size n

        var secondLine = lines[1].Split(); // read second line
        for (int i = 0; i < n; i++) {
            a[i] = int.Parse(secondLine[i]); // fill the a array
        }

        for (int i = 1; i < n; i++) {
            a[i] += a[i - 1]; // cumulative sum
        }

        int m = int.Parse(lines[2]); // read third line for m
        var qs = new int[m]; // create an array for queries
        var thirdLine = lines[3].Split(); // read query line
        for (int j = 0; j < m; j++) {
            qs[j] = int.Parse(thirdLine[j]); // fill the qs array
        }

        // processing each query
        for (int k = 0; k < m; k++) {
            int q = qs[k]; // query value
            int result = BinarySearch(a, q); // get index from binary search
            Console.WriteLine(result + 1); // output result
        }
    }

    static int BinarySearch(int[] arr, int x) {
        int low = 0;
        int high = arr.Length - 1;
        while (low <= high) {
            int mid = (low + high) / 2;
            if (arr[mid] < x) {
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        return low; // return insertion point
    }
}

