class Program
{
    static void Main()
    {
        Console.WriteLine("Enter a number: ");
        string input = Console.ReadLine();
        int n;
        bool isParsed = int.TryParse(input, out n);

        if (!isParsed)
        {
            Console.WriteLine("Not a valid number!");
            return;
        }

        long result = fibSum(n);
        Console.WriteLine($"Fibonacci sum for {n} is: {result}");
    }

    static long fibSum(int N)
    {
        if (N == 0)
        {
            return 0;
        }
        if (N == 1)
        {
            return 1;
        }
        long a = 0; 
        long b = 1; 
        long s = 1; 
        long mod = 1000000007;

        for (int i = 2; i <= N; i++)
        {
            long c = (a + b) % mod; 
            s = (s + c) % mod; 
            a = b; 
            b = c; 
        }

        return s;
    }
}

