        var data = input.Split(' ');
        int n = data.Length;
        int[] A = new int[n];
        for (int i = 0; i < n; i++)
        {
            A[i] = int.Parse(data[i]);
        }
        int result = lengthOfLongestAP(A, n);
        Console.WriteLine(result);
    }

    static int lengthOfLongestAP(int[] A, int n)
    {
        Dictionary<(int, int), int> dp = new Dictionary<(int, int), int>();
        int ans = 1 ;
        for (int i = 0; i < n; i++)
        {
            int vi = A[i];
            for (int j = 0; j < i; j++)
            {
                int vj = A[j];
                int dif = vi - vj;
                int tmp = 0;
                if (dp.TryGetValue((vj, dif), out int val))
                {
                    tmp = 1 + val ;
                }
                else
                {
                    tmp = 1 ;
                }

                dp[(vi, dif)] = tmp ; 
                ans = Math.Max(ans, tmp) ;
            }
        }
        return ans;
    }
}

