class Program
{
    static void Main()
    {
        string input = Console.ReadLine(); // Console input is handled here
        int[] arr = input.Split(',') // expect input like "5,3,8,6" and more
                         .Select(x => int.Parse(x.Trim())).ToArray();
        int n = arr.Length;
        CustomSort(arr, n);
        Console.WriteLine(string.Join(",", arr));
    }

    static void CustomSort(int[] arr, int n)
    {
        int[] a = new int[n / 2]; 
        int[] b = new int[n - n / 2]; 

        for (int i = 0; i < n / 2; i++)
        {
            a[i] = arr[i];
        }
        for (int i = n / 2; i < n; i++)
        {
            b[i - n / 2] = arr[i];
        }

        Sort(a);
        SortReverse(b);

        for (int i = 0; i < a.Length; i++)
        {
            arr[i] = a[i];
        }
        for (int i = 0; i < b.Length; i++)
        {
            arr[i + a.Length] = b[i];
        }
    }

    static void Sort(int[] arr)
    {
        Array.Sort(arr);
    }

    static void SortReverse(int[] arr)
    {
        Array.Sort(arr);
        Array.Reverse(arr);
    }
}

