class Program {
    static void Main() {
        var input = Console.ReadLine();
        string[] tokens = input.Split(' ');
        int n = int.Parse(tokens[0]);
        int m = int.Parse(tokens[1]);
        int k = int.Parse(tokens[2]);

        int[][] grid = new int[n][];
        for (int i = 0; i < n; i++) {
            grid[i] = new int[m];
            string[] rowTokens = Console.ReadLine().Split(' ');
            for (int j = 0; j < m; j++) {
                grid[i][j] = int.Parse(rowTokens[j]);
            }
        }

        var result = numberOfPaths(grid, k);
        Console.WriteLine(result);
    }

    static int numberOfPaths(int[][] grid, int k) {
        int ttt = 1000000007;
        int n = grid.Length;
        int m = grid[0].Length;

        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                int[] temp = new int[k];
                if (i == 0 && j == 0) {
                    temp[grid[i][j] % k] = 1;
                }
                if (i > 0) {
                    for (int pi = 0; pi < k; pi++) {
                        if (grid[i-1][j] > 0) {
                            temp[(pi + grid[i][j]) % k] += grid[i-1][j];
                        }
                    }
                }
                if (j > 0) {
                    for (int pi = 0; pi < k; pi++) {
                        if (grid[i][j-1] > 0) {
                            temp[(pi + grid[i][j]) % k] += grid[i][j-1];
                        }
                    }
                }

                for (int t = 0; t < k; t++) {
                    temp[t] %= ttt;
                }
                grid[i][j] = temp[0]; // Assuming this should store the first entry
            }
        }
        return grid[n-1][m-1];
    }
}

