        List<int> a = new List<int>();
        for (int i = 0; i < n; i++)
        {
            int tmp = -int.Parse(Console.ReadLine());
            a.Add(tmp);
        }

        List<int> x = new List<int>();
        if (a.Count > 0)
        {
            x.Add(a[0]);
        }

        for (int i = 1; i < a.Count; i++)
        {
            int current = a[i];
            int pos = FindPosition(x, current);
            if (pos == x.Count)
            {
                x.Add(current);
            }
            else
            {
                x[pos] = current;
            }
        }
        Console.WriteLine(x.Count);
    }

    static int FindPosition(List<int> sortedList, int value)
    {
        int low = 0;
        int high = sortedList.Count;

        while (low < high)
        {
            int mid = (low + high) / 2;
            if (sortedList[mid] < value)
            {
                low = mid + 1;
            }
            else
            {
                high = mid;
            }
        }
        return low;
    }
}

using System;
using System.Collections.Generic;
using System.Linq;

class Program
{
    static void Main()
    {
        // Read input
        string input = Console.ReadLine();
        string[] parts = input.Split(' ');
        int n = int.Parse(parts[0]);
        int m = int.Parse(parts[1]);
        int x = int.Parse(parts[2]);

        List<Tuple<int>> books = new List<Tuple<int>>();
        for (int i = 0; i < n; i++) {
            string line = Console.ReadLine();
            var bookParts = line.Split(' ').Select(int.Parse).ToArray();
            books.Add(new Tuple<int>(bookParts[0], bookParts[1], bookParts[2])); // assuming 3 elements
        }

        int result = doMain(n, m, x, books);
        Console.WriteLine(result);
    }

    static int doMain(int n, int m, int x, List<Tuple<int>> books) {
        var allCombos = product(n);
        int r = int.MaxValue;

        foreach (var combo in allCombos) {
            int[] effects = new int[m + 1];
            for (int i = 0; i < n; i++) {
                if (combo[i] == 1) {
                    for (int j = 0; j <= m; j++) {
                        effects[j] += books[i].Item1; // Use appropriate item based on input
                    }
                }
            }
            if (effects.Skip(1).All(e => e >= x)) {
                r = Math.Min(r, effects[0]);
            }
        }

        return r == int.MaxValue ? -1 : r;
    }

    static List<List<int>> product(int n) {
        List<List<int>> result = new List<List<int>>();
        int total = 1 << n; // 2^n
        for (int i = 0; i < total; i++) {
            List<int> combo = new List<int>();
            for (int j = 0; j < n; j++) {
                combo.Add((i >> j) & 1);
            }
            result.Add(combo);
        }
        return result;
    }
}

