class Program {
    static void Main() {
        string input = Console.ReadLine();
        int k = int.Parse(Console.ReadLine());
        int result = longestSubsequence(input, k);
        Console.WriteLine(result);
    }

    static int longestSubsequence(string s, int k) {
        int length = s.Length;
        for (int i = length; i >= 0; --i) {
            int cnt = i;
            long uwu = 0;
            for (int j = 0; j < length; ++j) {
                if (cnt == 0) break;
                if (s[j] == '0') {
                    cnt--;
                } else if ((length - j) <= cnt) {
                    if ((cnt - 1) >= 35) {
                        uwu = k + 1; 
                        break;
                    }
                    uwu += (1L << (cnt - 1));
                    cnt--;
                }
            }
            // Output debug info
            // Console.WriteLine(uwu + " " + k);
            if (uwu <= k) {
                return i;
            }
        }
        return 0;
    }
}

