    }

    static bool canBeEqual(List<int> a, List<int> b) {
        int n = a.Count;
        Dictionary<int, int> hashh = new Dictionary<int, int>();

        for(int i = 0; i < n; i++) {
            if (hashh.ContainsKey(a[i])) {
                hashh[a[i]]++;
            } else {
                hashh[a[i]] = 1;
            }
        }

        for(int i = 0; i < n; i++) {
            int val = b[i];
            if(!hashh.ContainsKey(val) || hashh[val] == 0) {
                return false;
            }
            hashh[val]--;
        }
        return true;
    }
}

