    static int CalculateLogBase2(int n)
    {
        if (n <= 0) 
        {
            Console.WriteLine("Number must be greater than 0.");
            return 0; // return 0 for invalid input
        }
        double logValue = Math.Log(n, 2);
        int logInt = (int)logValue;
        logInt += 1; // Add 1 to match original behavior
        return logInt;
    }
