            var n = int.Parse(Console.ReadLine().Trim());
            var s = Console.ReadLine().Trim();
            var d = new List<int> { 0 };
            var k = new List<int> { 0 };
            var ans = new List<int>();
            var cnt = new Dictionary<(int, int), int>();

            foreach (var c in s) {
                if (c == 'D') {
                    d.Add(d[d.Count - 1] + 1);
                    k.Add(k[k.Count - 1]);
                } 
                else {
                    k.Add(k[k.Count - 1] + 1);
                    d.Add(d[d.Count - 1]);
                }

                int a, b;
                if (d[d.Count - 1] == 0) {
                    a = 0;
                    b = 1;
                } 
                else if (k[k.Count - 1] == 0) {
                    b = 0;
                    a = 1;
                } 
                else {
                    var g = Gcd(d[d.Count - 1], k[k.Count - 1]);
                    a = d[d.Count - 1] / g;
                    b = k[k.Count - 1] / g;
                }

                int currentKey = cnt.ContainsKey((a, b)) ? cnt[(a, b)] : 0;
                ans.Add(currentKey + 1);
                if (cnt.ContainsKey((a, b))) {
                    cnt[(a, b)]++;
                } 
                else {
                    cnt[(a, b)] = 1;
                }
            }
            Console.WriteLine(string.Join(" ", ans));
        }
    }

    static int Gcd(int x, int y) {
        while (y != 0) {
            int temp = y;
            y = x % y;
            x = temp;
        }
        return x;
    }
}

