class Solution {
    public int largestMagicSquare(List<List<int>> grid_) {
        int n = grid_.Count;
        int m = grid_[0].Count;

        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                grid[i, j] = grid_[i][j];
            }
        }

        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                rs[i, j + 1] = rs[i, j] + grid[i, j];
            }
        }

        for (int j = 0; j < m; j++) {
            for (int i = 0; i < n; i++) {
                cs[j, i + 1] = cs[j, i] + grid[i, j];
            }
        }

        int ans = 1;
        for (int k = 2; k <= Math.Min(n, m); k++) {
            bool found = false;
            for (int i = 0; i + k <= n; i++) {
                for (int j = 0; j + k <= m; j++) {
                    int s = rs[i, j + k] - rs[i, j];
                    bool ok = true;
                    for (int ii = i; ii < i + k; ii++) {
                        if (rs[ii, j + k] - rs[ii, j] != s) {
                            ok = false;
                            break;
                        }
                    }
                    if (!ok) continue;

                    for (int jj = j; jj < j + k; jj++) {
                        if (cs[jj, i + k] - cs[jj, i] != s) {
                            ok = false;
                            break;
                        }
                    }
                    if (!ok) continue;

                    int diag = 0;
                    for (int ii = i, jj = j; ii < i + k; ii++, jj++) diag += grid[ii, jj];
                    if (diag != s) continue;

                    diag = 0;
                    for (int ii = i, jj = j + k - 1; ii < i + k; ii++, jj--) diag += grid[ii, jj];
                    if (diag != s) continue;

                    found = true;
                    ans = k;
                    break;
                }
                if (found) break;
            }
        }
        return ans;
    }
}

