        var h1 = Console.ReadLine().Trim().Split(' ').Select(int.Parse).ToList();
        var h2 = Console.ReadLine().Trim().Split(' ').Select(int.Parse).ToList();

        var stacks = new List<List<int>> { h0, h1, h2 };
        var sums = new List<int> { h0.Sum(), h1.Sum(), h2.Sum() };

        while (!(sums[0] == sums[1] && sums[1] == sums[2])) {
            int tallest = max_index(sums);
            int tmp2 = stacks[tallest][0];
            stacks[tallest].RemoveAt(0);
            sums[tallest] -= tmp2;
        }

        Console.WriteLine(sums[0]);
    }

    static int max_index(List<int> array) {
        int max_val = array[0];
        int max_index = 0;
        for (int index = 0; index < array.Count; index++) {
            if (array[index] > max_val) {
                max_index = index;
                max_val = array[index];
            }
        }
        return max_index;
    }
}

