            for (int i = 0; i < di; i++) {
                while (v % div[i] == 0 && u % div[i] == 0) {
                    v /= div[i];
                    u /= div[i];
                }
                if (v % div[i] == 0) {
                    divs1.Add(0);
                } else {
                    divs1.Add(-1); // Some dummy value to indicate not counted
                }
                if (u % div[i] == 0) {
                    divs2.Add(0);
                } else {
                    divs2.Add(-1); // Some dummy value to indicate not counted
                }
                while (v % div[i] == 0) {
                    v /= div[i];
                    divs1[divs1.Count - 1]++;
                    tot1++;
                }
                while (u % div[i] == 0) {
                    u /= div[i];
                    divs2[divs2.Count - 1]++;
                    tot2++;
                }
            }

            long res = fac[tot1] * fac[tot2] % mod;
            long tod = 1;

            foreach (int x in divs1) {
                if (x >= 0) {
                    tod = tod * fac[x] % mod;
                }
            }
            foreach (int x in divs2) {
                if (x >= 0) {
                    tod = tod * fac[x] % mod;
                }
            }

            res = res * Power(tod, mod - 2, mod) % mod;
            Console.WriteLine(res);
        }
    }

    static long Power(long baseVal, long exp, long mod) {
        long result = 1;
        while (exp > 0) {
            if (exp % 2 == 1) {
                result = result * baseVal % mod;
            }
            baseVal = baseVal * baseVal % mod;
            exp /= 2;
        }
        return result;
    }
}

