class Program 
{
    static void Main() 
    {
        var trips = new List<List<int>>();
        int n = int.Parse(Console.ReadLine());
        for(int i = 0; i < n; i++) 
        {
            string[] input = Console.ReadLine().Split(' ');
            List<int> trip = new List<int>();
            for(int j = 0; j < input.Length; j++) 
            {
                trip.Add(int.Parse(input[j]));
            }
            trips.Add(trip);
        }
        int capacity = int.Parse(Console.ReadLine());

        bool result = CarPooling(trips, capacity);
        Console.WriteLine(result);
    }

    static bool CarPooling(List<List<int>> trips, int capacity) 
    {
        trips.Sort((x, y) => x[1].CompareTo(y[1]));
        int capacity_needed = 0;
        var hp = new List<Tuple<int, int, int>>();

        for(int i = 0; i < trips.Count; i++) 
        {
            var trip = trips[i];
            while (hp.Count > 0 && hp[0].Item1 <= trip[1]) 
            {
                var firstTrip = hp[0];
                hp.RemoveAt(0);
                capacity_needed -= firstTrip.Item3;
            }
            capacity_needed += trip[0];
            if (capacity_needed > capacity) 
            {
                return false;
            }
            hp.Add(Tuple.Create(trip[2], trip[1], trip[0]));
            hp.Sort((a, b) => a.Item1.CompareTo(b.Item1));
        }
        return true;
    }
}

