        List<string> ans = new List<string>();

        for (int i = 0; i < t; i++) {
            string s = Console.ReadLine().Trim();
            s = Count(s);
            ans.Add(s);
        }

        Console.WriteLine(string.Join("\n", ans));
    }

    static string Count(string line) {
        if (line.Length == 1) {
            return line;
        }
        Dictionary<char, bool> freq = new Dictionary<char, bool>();
        int idx = 0;

        while (idx < line.Length) {
            if (idx < line.Length - 1 && line[idx] == line[idx + 1]) {
                if (!freq.ContainsKey(line[idx])) {
                    freq[line[idx]] = false;
                }
                idx += 2;
            } else {
                freq[line[idx]] = true;
                idx += 1;
            }
        }

        List<char> res = new List<char>();
        foreach (var kv in freq) {
            if (kv.Value) {
                res.Add(kv.Key);
            }
        }

        res.Sort();
        return new string(res.ToArray());
    }
}

