class Program {
    static void Main() {
        var inputs = Console.ReadLine();
        var inputLines = inputs.Split('\n');
        var pointList = new List<List<int>>();
        foreach(var line in inputLines) {
            var nums = line.Split(',');
            var point = new List<int>();
            for (int i = 0; i < nums.Length; i++) {
                point.Add(int.Parse(nums[i]));
            }
            pointList.Add(point);
        }
        var angle = int.Parse(Console.ReadLine());
        var location = new List<int> { int.Parse(Console.ReadLine()), int.Parse(Console.ReadLine()) };

        var result = visiblePoints(pointList, angle, location);
        Console.WriteLine(result);
    }

    static int visiblePoints(List<List<int>> points, int angle, List<int> location) {
        int same = 0;
        List<double> angles = new List<double>();

        for (int i = 0; i < points.Count; i++) {
            if (points[i][1] == location[1] && points[i][0] == location[0]) {
                same++;
                continue;
            }
            double a = Math.Atan2(points[i][1] - location[1], points[i][0] - location[0]);
            angles.Add(Math.ToDegrees(a) + 180.0);
        }

        angles.Sort((e1, e2) => e1.CompareTo(e2));

        int slow = 0;
        int fast = 0;
        int max = 0;

        while (slow < angles.Count) {
            double begin = angles[slow];
            int count = 0;

            while ((angles[fast] >= begin && angles[fast] - begin <= angle) || 
                   (angles[fast] < begin && angles[fast] - begin + 360.0 <= angle)) {
                count++;
                fast++;
                fast = fast % angles.Count;

                if (count == angles.Count) {
                    return angles.Count + same;
                }
            }

            max = Math.Max(max, fast >= slow ? fast - slow : fast + angles.Count - slow);
            slow++;
        }

        return max + same;
    }
}

