using System;
using System.Linq;

class UnionFind
{
    private int[] par;
    private int[] rank;

    public UnionFind(int n = 1)
    {
        par = new int[n];
        rank = new int[n];
        for (int i = 0; i < n; i++)
        {
            par[i] = i;
            rank[i] = 0;
        }
    }

    public int find(int x)
    {
        if (par[x] == x)
            return x;
        else
        {
            par[x] = find(par[x]);
            return par[x];
        }
    }

    public void union(int x, int y)
    {
        x = find(x);
        y = find(y);
        if (x != y)
        {
            if (rank[x] < rank[y])
            {
                int tmp = y;
                y = x;
                x = tmp;
            }
            if (rank[x] == rank[y])
            {
                rank[x] += 1;
            }
            par[y] = x;
        }
    }

    public bool is_same(int x, int y)
    {
        return find(x) == find(y);
    }
}

