class Program {
    static void Main() {
        string input = Console.ReadLine();
        int result = SumScores(input);
        Console.WriteLine(result);
    }

    static int SumScores(string s) {
        return HelperSumScores(s);
    }

    static int HelperSumScores(string s) {
        int[] zArray = GetZarr(s);
        int total = 0;
        for(int i = 0; i < zArray.Length; i++) {
            total += zArray[i];
        }
        return total;
    }

    static int[] GetZarr(string str) {
        int n = str.Length;
        int[] z = new int[n];
        for(int i = 0; i < n; i++) {
            z[i] = 0; // init z array
        }
        int l = 0, r = 0, k = 0;
        for(int i = 1; i < n; i++) {
            if(i > r) {
                l = i;
                r = i;
                while(r < n && str[r - l] == str[r]) {
                    r++;
                }
                z[i] = r - l;
                r--; 
            } else {
                k = i - l;
                if(z[k] < r - i + 1) {
                    z[i] = z[k];
                } else {
                    l = i;
                    while(r < n && str[r - l] == str[r]) {
                        r++;
                    }
                    z[i] = r - l;
                    r--;
                }
            }
        }
        z[0] = n; // First element is length of the string
        return z;
    }
}

