        for (int i = 0; i < l - 1; i++) 
        {
            int tmp = l - i - 1;
            if (y[tmp] > y[tmp - 1]) 
            {
                count += y[tmp - 1];
            } 
            else 
            {
                y[tmp - 1] = y[tmp] - 1;

                if (y[tmp - 1] == 0) 
                {
                    break;
                }

                count += y[tmp - 1];
            }
        }

        Console.WriteLine(count);
    }
