class Solution 
{
    public int MagnificentSets(int n, List<List<int>> edges) 
    {
        var parent = new int[n + 1];
        for(int i = 0; i <= n; i++) 
        {
            parent[i] = i; 
        }

        for (int i = 0; i < edges.Count; i++) 
        {
            Union(edges[i][0], edges[i][1], parent);
        }

        var graphs = new Dictionary<int, List<int>>();
        for (int i = 1 ; i <= n; i++) 
        {
            int root = Find(i, parent);
            if (!graphs.ContainsKey(root)) 
            {
                graphs[root] = new List<int>();
            }
            graphs[root].Add(i);
        }

        var g = new List<int>[n + 1];
        for (int k = 0; k <= n; k++) 
        {
            g[k] = new List<int>();
        }

        foreach (var edge in edges) 
        {
            g[edge[0]].Add(edge[1]);
            g[edge[1]].Add(edge[0]);
        }

        int ans = 0;
        foreach (var kvp in graphs) 
        {
            var nodes = kvp.Value;
            int tmp = MaxGroups(nodes, g);
            if (tmp < 0) 
            {
                return -1;
            }
            ans += tmp;
        }

        return ans;
    }

    private int Find(int i, int[] parent) 
    {
        int p = i;
        while (p != parent[p]) 
        {
            int tmp = parent[p];
            parent[p] = parent[parent[p]];
            p = tmp;
        }
        return p;
    }

    private void Union(int i, int j, int[] parent) 
    {
        parent[Find(i, parent)] = Find(j, parent);
    }

    private int MaxGroups(List<int> nodes, List<int>[] g) 
    {
        int maxLayers = 0;

        foreach (var start in nodes) 
        {
            int cnt = Bfs(start, g);
            if (cnt < 0) 
            {
                return -1;
            }
            if (cnt > maxLayers) 
            {
                maxLayers = cnt;
            }
        }

        return maxLayers;
    }

    private int Bfs(int start, List<int>[] g) 
    {
        int cnt = 0;
        var vis = new HashSet<int>();
        vis.Add(start);
        var lastLayer = new HashSet<int>();
        var layer = new HashSet<int> { start };

        while (layer.Count > 0) 
        {
            cnt++;
            var newLayer = new HashSet<int>();
            foreach (var x in layer) 
            {
                foreach (var y in g[x]) 
                {
                    if (vis.Contains(y)) 
                    {
                        if (lastLayer.Contains(y) || newLayer.Contains(y)) 
                        {
                            continue;
                        } 
                        else 
                        {
                            return -1;
                        }
                    }
                    newLayer.Add(y);
                    vis.Add(y);
                }
            }
            lastLayer = layer;
            layer = newLayer;
        }
        return cnt;
    }
}

