using System;
using System.Linq;

class Program {
    static void Main() {
        var input = Console.ReadLine(); // read first line
        var parts = input.Split(' '); // split it by space
        int length = int.Parse(parts[0]);
        int k = int.Parse(parts[1]);

        var arrayInput = Console.ReadLine(); // read second line
        var array = arrayInput.Split(' ').Select(int.Parse).ToList(); // make a list of integers

        var result = get_winners(array, k); // call the function
        Console.WriteLine(result); // print the result
    }

    static int get_winners(System.Collections.Generic.List<int> array, int k) {
        int result = -1; // initializing
        array.Sort((a, b) => b.CompareTo(a)); // sort array descending
        int score = array[k - 1]; // find the score at k-1

        if (score > 0) {
            result = k; // set result
            int next_index = k;
            while (next_index < array.Count) {
                int next_ammount = array[next_index]; // current value
                if (next_ammount == score) {
                    result += 1; // equals score, increment result
                } else {
                    break; // break if not equal
                }
                next_index += 1; // move to next
            }
        } else {
            result = 0; // set default for zero score
            int next_index = k - 2; 
            while (next_index >= 0) {
                int next_ammount = array[next_index]; // check previous values
                if (next_ammount > 0) {
                    result = next_index + 1; // found a valid score
                    break; // exit loop
                }
                next_index -= 1; // check previous indexes
            }
        }
        return result; // return the result
    }
}

