using System;
using System.Collections.Generic;

class Program {
    static void Main() {
        var input = Console.ReadLine();
        int maxLetters = int.Parse(Console.ReadLine());
        int minSize = int.Parse(Console.ReadLine());
        int maxSize = int.Parse(Console.ReadLine());
        int result = MaxFreq(input, maxLetters, minSize, maxSize);
        Console.WriteLine(result);
    }

    static int MaxFreq(string s, int maxLetters, int minSize, int maxSize) {
        Dictionary<string, int> res = new Dictionary<string, int>();
        int n = s.Length;
        int size = minSize;

        while (size <= maxSize) {
            Dictionary<char, int> M = new Dictionary<char, int>();
            for (int i = 0; i < n; i++) {
                if (i < size) {
                    if (M.ContainsKey(s[i])) {
                        M[s[i]]++;
                    } else {
                        M[s[i]] = 1;
                    }
                    continue;
                }

                if (M.Count <= maxLetters) {
                    string subStr = s.Substring(i - size, size);
                    if (res.ContainsKey(subStr)) {
                        res[subStr]++;
                    } else {
                        res[subStr] = 1;
                    }
                }

                char leftChar = s[i - size];
                if (M.ContainsKey(leftChar)) {
                    M[leftChar]--;
                    if (M[leftChar] == 0) {
                        M.Remove(leftChar);
                    }
                }

                if (M.ContainsKey(s[i])) {
                    M[s[i]]++;
                } else {
                    M[s[i]] = 1;
                }
            }

            if (M.Count <= maxLetters) {
                string subStrLast = s.Substring(n - size, size);
                if (res.ContainsKey(subStrLast)) {
                    res[subStrLast]++;
                } else {
                    res[subStrLast] = 1;
                }
            }
            size++;
        }

        KeyValuePair<string, int>? ans = null;
        foreach (var item in res) {
            if (ans == null || item.Value > ans.Value.Value) {
                ans = item;
            }
        }

        if (ans == null) {
            return 0;
        } else {
            return ans.Value.Value;
        }
    }
}

