class Program 
{
    static void Main() 
    {
        var input = Console.ReadLine();
        var parts = input.Split(' ').Select(int.Parse).ToArray();
        int n = parts[0]; 
        int m = parts[1]; 
        int k = parts[2];

        var arr = Console.ReadLine().Split(' ').Select(int.Parse).ToArray();
        var ops = new (int l, int r, int d)[m];
        for (int x = 0; x < m; x++) 
        {
            var opParts = Console.ReadLine().Split(' ').Select(int.Parse).ToArray();
            ops[x] = (opParts[0], opParts[1], opParts[2]);
        }

        var c = new int[m];
        for (int x = 0; x < k; x++) 
        {
            var lrParts = Console.ReadLine().Split(' ').Select(int.Parse).ToArray();
            int l = lrParts[0]; 
            int r = lrParts[1];
            c[l - 1] += 1;
            if (r < m) 
            {
                c[r] -= 1;
            }
        }

        var times_used = new int[m];
        times_used[0] = c[0];
        for (int x = 1; x < m; x++) 
        {
            times_used[x] = times_used[x - 1] + c[x];
        }

        var c1 = new int[n];
        for (int x = 0; x < m; x++) 
        {
            var (l, r, d) = ops[x];
            c1[l - 1] += times_used[x] * d;
            if (r < n) 
            {
                c1[r] -= times_used[x] * d;
            }
        }

        var amount_added = new int[n];
        amount_added[0] = c1[0];
        arr[0] += amount_added[0];
        for (int x = 1; x < n; x++) 
        {
            amount_added[x] = amount_added[x - 1] + c1[x];
            arr[x] += amount_added[x];
        }

        Console.WriteLine(string.Join(" ", arr));
