class Program {
    static void Main() {
        string[] inputs = Console.ReadLine().Split(' ');
        int n = int.Parse(inputs[0]);
        int m = int.Parse(inputs[1]);
        string[] arrInputs = Console.ReadLine().Split(' ');
        int[] a = new int[n];

        for (int i = 0; i < n; i++) {
            a[i] = int.Parse(arrInputs[i]) % m;
        }

        bool result = main(n, m, a);
        Console.WriteLine(result ? "YES" : "NO");
    }

    static bool main(int n, int m, int[] a) {
        if (n >= m) {
            return true;
        }

        List<int> sums = new List<int>();
        HashSet<int> vis = new HashSet<int>();

        for (int i = 0; i < n; i++) {
            if (a[i] == 0) {
                return true; 
            }

            for (int j = 0; j < sums.Count; j++) {
                int _sum = (sums[j] + a[i]) % m;

                if (_sum == 0) {
                    return true;
                }

                if (!vis.Contains(_sum)) {
                    sums.Add(_sum);
                    vis.Add(_sum);
                }
            }

            if (!vis.Contains(a[i])) {
                sums.Add(a[i]);
                vis.Add(a[i]);
            }
        }

        return sums.Contains(0); 
    }
}

