        int result = doWork(n, k, a); 
        Console.WriteLine(result); 
    } 

    static int doWork(int n, int k, int[] a) 
    { 
        int i = 0; 
        while (i < n && a[i] <= k) 
        { 
            i++; 
        } 
        if (i == n) 
        { 
            return i; 
        } 
        int j = n - 1; 
        while (j >= 0 && a[j] <= k) 
        { 
            j--; 
        } 
        return i + (n - 1 - j); 
    } 
}

