    static int solution(int m, int n) 
    {
        int count = 0;
        while (true) 
        {
            if (m >= 2) 
            {
                int s = m / 2;
                m = m - s * 2;
                count = count + n * s;
            }
            if (n >= 2) 
            {
                int s = n / 2;
                n = n - s * 2;
                count = count + m * s;
            }
            if (n <= 1 && m <= 1) 
            {
                break;
            }
        }
        return count;
    }
}

