class Program 
{
    static void Main() 
    {
        string input = Console.ReadLine();
        int maxLetters = int.Parse(Console.ReadLine());
        int minSize = int.Parse(Console.ReadLine());
        int maxSize = int.Parse(Console.ReadLine());

        int result = maxFreq(input, maxLetters, minSize, maxSize);
        Console.WriteLine(result);
    }

    static int maxFreq(string s, int maxLetters, int minSize, int maxSize) 
    {
        Dictionary<string, int> substr = new Dictionary<string, int>();
        int n = s.Length;
        HashSet<char> unique = new HashSet<char>();
        int max_freq = 0;

        for (int i = 0; i <= n - minSize; i++) 
        {
            string current_str = s.Substring(i, minSize);
            unique.Clear();
            for (int j = 0; j < minSize; j++) 
            {
                unique.Add(current_str[j]); // builds unique chars
            }
            if (unique.Count <= maxLetters) 
            {
                if (substr.ContainsKey(current_str)) 
                {
                    substr[current_str] += 1;
                } 
                else 
                {
                    substr[current_str] = 1;
                }
                max_freq = Math.Max(max_freq, substr[current_str]);
            }
        }
        return max_freq;
    }
}

