    static List<int> SieveOfEratosthenes(int n)
    {
        bool[] prime = Enumerable.Repeat(true, n + 1).ToArray();
        List<int> l = new List<int>();
        int p = 2;

        while (p * p <= n)
        {
            if (prime[p])
            {
                for (int i = p * p; i <= n; i += p)
                {
                    prime[i] = false;
                }
            }
            p++;
        }

        for (p = 2; p <= n; p++)
        {
            if (prime[p])
            {
                l.Add(p);
            }
        }

        return l;
    }

    static bool isPrime(int n)
    {
        if (n <= 1) return false;
        for (int i = 2; i <= Math.Sqrt(n); i++)
        {
            if (n % i == 0) return false;
        }
        return true;
    }

    static int gcd(IEnumerable<int> a)
    {
        int x = 0;
        foreach (int p in a)
        {
            x = GCD(x, p);
        }
        return x;
    }

    static int GCD(int a, int b)
    {
        while (b != 0)
        {
            int t = b;
            b = a % b;
            a = t;
        }
        return a;
    }

    static List<int> printDivisors(int n)
    {
        List<int> ans = new List<int>();
        for (int i = 1; i <= Math.Sqrt(n); i++)
        {
            if (n % i == 0)
            {
                ans.Add(i);
                if (i != n / i)
                {
                    ans.Add(n / i);
                }
            }
        }
        ans.Sort();
        return ans;
    }

