class Program {
    static void Main() {
        var inputs = ReadData();
        int n = inputs[0]; 
        int m = inputs[1]; 
        m *= 2; 
        long mod = 1000000007; 
        long[] dp = new long[n * m + 1]; 
        dp[0] = 1; 

        for (int i = 1; i < n + m; i++) { 
            dp[i] = dp[i - 1] * i % mod; 
        }

        long ans = dp[n + m - 1] * Pow(dp[m] * dp[n - 1], mod - 2, mod) % mod; 
        Output(ans); 
    }

    static int[] ReadData() { 
        string line = Console.ReadLine(); 
        return line.Split(' ').Select(int.Parse).ToArray(); 
    }

    static void Output(long val) { 
        Console.WriteLine(val); 
    }

    static long Pow(long baseNum, long exponent, long mod) { 
        long result = 1; 
        baseNum %= mod; 
        while (exponent > 0) {
            if (exponent % 2 == 1) { 
                result = result * baseNum % mod; 
            }
            exponent >>= 1; 
            baseNum = baseNum * baseNum % mod; 
        }
        return result; 
    }
}

