using System;
using System.Collections.Generic;

class Program {
    static void Main() {
        string input;
        input = Console.ReadLine();
        string[] parts = input.Split();
        int d = int.Parse(parts[0]);
        int f = int.Parse(parts[1]);
        int target = int.Parse(parts[2]);

        var result = numRollsToTarget(d, f, target);
        Console.WriteLine(result);
    }

    static int numRollsToTarget(int d, int f, int target) {
        int bottomWidth = f + (d - 1) * (f - 1);
        int[] currentLayer = new int[bottomWidth];
        for (int i = 0; i < f; i++) {
            currentLayer[i] = 1;
        }
        List<int> nextLayer = new List<int>();

        for (int run = 0; run < d - 1; run++) {
            nextLayer.Clear();
            for (int i = f; i < currentLayer.Length - f; i++) {
                int localSum = 0;
                for (int j = 0; j < f; j++) {
                    localSum += currentLayer[i - j];
                }
                nextLayer.Add(localSum);
            }
            int neededZerosCount = (currentLayer.Length - nextLayer.Count) / 2;
            int[] neededZeros = new int[neededZerosCount];
            currentLayer = new int[neededZerosCount + nextLayer.Count + neededZerosCount];
            Array.Copy(neededZeros, currentLayer, neededZerosCount);
            nextLayer.CopyTo(currentLayer, neededZerosCount);
            Array.Copy(neededZeros, 0, currentLayer, neededZerosCount + nextLayer.Count, neededZerosCount);
        }

        while (currentLayer.Length > 0 && currentLayer[0] == 0) {
            int[] temp = new int[currentLayer.Length - 1];
            Array.Copy(currentLayer, 1, temp, 0, temp.Length);
            currentLayer = temp;
        }

        if (target - d >= currentLayer.Length) {
            return 0;
        } else {
            return currentLayer[target - d] % (1000000007);
        }
    }
}

