using System;
using System.Collections.Generic;
using System.Linq;

class Program {
    static void Main() {
        long m = 1000000007;
        int t = int.Parse(Console.ReadLine());
        for (int i = 0; i < t; i++) {
            int n = int.Parse(Console.ReadLine());
            int[] a = Console.ReadLine().Split().Select(int.Parse).ToArray();
            Dictionary<int, int> v = new Dictionary<int, int>();
            long ma = 1;

            for (int j = 1; j <= n; j++) {
                if (v.ContainsKey(a[j - 1])) {
                    v[a[j - 1]] += 1;
                } else {
                    v[a[j - 1]] = 1;
                }
                ma = Math.Max(ma, v[a[j - 1]]);
            }

            if (ma == 1) {
                for (int j = 1; j <= n; j++) {
                    Console.Write((Power(2, n - j, m)) + " ");
                }
                Console.WriteLine();
                continue;
            }

            var sortedV = v.ToList();
            sortedV.Sort();
            int v1 = sortedV.Count;
            Dictionary<long, int> pre = new Dictionary<long, int>();
            Dictionary<long, int> suf = new Dictionary<long, int>();

            for (int j = 0; j < v1; j++) {
                if (suf.ContainsKey(sortedV[j].Value)) {
                    suf[sortedV[j].Value] += 1;
                } else {
                    suf[sortedV[j].Value] = 1;
                }
            }

            List<long> fact = new List<long> { 1 };
            List<long> inverse = new List<long> { 1 };

            for (int j = 1; j <= ma; j++) {
                fact.Add(fact[j - 1] * j % m);
                inverse.Add(Power(fact[j], m - 2, m));
            }

            Dictionary<long, List<long>> mul = new Dictionary<long, List<long>>();
            foreach (var j in suf.Keys) {
                mul[j] = new List<long> { inverse[j] };
                for (int k = 1; k <= j; k++) {
                    mul[j].Add(mul[j][k - 1]);
                    mul[j][k] = (mul[j][k] + inverse[k] * inverse[j - k] % m) % m;
                }
            }

            if (n * suf.Count < ma * v1) {
                long[] ans = new long[n + 1];
                for (int j = 0; j < v1; j++) {
                    suf[sortedV[j].Value] -= 1;
                    long p = 1;
                    while (p <= sortedV[j].Value) {
                        long curr = fact[sortedV[j].Value] * (inverse[p] * inverse[sortedV[j].Value - p] % m) % m;
                        foreach (var k in suf.Keys) {
                            curr = curr * Power(fact[k] * mul[k][Math.Min(p, k)] % m, suf[k], m) % m;
                        }
                        foreach (var k in pre.Keys) {
                            curr = curr * Power(fact[k] * mul[k][Math.Min(p - 1, k)] % m, pre[k], m) % m;
                        }
                        ans[sortedV[j].Key] = (ans[sortedV[j].Key] + curr) % m;
                        p += 1;
                    }
                    if (pre.ContainsKey(sortedV[j].Value)) {
                        pre[sortedV[j].Value] += 1;
                    } else {
                        pre[sortedV[j].Value] = 1;
                    }
                }
                Console.WriteLine(string.Join(" ", ans.Skip(1)));
                continue;
            }

            var final = new Dictionary<long, List<long>>();
            var final2 = new Dictionary<long, Queue<long>>();
            for (int j = 0; j <= ma; j++) {
                final[j] = new List<long> { mul[sortedV[0].Value][Math.Min(j, sortedV[0].Value)] };
                for (int k = 1; k < v1; k++) {
                    final[j].Add(final[j][k - 1]);
                    final[j][k] = final[j][k] * mul[sortedV[k].Value][Math.Min(j, sortedV[k].Value)] % m;
                }
                final[j].Add(1);
                final2[j] = new Queue<long>();
                final2[j].Enqueue(1);
                final2[j].Enqueue(mul[sortedV[v1 - 1].Value][Math.Min(j, sortedV[v1 - 1].Value)]);
                for (int k = v1 - 2; k >= 0; k--) {
                    final2[j].Enqueue(final2[j].Peek());
                    long first = final2[j].Dequeue();
                    final2[j].Enqueue(first * mul[sortedV[k].Value][Math.Min(j, sortedV[k].Value)] % m);
                }
            }

            long[] results = new long[n + 1];
            long all = 1;
            for (int j = 0; j < v1; j++) {
                all = all * fact[sortedV[j].Value] % m;
                long p2 = 1;
                while (p2 <= sortedV[j].Value) {
                    long curr = inverse[p2] * inverse[sortedV[j].Value - p2] % m;
                    curr = curr * final2[p2][j + 1] % m * final[p2 - 1][j - 1] % m;
                    results[sortedV[j].Key] = (results[sortedV[j].Key] + curr) % m;
                    p2 += 1;
                }
            }

            for (int j = 1; j <= n; j++) {
                Console.Write((all * results[j] % m) + " ");
            }
            Console.WriteLine();
        }
    }

    static long Power(long x, long y, long m) {
        if (y == 0) return 1;
        long p = Power(x, y / 2, m) % m;
        p = p * p % m;
        if (y % 2 == 0) return p;
        else return x * p % m;
    }
}

