using System;
using System.Collections.Generic;
using System.Linq;

class Program
{
    static void Main()
    {
        int n = int.Parse(Console.ReadLine().Trim());
        var sticks = Console.ReadLine().Trim().Split(' ').Select(int.Parse).ToList();
        int result = longest_sequence_multiple_sticks(sticks);
        Console.WriteLine(result);
    }

    static List<List<int>> factor_trial_division(int x)
    {
        if (x <= 1) return new List<List<int>>();
        var f = new List<List<int>>();
        int e = 0;

        while (x % 2 == 0)
        {
            x /= 2;
            e++;
        }
        if (e > 0)
        {
            f.Add(new List<int> { 2, e });
        }

        int p = 3;
        while (p * p <= x)
        {
            e = 0;
            while (x % p == 0)
            {
                x /= p;
                e++;
            }
            if (e > 0)
            {
                f.Add(new List<int> { p, e });
            }
            p += 2;
        }
        if (x > 1)
        {
            f.Add(new List<int> { x, 1 });
        }

        return f.OrderBy(item => item[0]).ToList();
    }

    static int longest_sequence_single_stick(int stick, List<List<int>> factors = null)
    {
        if (stick <= 3)
        {
            return new[] { 0, 1, 3, 4 }[stick];
        }
        if (factors == null)
        {
            factors = factor_trial_division(stick);
        }

        int lpf = factors.Last()[0];
        factors[factors.Count - 1][1] -= 1;
        if (factors.Last()[1] == 0)
        {
            factors.RemoveAt(factors.Count - 1);
        }

        int num_moves = 1 + lpf * longest_sequence_single_stick(stick / lpf, factors);
        return num_moves;
    }

    static int longest_sequence_multiple_sticks(List<int> sticks)
    {
        int total = 0;
        foreach (var stick in sticks)
        {
            total += longest_sequence_single_stick(stick);
        }
        return total;
    }
}

