using System;

class Edge {
    public int to, next, len;

    public Edge() {
        to = 0; next = 0; len = 0;
    }
}

class Graph {
    public Edge[] g = new Edge[200001 * 2];
    public int[] head = new int[200001];
    public int tot;

    public Graph() {
        for(int i = 0; i < g.Length; i++) {
            g[i] = new Edge();
        }
        Array.Fill(head, 0);
        tot = 0;
    }

    public void clear(int n) {
        Array.Fill(head, 0, 0, n + 1);
        Array.Fill(g, new Edge(), 0, tot + 1);
        tot = 0;
    }

    public void addEdge(int from, int to, int len) {
        g[++tot].to = to; g[tot].next = head[from]; g[tot].len = len; head[from] = tot;
        g[++tot].to = from; g[tot].next = head[to]; g[tot].len = len; head[to] = tot;
    }
}

class Program {
    static int n, k;
    static int[] need = new int[200001], dep = new int[200001], a = new int[200001];
    static bool[] vis = new bool[200001];
    static Graph g = new Graph();

    static void readInt(out int res) {
        res = 0; bool f = false; char ch = (char)Console.Read();

        while(ch < '0' || ch > '9') { if(ch == '-') f = true; ch = (char)Console.Read(); }

        while(ch >= '0' && ch <= '9') {
            res = (res << 3) + (res << 1) + (ch - '0'); ch = (char)Console.Read();
        }

        if(f) res = -res;
    }

    static void writeln(int x) {
        if(x < 0) { Console.Write('-'); x = -x; }
        if(x > 9) writeln(x / 10);
        Console.Write(x % 10);
        Console.WriteLine();
    }

    static bool dfs(int u, int fa) {
        dep[u] = 0;

        for(int i = g.head[u]; i > 0; i = g.g[i].next) {
            int v = g.g[i].to;

            if(v == fa) continue;

            if(!dfs(v, u)) return false;

            if(!vis[v]) dep[u] = Math.Max(dep[u], dep[v] + 1);
        }

        if(dep[u] >= need[u]) return true;

        if(dep[u] < need[u]) {
            if(fa == 0 || vis[fa]) return false;

            vis[fa] = true;
            need[fa] = need[u] - 1;
            need[u] = 0;
        }

        return true;
    }

    static bool check(int len) {
        Array.Fill(vis, false, 0, n + 1);
        Array.Fill(need, 0, 0, n + 1);

        vis[0] = true;

        for(int i = 1; i <= k; i++) {
            need[a[i]] = len / k;
            vis[a[i]] = true;
        }

        for(int i = 1; i <= len % k; i++) {
            ++need[a[i]];
        }

        return dfs(1, 0);
    }

    static void solve() {
        readInt(out n);

        for(int i = 1; i < n; i++) {
            int u = 0, v = 0;
            readInt(out u); 
            readInt(out v);
            g.addEdge(u, v, 1);
        }

        readInt(out k);

        for(int i = 1; i <= k; i++) {
            readInt(out a[i]);
        }

        int l = 0, r = n, res = 0;

        while(l <= r) {
            int mid = (l + r) >> 1;
            if(check(mid)) {
                res = mid;
                l = mid + 1;
            } else {
                r = mid - 1;
            }
        }

        g.clear(n);
        writeln(res);
    }

    static void Main() {
        int T = 0; 
        readInt(out T);

        while(T-- > 0) solve();
    }
}

