    static int totalScore(string str) {
        int prev = 0;
        int score = 0;

        for (int i = 0; i < str.Length; i++) {
            char s = str[i];
            if (s == 'H') {
                score += prev + 1;
                prev += 1;
            } else {
                prev = 0;
            }
        }
        return score;
    }
}
